    fn jsonObjectKeyTypeIsSupported(self: *BodyContext, ty: Type.TypeId) bool {
        return self.jsonParseObjectKeyMethodName(ty) != null or self.jsonObjectKeyUnitTags(ty) != null;
    }

    fn jsonObjectKeyUnitTags(self: *BodyContext, ty: Type.TypeId) ?Type.Span {
        switch (self.builder.program.types.get(ty)) {
            .named => |named| if (named.kind != .alias) return null,
            else => {},
        }
        const tags_span = switch (self.builder.shapeContent(ty)) {
            .tag_union => |span| span,
            else => return null,
        };
        const tags = self.builder.program.types.tagSpan(tags_span);
        if (tags.len == 0) return null;
        for (tags) |tag| {
            if (self.builder.program.types.span(tag.payloads).len != 0) return null;
        }
        return tags_span;
    }

    fn dispatchResultMonoType(
        self: *BodyContext,
        checked_ret_ty: checked.CheckedTypeId,
        maybe_plan: ?static_dispatch.StaticDispatchPlanId,
        expected_ret_ty: ?Type.TypeId,
    ) Allocator.Error!?Type.TypeId {
        const plan_id = maybe_plan orelse Common.invariant("checked dispatch expression reached Monotype without a dispatch plan");
        const plan = self.view.static_dispatch_plans.plans[@intFromEnum(plan_id)];

        var call_ctx = try BodyContext.init(self.allocator, self.builder, self.view, self.owner_template, self.graph, self.draft);
        defer call_ctx.deinit();
        call_ctx.owner_context_fn_key = self.owner_context_fn_key;
        call_ctx.current_fn_key = self.current_fn_key;
        call_ctx.source_region_override = self.source_region_override;
        call_ctx.current_entry_root = self.current_entry_root;

        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        const callable_mono_ty = try call_ctx.instantiateDispatchPlanCallTypeFromCaller(plan.callable_ty, self, checked_ret_ty, plan_args, expected_ret_ty);
        const plan_fn_data = self.builder.functionShape(callable_mono_ty, "checked dispatch plan had a non-function type");
        const plan_arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(plan_fn_data.args));
        defer self.allocator.free(plan_arg_tys);
        const plan_ret_ty = plan_fn_data.ret;
        const dispatcher_ty = try self.dispatcherMonoType(plan, plan_arg_tys);

        // The dispatcher may not be solved yet when this runs for argument
        // evidence; the target then resolves when the expression itself
        // lowers, and the plan's return carries the evidence for now.
        if (methodOwnerFromType(&self.builder.program.types, dispatcher_ty) == null) {
            try self.constrainTypeToMono(checked_ret_ty, plan_ret_ty);
            return plan_ret_ty;
        }
        const resolved = self.dispatchTarget(plan, dispatcher_ty) orelse {
            try self.constrainTypeToMono(checked_ret_ty, plan_ret_ty);
            return plan_ret_ty;
        };
        if (self.generatedStructuralDispatchKind(resolved) != null) {
            try self.constrainTypeToMono(checked_ret_ty, plan_ret_ty);
            return plan_ret_ty;
        }
        const target_mono_ty = try self.methodTargetMonoTypeFromPlan(resolved, &call_ctx, plan.callable_ty, null);
        try call_ctx.constrainTypeToMono(plan.callable_ty, target_mono_ty);
        if (!self.sameType(callable_mono_ty, target_mono_ty)) {
            Common.invariant("checked dispatch target callable type differed from dispatch plan callable type");
        }
        const ret_ty = self.functionReturnType(target_mono_ty);
        try self.constrainTypeToMono(checked_ret_ty, ret_ty);
        return ret_ty;
    }

    fn dispatcherMonoType(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        arg_tys: []const Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        return switch (plan.dispatcher) {
            .arg => |index| blk: {
                if (index >= arg_tys.len) Common.invariant("dispatch plan dispatcher argument index was outside the argument span");
                break :blk arg_tys[index];
            },
            .type_only => try self.sealCheckedType(plan.dispatcher_ty),
        };
    }

    fn dispatchTarget(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        dispatcher_ty: Type.TypeId,
    ) ?MethodLookup {
        switch (plan.resolution) {
            .resolved_target => |target| return self.methodLookupForResolvedTarget(target),
            .unresolved_checked_plan => {},
        }

        const owner = methodOwnerFromType(&self.builder.program.types, dispatcher_ty) orelse {
            if (planAllowsStructural(plan.result_mode)) return null;
            Common.invariant("dispatch plan had no method owner and no structural equality permission");
        };

        const lookup = self.builder.lookupMethodTarget(owner, self.view, plan.method) orelse {
            if (planAllowsStructural(plan.result_mode)) return null;
            Common.invariant("checked method registry is missing resolved dispatch target");
        };
        return lookup;
    }

    /// Whether a dispatch plan permits structural decomposition (equality or
    /// hashing) instead of resolving to a concrete method target.
    fn planAllowsStructural(mode: static_dispatch.StaticDispatchResultMode) bool {
        return switch (mode) {
            .equality => |eq| eq.structural_allowed,
            .hash => |hash| hash.structural_allowed,
            .parser_for => |parser_for| parser_for.structural_allowed,
            .encode_to => |encode_to| encode_to.structural_allowed,
            .value => false,
        };
    }

    fn methodLookupForResolvedTarget(
        self: *BodyContext,
        target: static_dispatch.MethodTarget,
    ) MethodLookup {
        return switch (target.kind) {
            .procedure => |procedure| .{
                .view = self.builder.moduleForDigest(names.procTemplateModuleDigest(procedure.template)),
                .target = target,
            },
            .local_proc => .{
                .view = self.view,
                .target = target,
            },
            .generated_structural_parser,
            .generated_structural_encoder,
            => .{
                .view = self.builder.moduleForModuleIndex(target.module_idx),
                .target = target,
            },
        };
    }

    fn methodTargetContext(
        self: *BodyContext,
        lookup: MethodLookup,
    ) Allocator.Error!BodyContext {
        const owner_template = switch (lookup.target.kind) {
            .procedure => |procedure| procedure.template,
            .local_proc => blk: {
                self.requireLocalMethodTargetInCurrentView(lookup);
                break :blk self.owner_template;
            },
            .generated_structural_parser,
            .generated_structural_encoder,
            => self.owner_template,
        };
        return BodyContext.init(self.allocator, self.builder, lookup.view, owner_template, self.graph, self.draft);
    }

    fn requireLocalMethodTargetInCurrentView(self: *BodyContext, lookup: MethodLookup) void {
        if (!moduleBytesEqual(lookup.view.key.bytes, self.view.key.bytes)) {
            Common.invariant("local method dispatch target belonged to a different checked module view");
        }
    }

    fn methodTargetMonoTypeFromPlan(
        self: *BodyContext,
        lookup: MethodLookup,
        plan_ctx: *BodyContext,
        plan_callable_ty: checked.CheckedTypeId,
        expected_ret_ty: ?Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var target_ctx = try self.methodTargetContext(lookup);
        defer target_ctx.deinit();
        return try target_ctx.instantiateTargetFromPlan(lookup.target.callable_ty, plan_ctx, plan_callable_ty, expected_ret_ty);
    }

    fn methodTargetMonoTypePreservingSourceArgsAndRet(
        self: *BodyContext,
        lookup: MethodLookup,
        ret_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var target_ctx = try self.methodTargetContext(lookup);
        defer target_ctx.deinit();
        return try target_ctx.instantiateTargetCallTypePreservingSourceArgsAndRet(lookup.target.callable_ty, ret_ty);
    }

    fn methodTargetMonoTypeFromArgs(
        self: *BodyContext,
        lookup: MethodLookup,
        arg_tys: []const Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var target_ctx = try self.methodTargetContext(lookup);
        defer target_ctx.deinit();
        return try target_ctx.instantiateTargetCallTypeFromMonoArgs(lookup.target.callable_ty, arg_tys, ret_ty);
    }

    fn methodTargetMonoTypeFromArgsPreservingArgs(
        self: *BodyContext,
        lookup: MethodLookup,
        arg_tys: []const Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var target_ctx = try self.methodTargetContext(lookup);
        defer target_ctx.deinit();
        return try target_ctx.instantiateTargetCallTypeFromMonoArgsPreservingArgs(lookup.target.callable_ty, arg_tys, ret_ty);
    }

    fn methodTargetMonoTypeFromArgAtIndexAndRet(
        self: *BodyContext,
        lookup: MethodLookup,
        arg_index: usize,
        arg_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var target_ctx = try self.methodTargetContext(lookup);
        defer target_ctx.deinit();
        return try target_ctx.instantiateTargetCallTypeFromMonoArgAtIndexAndRet(lookup.target.callable_ty, arg_index, arg_ty, ret_ty);
    }

    fn methodTargetMonoTypeFromArgAtIndexIsolated(
        self: *BodyContext,
        lookup: MethodLookup,
        arg_index: usize,
        arg_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        var graph = try InstGraph.create(self.allocator, &self.builder.program.types, &self.builder.program.names, &self.builder.unsolved_monos);
        defer graph.destroy();

        const owner_template = switch (lookup.target.kind) {
            .procedure => |procedure| procedure.template,
            .local_proc => blk: {
                self.requireLocalMethodTargetInCurrentView(lookup);
                break :blk self.owner_template;
            },
            .generated_structural_parser,
            .generated_structural_encoder,
            => self.owner_template,
        };
        var body_draft = BodyDraftStore.init(self.allocator);
        defer body_draft.deinit();
        var target_ctx = try BodyContext.init(self.allocator, self.builder, lookup.view, owner_template, graph, &body_draft);
        defer target_ctx.deinit();
        const fn_node = try target_ctx.instantiateTargetCallNodeFromMonoArgAtIndex(lookup.target.callable_ty, arg_index, arg_ty);
        return try graph.sealNode(fn_node);
    }

    fn methodLookupForTypeName(
        self: *BodyContext,
        owner_ty: Type.TypeId,
        method_name: []const u8,
    ) MethodLookup {
        const owner = methodOwnerFromType(&self.builder.program.types, owner_ty) orelse
            Common.invariant("parser format type did not have a method owner");
        return self.builder.lookupMethodTargetByName(owner, method_name) orelse
            Common.invariant("checked method registry is missing parser format method");
    }

    fn methodTargetCalleeWithMono(
        self: *BodyContext,
        lookup: MethodLookup,
        callable_mono_ty: Type.TypeId,
    ) Allocator.Error!Ast.FnSlot {
        const source_fn_ty = lookup.target.callable_ty;
        const source_fn_key = lookup.view.types.rootKey(source_fn_ty);
        return switch (lookup.target.kind) {
            .procedure => |procedure| blk: {
                const fn_template = self.builder.fnDefForTemplate(
                    lookup.view,
                    procedure.template,
                    source_fn_ty,
                    source_fn_key,
                    callable_mono_ty,
                );
                break :blk try self.builder.lowerFnTemplateCallTargetFromContext(self, fn_template);
            },
            .local_proc => |local| blk: {
                self.requireLocalMethodTargetInCurrentView(lookup);
                break :blk .{ .local = try self.fnTemplateForLocalProcWithMono(
                    .{ .binder = local.binder, .expr = local.expr },
                    source_fn_ty,
                    source_fn_key,
                    callable_mono_ty,
                ) };
            },
            .generated_structural_parser,
            .generated_structural_encoder,
            => Common.invariant("generated structural dispatch target has no callable procedure body"),
        };
    }

    const GeneratedStructuralDispatchKind = enum { parser, encoder };

    fn generatedStructuralDispatchKind(_: *BodyContext, lookup: MethodLookup) ?GeneratedStructuralDispatchKind {
        return switch (lookup.target.kind) {
            .generated_structural_parser => .parser,
            .generated_structural_encoder => .encoder,
            .procedure,
            .local_proc,
            => null,
        };
    }

    fn lowerResolvedDispatch(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        lookup: MethodLookup,
        callable_mono_ty: Type.TypeId,
        arg_ctx: *BodyContext,
        pre_lowered: ?PreLoweredOperand,
    ) Allocator.Error!BodyExprData {
        const fn_data = self.builder.functionShape(callable_mono_ty, "checked dispatch target had a non-function type");
        const args = try arg_ctx.lowerDispatchOperandsAtTypes(plan.argsSlice(self.view.static_dispatch_plans), self.builder.program.types.span(fn_data.args), pre_lowered);
        return .{ .call_proc = .{
            .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
            .args = args,
        } };
    }

    fn lowerStructuralEquality(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        callable_mono_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        arg_ctx: *BodyContext,
        pre_lowered: ?PreLoweredOperand,
    ) Allocator.Error!DraftExprId {
        return switch (plan.result_mode) {
            .equality => |eq| if (eq.structural_allowed) blk: {
                const operands = try self.lowerStructuralEqualityOperands(plan, arg_ctx);
                var result = try self.lowerEqualityExpr(operands.derived_ty, operands.first, operands.second, self.view.names.methodNameText(plan.method), ret_ty);
                if (eq.negated) {
                    result = try self.lowLevelExpr(.bool_not, &.{result}, ret_ty);
                }
                break :blk result;
            } else Common.invariant("structural equality dispatch plan did not permit structural equality"),
            .hash => |hash| if (hash.structural_allowed) blk: {
                const operands = try self.lowerStructuralBinaryOperands("hash", plan, callable_mono_ty, arg_ctx, pre_lowered);
                break :blk try self.lowerHashExpr(operands.derived_ty, operands.first, operands.second, ret_ty);
            } else Common.invariant("structural hash dispatch plan did not permit structural hashing"),
            .value => Common.invariant("value dispatch plan reached structural equality lowering"),
            .parser_for => Common.invariant("parser_for dispatch plan reached structural equality lowering"),
            .encode_to => Common.invariant("encode_to dispatch plan reached structural equality lowering"),
        };
    }

    /// The two lowered operands of a structural derivation plus `derived_ty`,
    /// the type being derived on, which the terminal lowering needs.
    const StructuralBinaryOperands = struct {
        first: DraftExprId,
        second: DraftExprId,
        derived_ty: Type.TypeId,
    };

    fn lowerStructuralEqualityOperands(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        arg_ctx: *BodyContext,
    ) Allocator.Error!StructuralBinaryOperands {
        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        if (plan_args.len != 2) Common.invariant("structural equality dispatch plan must have two operands");
        const lhs_expr = switch (plan_args[0]) {
            .checked_expr => |expr| expr,
            else => Common.invariant("structural equality operand was not a checked expression"),
        };
        const rhs_expr = switch (plan_args[1]) {
            .checked_expr => |expr| expr,
            else => Common.invariant("structural equality operand was not a checked expression"),
        };
        const operand_ty = try arg_ctx.structuralEqualityOperandType(.{ .lhs = lhs_expr, .rhs = rhs_expr });
        const first = try arg_ctx.lowerExprAtType(lhs_expr, operand_ty);
        const second = try arg_ctx.lowerExprAtType(rhs_expr, operand_ty);
        return .{
            .first = first,
            .second = second,
            .derived_ty = operand_ty,
        };
    }

    /// Lower the value and hasher operands of a structural hash dispatch,
    /// honoring a `pre_lowered` operand at index 0 or 1. `noun` is the derivation
    /// name used only in invariant diagnostics.
    fn lowerStructuralBinaryOperands(
        self: *BodyContext,
        comptime noun: []const u8,
        plan: static_dispatch.StaticDispatchCallPlan,
        callable_mono_ty: Type.TypeId,
        arg_ctx: *BodyContext,
        pre_lowered: ?PreLoweredOperand,
    ) Allocator.Error!StructuralBinaryOperands {
        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        if (plan_args.len != 2) Common.invariant("structural " ++ noun ++ " dispatch plan must have two operands");
        const fn_data = self.builder.functionShape(callable_mono_ty, "checked structural " ++ noun ++ " target had a non-function type");
        // Copy because the recursive operand lowering below may reallocate
        // types.span, dangling the slice; only the scalar derived type escapes.
        const arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(fn_data.args));
        defer self.allocator.free(arg_tys);
        if (arg_tys.len != 2) Common.invariant("structural " ++ noun ++ " callable type must have two operands");
        const first = if (pre_lowered != null and pre_lowered.?.index == 0)
            pre_lowered.?.expr
        else
            try arg_ctx.lowerDispatchOperandAtType(plan_args[0], arg_tys[0]);
        const second = if (pre_lowered != null and pre_lowered.?.index == 1)
            pre_lowered.?.expr
        else
            try arg_ctx.lowerDispatchOperandAtType(plan_args[1], arg_tys[1]);
        return .{ .first = first, .second = second, .derived_ty = arg_tys[0] };
    }

    fn lowerStructuralParser(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        callable_mono_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        arg_ctx: *BodyContext,
        pre_lowered: ?PreLoweredOperand,
    ) Allocator.Error!DraftExprId {
        const parser = switch (plan.result_mode) {
            .parser_for => |parser_for| parser_for,
            else => Common.invariant("non-parser_for dispatch plan reached structural parse lowering"),
        };
        if (!parser.structural_allowed) Common.invariant("structural parser dispatch plan did not permit structural parser lowering");

        const fn_data = self.builder.functionShape(callable_mono_ty, "checked structural parser target had a non-function type");
        const arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(fn_data.args));
        defer self.allocator.free(arg_tys);
        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        if (arg_tys.len != 1 or plan_args.len != 1) Common.invariant("structural parser callable type must have one encoding argument");
        if (!self.sameType(fn_data.ret, ret_ty)) Common.invariant("structural parser return type differed from dispatch expression type");

        const runtime_fn = self.builder.functionShape(ret_ty, "checked structural parser return had a non-function type");
        const runtime_arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(runtime_fn.args));
        defer self.allocator.free(runtime_arg_tys);
        if (runtime_arg_tys.len != 1) Common.invariant("structural parser runtime function must have one state argument");

        const shape_ty = try self.sealCheckedType(plan.dispatcher_ty);
        const top_level_json_try = self.tryJsonInfo(shape_ty);
        if (self.jsonParseScalarMethodName(shape_ty) == null and !(top_level_json_try != null and top_level_json_try.?.has_null and !top_level_json_try.?.has_missing)) {
            if (self.setPayloadType(shape_ty)) |elem_ty| {
                if (!self.parseFieldTypeIsSupported(elem_ty, false)) Common.invariant("structural parser set element type was not supported");
            } else if (self.dictEntryShape(shape_ty)) |dict| {
                if (!self.jsonObjectKeyTypeIsSupported(dict.key_ty)) Common.invariant("structural parser dict key type was not supported");
                if (!self.parseFieldTypeIsSupported(dict.value_ty, false)) Common.invariant("structural parser dict value type was not supported");
            } else {
                switch (self.builder.shapeContent(shape_ty)) {
                    .list => |elem_ty| {
                        if (!self.parseFieldTypeIsSupported(elem_ty, false)) Common.invariant("structural parser list element type was not supported");
                    },
                    .box => |payload_ty| {
                        if (!self.parseFieldTypeIsSupported(payload_ty, false)) Common.invariant("structural parser box payload type was not supported");
                    },
                    .tuple => |span| {
                        for (self.builder.program.types.span(span)) |elem_ty| {
                            if (!self.parseFieldTypeIsSupported(elem_ty, false)) Common.invariant("structural parser tuple element type was not supported");
                        }
                    },
                    .record => |fields_span| blk: {
                        for (self.builder.program.types.fieldSpan(fields_span)) |field| {
                            if (!self.parseFieldTypeIsSupported(field.ty, true)) Common.invariant("structural parser record field type was not supported");
                        }
                        break :blk;
                    },
                    .tag_union => |tags_span| blk: {
                        const tags = self.builder.program.types.tagSpan(tags_span);
                        if (tags.len == 0) Common.invariant("structural parser empty tag union reached postcheck lowering");
                        for (tags) |tag| {
                            for (self.builder.program.types.span(tag.payloads)) |payload_ty| {
                                if (!self.parseFieldTypeIsSupported(payload_ty, false)) Common.invariant("structural parser tag-union payload type was not supported");
                            }
                        }
                        break :blk;
                    },
                    .zst => {},
                    else => Common.invariant("structural parser dispatcher was not a supported structural type"),
                }
            }
        }

        const encoding_value = if (pre_lowered != null and pre_lowered.?.index == 0)
            pre_lowered.?.expr
        else
            try arg_ctx.lowerDispatchOperandAtType(plan_args[0], arg_tys[0]);
        const encoding_local = try self.addLocal(self.builder.symbols.fresh(), arg_tys[0]);
        self.setLocalCaptureId(encoding_local, parserEncodingCaptureId());
        const state_local = try self.addLocal(self.builder.symbols.fresh(), runtime_arg_tys[0]);

        const str_ty = try self.builder.primitiveType(.str);
        var precomputed_plan = ParserPrecomputedPlan.init(self.allocator);
        defer precomputed_plan.deinit();
        try self.buildParserConstructionPrecomputedPlan(
            &precomputed_plan,
            shape_ty,
            try self.localExpr(encoding_local, arg_tys[0]),
            arg_tys[0],
            str_ty,
        );

        const parsed = try self.lowerParseResultFromState(
            shape_ty,
            try self.localExpr(encoding_local, arg_tys[0]),
            arg_tys[0],
            try self.localExpr(state_local, runtime_arg_tys[0]),
            runtime_arg_tys[0],
            runtime_fn.ret,
            &precomputed_plan,
        );
        const fn_id = try self.addFn(.{
            .fn_def = .{ .parser_runtime = .{
                .owner = self.owner_template,
                .expr = plan.expr,
            } },
            .source_fn_ty = plan.callable_ty,
            .source_fn_key = generatedParserRuntimeKey(self.current_fn_key, plan.expr),
            .mono_fn_ty = ret_ty,
        });
        var parser_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .lambda = .{
            .fn_id = .{ .draft = fn_id },
            .args = try self.addTypedLocalSpan(&.{
                .{ .local = state_local, .ty = runtime_arg_tys[0] },
            }),
            .body = parsed,
        } } });
        var capture_index = precomputed_plan.captures.items.len;
        while (capture_index > 0) {
            capture_index -= 1;
            const capture = precomputed_plan.captures.items[capture_index];
            parser_expr = try self.wrapLet(capture.local, str_ty, capture.value, parser_expr, ret_ty);
        }
        return try self.wrapLet(encoding_local, arg_tys[0], encoding_value, parser_expr, ret_ty);
    }

    fn lowerStructuralEncodeTo(
        self: *BodyContext,
        plan: static_dispatch.StaticDispatchCallPlan,
        callable_mono_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        arg_ctx: *BodyContext,
        pre_lowered: ?PreLoweredOperand,
    ) Allocator.Error!DraftExprId {
        const encode_to = switch (plan.result_mode) {
            .encode_to => |encode_to| encode_to,
            else => Common.invariant("non-encode_to dispatch plan reached structural encode_to lowering"),
        };
        if (!encode_to.structural_allowed) Common.invariant("structural encode_to dispatch plan did not permit structural encode_to lowering");

        const fn_data = self.builder.functionShape(callable_mono_ty, "checked structural encode_to target had a non-function type");
        const arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(fn_data.args));
        defer self.allocator.free(arg_tys);
        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        if (arg_tys.len != 2 or plan_args.len != 2) Common.invariant("structural encode_to callable type must have value and encoding arguments");
        if (!self.sameType(fn_data.ret, ret_ty)) Common.invariant("structural encode_to return type differed from dispatch expression type");

        const runtime_fn = self.builder.functionShape(ret_ty, "checked structural encode_to return had a non-function type");
        const runtime_arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(runtime_fn.args));
        defer self.allocator.free(runtime_arg_tys);
        if (runtime_arg_tys.len != 1) Common.invariant("structural encode_to runtime function must have one state argument");

        const shape_ty = try self.sealCheckedType(plan.dispatcher_ty);
        if (!self.encodeFieldTypeIsSupported(shape_ty)) Common.invariant("structural encode_to dispatcher was not a supported structural type");

        const value_expr = if (pre_lowered != null and pre_lowered.?.index == 0)
            pre_lowered.?.expr
        else
            try arg_ctx.lowerDispatchOperandAtType(plan_args[0], arg_tys[0]);
        const encoding_value = if (pre_lowered != null and pre_lowered.?.index == 1)
            pre_lowered.?.expr
        else
            try arg_ctx.lowerDispatchOperandAtType(plan_args[1], arg_tys[1]);

        const value_local = try self.addLocal(self.builder.symbols.fresh(), arg_tys[0]);
        const encoding_local = try self.addLocal(self.builder.symbols.fresh(), arg_tys[1]);
        const state_local = try self.addLocal(self.builder.symbols.fresh(), runtime_arg_tys[0]);
        self.setLocalCaptureId(value_local, encodeToValueCaptureId());
        self.setLocalCaptureId(encoding_local, encodeToEncodingCaptureId());

        const str_ty = try self.builder.primitiveType(.str);
        var precomputed_plan = ParserPrecomputedPlan.init(self.allocator);
        defer precomputed_plan.deinit();
        precomputed_plan.next_capture_id = encodeToFirstFieldCaptureId();
        try self.buildEncodeConstructionPrecomputedPlan(
            &precomputed_plan,
            shape_ty,
            try self.localExpr(encoding_local, arg_tys[1]),
            arg_tys[1],
            str_ty,
        );

        const encoded = try self.lowerEncodeShapeToState(
            shape_ty,
            try self.localExpr(value_local, arg_tys[0]),
            try self.localExpr(encoding_local, arg_tys[1]),
            arg_tys[1],
            try self.localExpr(state_local, runtime_arg_tys[0]),
            runtime_arg_tys[0],
            runtime_fn.ret,
            &precomputed_plan,
        );
        const fn_id = try self.addFn(.{
            .fn_def = .{ .encode_to_runtime = .{
                .owner = self.owner_template,
                .expr = plan.expr,
            } },
            .source_fn_ty = plan.callable_ty,
            .source_fn_key = generatedEncodeToRuntimeKey(self.current_fn_key, plan.expr),
            .mono_fn_ty = ret_ty,
        });
        var encoder_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .lambda = .{
            .fn_id = .{ .draft = fn_id },
            .args = try self.addTypedLocalSpan(&.{
                .{ .local = state_local, .ty = runtime_arg_tys[0] },
            }),
            .body = encoded,
        } } });
        var capture_index = precomputed_plan.captures.items.len;
        while (capture_index > 0) {
            capture_index -= 1;
            const capture = precomputed_plan.captures.items[capture_index];
            encoder_expr = try self.wrapLet(capture.local, str_ty, capture.value, encoder_expr, ret_ty);
        }
        encoder_expr = try self.wrapLet(encoding_local, arg_tys[1], encoding_value, encoder_expr, ret_ty);
        return try self.wrapLet(value_local, arg_tys[0], value_expr, encoder_expr, ret_ty);
    }

    fn lowerEncodeShapeToState(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        if (self.tryJsonInfo(shape_ty)) |info| {
            if (!info.has_null or info.has_missing) Common.invariant("unsupported JSON Try shape reached encode_to lowering");
            return try self.lowerEncodeJsonTryToState(info, shape_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
        }
        if (self.dictEntryShape(shape_ty)) |dict| {
            return try self.lowerEncodeDictToState(dict.key_ty, dict.value_ty, shape_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
        }
        if (self.setPayloadType(shape_ty)) |payload_ty| {
            return try self.lowerEncodeSetToState(payload_ty, shape_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
        }
        switch (self.builder.shapeContent(shape_ty)) {
            .list => |elem_ty| return try self.lowerEncodeListToState(elem_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan),
            .tuple => |items| {
                const item_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(items));
                defer self.allocator.free(item_tys);
                return try self.lowerEncodeTupleToState(item_tys, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
            },
            .box => |payload_ty| {
                const unboxed = try self.lowLevelExpr(.box_unbox, &.{value_expr}, payload_ty);
                return try self.lowerEncodeShapeToState(payload_ty, unboxed, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
            },
            else => {},
        }
        if (self.customEncodeToLookup(shape_ty)) |lookup| {
            return try self.lowerCustomEncodeToState(lookup, shape_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty);
        }
        if (self.jsonEncodeScalarMethodName(shape_ty)) |method_name| {
            return try self.lowerEncodeFormatMethod(method_name, &.{ value_expr, state_expr }, &.{ shape_ty, state_ty }, encoding_ty, ret_ty);
        }
        return switch (self.builder.shapeContent(shape_ty)) {
            .record, .zst => try self.lowerEncodeRecordToState(shape_ty, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan),
            .tag_union => |tags_span| try self.lowerEncodeTagUnionToState(tags_span, value_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan),
            else => Common.invariant("encode_to selected an unsupported shape"),
        };
    }

    fn lowerEncodeTupleToState(
        self: *BodyContext,
        item_tys: []const Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const begin_try = try self.lowerEncodeFormatMethod("begin_array", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const begin_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const body = try self.lowerEncodeTupleItemsFromState(
            item_tys,
            value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(begin_state_local, state_ty),
            state_ty,
            ret_ty,
            0,
            precomputed_plan,
        );
        return try self.sequenceEncodeTry(begin_try, ret_ty, begin_state_local, body, ret_ty);
    }

    fn lowerEncodeTupleItemsFromState(
        self: *BodyContext,
        item_tys: []const Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        item_index: usize,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        if (item_index == item_tys.len) {
            return try self.lowerEncodeFormatMethod("end_array", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        }

        const element_start_try = try self.lowerEncodeFormatMethod("encode_array_element", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const element_start_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const item_ty = item_tys[item_index];
        const item_expr = try self.addExpr(.{ .ty = item_ty, .data = .{ .tuple_access = .{
            .tuple = value_expr,
            .elem_index = @intCast(item_index),
        } } });
        const item_try = try self.lowerEncodeShapeToState(
            item_ty,
            item_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(element_start_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
        );
        const item_done_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const rest = try self.lowerEncodeTupleItemsFromState(
            item_tys,
            value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(item_done_local, state_ty),
            state_ty,
            ret_ty,
            item_index + 1,
            precomputed_plan,
        );
        const after_item = try self.sequenceEncodeTry(item_try, ret_ty, item_done_local, rest, ret_ty);
        return try self.sequenceEncodeTry(element_start_try, ret_ty, element_start_local, after_item, ret_ty);
    }

    fn lowerEncodeListToState(
        self: *BodyContext,
        elem_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const begin_try = try self.lowerEncodeFormatMethod("begin_array", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const begin_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const u64_ty = try self.builder.primitiveType(.u64);
        const len_local = try self.addLocal(self.builder.symbols.fresh(), u64_ty);
        const index_local = try self.addLocal(self.builder.symbols.fresh(), u64_ty);
        const loop_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const len_value = try self.lowLevelExpr(.list_len, &.{value_expr}, u64_ty);
        const loop_body = try self.lowerEncodeListLoopBody(
            elem_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            state_ty,
            len_local,
            index_local,
            loop_state_local,
            ret_ty,
            precomputed_plan,
        );
        const params = [_]BodyTypedLocal{
            .{ .local = index_local, .ty = u64_ty },
            .{ .local = loop_state_local, .ty = state_ty },
        };
        const initial_values = [_]DraftExprId{
            try self.intLiteralExpr(0, u64_ty),
            try self.localExpr(begin_state_local, state_ty),
        };
        const loop_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .loop_ = .{
            .params = try self.addTypedLocalSpan(&params),
            .initial_values = try self.addExprSpan(&initial_values),
            .body = loop_body,
        } } });
        const with_len = try self.wrapLet(len_local, u64_ty, len_value, loop_expr, ret_ty);
        return try self.sequenceEncodeTry(begin_try, ret_ty, begin_state_local, with_len, ret_ty);
    }

    fn lowerEncodeSetToState(
        self: *BodyContext,
        elem_ty: Type.TypeId,
        set_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const list_ty = try self.listType(elem_ty);
        const list_expr = try self.lowerSetToList(set_ty, list_ty, value_expr);
        return try self.lowerEncodeListToState(elem_ty, list_expr, encoding_expr, encoding_ty, state_expr, state_ty, ret_ty, precomputed_plan);
    }

    fn lowerEncodeDictToState(
        self: *BodyContext,
        key_ty: Type.TypeId,
        value_ty: Type.TypeId,
        dict_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const begin_try = try self.lowerEncodeFormatMethod("begin_record", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const begin_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const entry_ty = try self.tupleType(&.{ key_ty, value_ty });
        const entries_ty = try self.listType(entry_ty);
        const entries_expr = try self.lowerDictToList(dict_ty, entries_ty, value_expr);
        const entries_local = try self.addLocal(self.builder.symbols.fresh(), entries_ty);
        const u64_ty = try self.builder.primitiveType(.u64);
        const len_local = try self.addLocal(self.builder.symbols.fresh(), u64_ty);
        const index_local = try self.addLocal(self.builder.symbols.fresh(), u64_ty);
        const loop_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const len_value = try self.lowLevelExpr(.list_len, &.{try self.localExpr(entries_local, entries_ty)}, u64_ty);
        const loop_body = try self.lowerEncodeDictLoopBody(
            key_ty,
            value_ty,
            entry_ty,
            try self.localExpr(entries_local, entries_ty),
            encoding_expr,
            encoding_ty,
            state_ty,
            len_local,
            index_local,
            loop_state_local,
            ret_ty,
            precomputed_plan,
        );
        const params = [_]BodyTypedLocal{
            .{ .local = index_local, .ty = u64_ty },
            .{ .local = loop_state_local, .ty = state_ty },
        };
        const initial_values = [_]DraftExprId{
            try self.intLiteralExpr(0, u64_ty),
            try self.localExpr(begin_state_local, state_ty),
        };
        const loop_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .loop_ = .{
            .params = try self.addTypedLocalSpan(&params),
            .initial_values = try self.addExprSpan(&initial_values),
            .body = loop_body,
        } } });
        const with_len = try self.wrapLet(len_local, u64_ty, len_value, loop_expr, ret_ty);
        const with_entries = try self.wrapLet(entries_local, entries_ty, entries_expr, with_len, ret_ty);
        return try self.sequenceEncodeTry(begin_try, ret_ty, begin_state_local, with_entries, ret_ty);
    }

    fn lowerEncodeDictLoopBody(
        self: *BodyContext,
        key_ty: Type.TypeId,
        value_ty: Type.TypeId,
        entry_ty: Type.TypeId,
        entries_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        len_local: DraftLocalId,
        index_local: DraftLocalId,
        loop_state_local: DraftLocalId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const bool_ty = try self.builder.primitiveType(.bool);
        const index_expr = try self.localExpr(index_local, u64_ty);
        const len_expr = try self.localExpr(len_local, u64_ty);
        const done_cond = try self.lowLevelExpr(.num_is_eq, &.{ index_expr, len_expr }, bool_ty);
        const finish_try = try self.lowerEncodeFormatMethod(
            "end_record",
            &.{try self.localExpr(loop_state_local, state_ty)},
            &.{state_ty},
            encoding_ty,
            ret_ty,
        );
        const finish_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const finish_body = try self.addExpr(.{
            .ty = ret_ty,
            .data = .{ .break_ = try self.tryOk(ret_ty, try self.localExpr(finish_local, state_ty)) },
        });
        const finish = try self.sequenceEncodeTry(finish_try, ret_ty, finish_local, finish_body, ret_ty);

        const step = try self.lowerEncodeDictEntry(
            key_ty,
            value_ty,
            entry_ty,
            entries_expr,
            encoding_expr,
            encoding_ty,
            state_ty,
            index_local,
            loop_state_local,
            ret_ty,
            precomputed_plan,
        );
        return try self.ifExpr(done_cond, finish, step, ret_ty);
    }

    fn lowerEncodeDictEntry(
        self: *BodyContext,
        key_ty: Type.TypeId,
        value_ty: Type.TypeId,
        entry_ty: Type.TypeId,
        entries_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        index_local: DraftLocalId,
        loop_state_local: DraftLocalId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const str_ty = try self.builder.primitiveType(.str);
        const ret_info = self.tryInfo(ret_ty);
        const index_expr = try self.localExpr(index_local, u64_ty);
        const entry_expr = try self.lowLevelExpr(.list_get_unsafe, &.{ entries_expr, index_expr }, entry_ty);
        const key_expr = try self.addExpr(.{ .ty = key_ty, .data = .{ .tuple_access = .{
            .tuple = entry_expr,
            .elem_index = 0,
        } } });
        const entry_expr_for_value = try self.lowLevelExpr(.list_get_unsafe, &.{ entries_expr, index_expr }, entry_ty);
        const item_value_expr = try self.addExpr(.{ .ty = value_ty, .data = .{ .tuple_access = .{
            .tuple = entry_expr_for_value,
            .elem_index = 1,
        } } });

        const key_try_ty = try self.tryTypeLike(ret_ty, str_ty, ret_info.err_ty);
        const key_try = try self.lowerEncodeDictKeyToString(key_ty, key_expr, encoding_expr, encoding_ty, key_try_ty);
        const key_local = try self.addLocal(self.builder.symbols.fresh(), str_ty);
        const field_start_try = try self.lowerEncodeFormatMethod(
            "encode_record_field",
            &.{ try self.localExpr(key_local, str_ty), try self.localExpr(loop_state_local, state_ty) },
            &.{ str_ty, state_ty },
            encoding_ty,
            ret_ty,
        );
        const field_start_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const value_try = try self.lowerEncodeShapeToState(
            value_ty,
            item_value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(field_start_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
        );
        const value_done_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const next_index = try self.lowLevelExpr(.num_plus, &.{ index_expr, try self.intLiteralExpr(1, u64_ty) }, u64_ty);
        const continue_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .continue_ = .{
            .values = try self.addExprSpan(&[_]DraftExprId{
                next_index,
                try self.localExpr(value_done_local, state_ty),
            }),
        } } });
        const after_value = try self.sequenceEncodeTry(value_try, ret_ty, value_done_local, continue_expr, ret_ty);
        const after_field = try self.sequenceEncodeTry(field_start_try, ret_ty, field_start_local, after_value, ret_ty);
        return try self.sequenceEncodeTry(key_try, key_try_ty, key_local, after_field, ret_ty);
    }

    fn lowerEncodeDictKeyToString(
        self: *BodyContext,
        key_ty: Type.TypeId,
        key_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        if (self.jsonEncodeObjectKeyMethodName(key_ty)) |method_name| {
            return try self.lowerEncodeFormatMethod(
                method_name,
                &.{ encoding_expr, key_expr },
                &.{ encoding_ty, key_ty },
                encoding_ty,
                ret_ty,
            );
        }
        if (self.jsonObjectKeyUnitTags(key_ty)) |tags_span| {
            return try self.lowerEncodeUnitTagDictKeyToString(tags_span, key_ty, key_expr, ret_ty);
        }
        Common.invariant("dict encode key type was unsupported");
    }

    fn lowerEncodeUnitTagDictKeyToString(
        self: *BodyContext,
        tags_span: Type.Span,
        key_ty: Type.TypeId,
        key_expr: DraftExprId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const str_ty = try self.builder.primitiveType(.str);
        const tags = self.builder.program.types.tagSpan(tags_span);
        const branches = try self.allocator.alloc(DraftBranch, tags.len);
        defer self.allocator.free(branches);
        for (tags, 0..) |tag, index| {
            if (self.builder.program.types.span(tag.payloads).len != 0) Common.invariant("dict unit tag key had payloads");
            const pat = try self.addPat(.{ .ty = key_ty, .data = .{ .tag = .{
                .name = tag.name,
                .payloads = .empty(),
            } } });
            const tag_name_expr = try self.stringExpr(self.builder.program.names.tagLabelText(tag.name), str_ty);
            branches[index] = .{
                .pat = pat,
                .body = try self.tryOk(ret_ty, tag_name_expr),
            };
        }
        return try self.addExpr(.{ .ty = ret_ty, .data = .{ .match_ = .{
            .scrutinee = key_expr,
            .branches = try self.addBranchSpan(branches),
        } } });
    }

    fn lowerEncodeListLoopBody(
        self: *BodyContext,
        elem_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        len_local: DraftLocalId,
        index_local: DraftLocalId,
        loop_state_local: DraftLocalId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const bool_ty = try self.builder.primitiveType(.bool);
        const index_expr = try self.localExpr(index_local, u64_ty);
        const len_expr = try self.localExpr(len_local, u64_ty);
        const done_cond = try self.lowLevelExpr(.num_is_eq, &.{ index_expr, len_expr }, bool_ty);
        const finish_try = try self.lowerEncodeFormatMethod(
            "end_array",
            &.{try self.localExpr(loop_state_local, state_ty)},
            &.{state_ty},
            encoding_ty,
            ret_ty,
        );
        const finish_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const finish_body = try self.addExpr(.{
            .ty = ret_ty,
            .data = .{ .break_ = try self.tryOk(ret_ty, try self.localExpr(finish_local, state_ty)) },
        });
        const finish = try self.sequenceEncodeTry(finish_try, ret_ty, finish_local, finish_body, ret_ty);

        const step = try self.lowerEncodeListElement(
            elem_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            state_ty,
            index_local,
            loop_state_local,
            ret_ty,
            precomputed_plan,
        );
        return try self.ifExpr(done_cond, finish, step, ret_ty);
    }

    fn lowerEncodeListElement(
        self: *BodyContext,
        elem_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        index_local: DraftLocalId,
        loop_state_local: DraftLocalId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const index_expr = try self.localExpr(index_local, u64_ty);
        const element_expr = try self.lowLevelExpr(.list_get_unsafe, &.{ value_expr, index_expr }, elem_ty);
        const element_local = try self.addLocal(self.builder.symbols.fresh(), elem_ty);
        const element_start_try = try self.lowerEncodeFormatMethod(
            "encode_array_element",
            &.{try self.localExpr(loop_state_local, state_ty)},
            &.{state_ty},
            encoding_ty,
            ret_ty,
        );
        const element_start_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const element_try = try self.lowerEncodeShapeToState(
            elem_ty,
            try self.localExpr(element_local, elem_ty),
            encoding_expr,
            encoding_ty,
            try self.localExpr(element_start_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
        );
        const element_done_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const next_index = try self.lowLevelExpr(.num_plus, &.{ index_expr, try self.intLiteralExpr(1, u64_ty) }, u64_ty);
        const continue_expr = try self.addExpr(.{ .ty = ret_ty, .data = .{ .continue_ = .{
            .values = try self.addExprSpan(&[_]DraftExprId{
                next_index,
                try self.localExpr(element_done_local, state_ty),
            }),
        } } });
        const after_element = try self.sequenceEncodeTry(element_try, ret_ty, element_done_local, continue_expr, ret_ty);
        const body = try self.sequenceEncodeTry(element_start_try, ret_ty, element_start_local, after_element, ret_ty);
        return try self.wrapLet(element_local, elem_ty, element_expr, body, ret_ty);
    }

    fn lowerEncodeJsonTryToState(
        self: *BodyContext,
        info: TryJsonInfo,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const try_info = self.tryInfo(shape_ty);

        const ok_payload_local = try self.addLocal(self.builder.symbols.fresh(), info.ok_payload_ty);
        const ok_payload_pat = try self.bindPat(ok_payload_local, info.ok_payload_ty);
        const ok_backing_pat = try self.addPat(.{ .ty = try_info.backing_ty, .data = .{ .tag = .{
            .name = try_info.ok_tag.name,
            .payloads = try self.addPatSpan(&[_]DraftPatId{ok_payload_pat}),
        } } });
        const ok_pat = try self.addPat(.{ .ty = shape_ty, .data = .{ .nominal = ok_backing_pat } });
        const ok_body = try self.lowerEncodeShapeToState(
            info.ok_payload_ty,
            try self.localExpr(ok_payload_local, info.ok_payload_ty),
            encoding_expr,
            encoding_ty,
            state_expr,
            state_ty,
            ret_ty,
            precomputed_plan,
        );

        const null_tag = self.monoTagByText(info.err_ty, "Null");
        if (self.builder.program.types.span(null_tag.payloads).len != 0) Common.invariant("JSON Null marker unexpectedly had payloads");
        const null_payload_pat = try self.addPat(.{ .ty = info.err_ty, .data = .{ .tag = .{
            .name = null_tag.name,
            .payloads = .empty(),
        } } });
        const err_backing_pat = try self.addPat(.{ .ty = try_info.backing_ty, .data = .{ .tag = .{
            .name = try_info.err_tag.name,
            .payloads = try self.addPatSpan(&[_]DraftPatId{null_payload_pat}),
        } } });
        const err_pat = try self.addPat(.{ .ty = shape_ty, .data = .{ .nominal = err_backing_pat } });
        const err_body = try self.lowerEncodeFormatMethod("encode_null", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);

        const branches = [_]DraftBranch{
            .{ .pat = ok_pat, .body = ok_body },
            .{ .pat = err_pat, .body = err_body },
        };
        return try self.addExpr(.{ .ty = ret_ty, .data = .{ .match_ = .{
            .scrutinee = value_expr,
            .branches = try self.addBranchSpan(&branches),
        } } });
    }

    fn lowerEncodeRecordToState(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const ret_info = self.tryInfo(ret_ty);
        if (!self.sameType(ret_info.ok_ty, state_ty)) Common.invariant("encode_to record return Ok type differed from state type");

        const record_fields = try self.allocator.dupe(Type.Field, switch (self.builder.shapeContent(shape_ty)) {
            .record => |span| self.builder.program.types.fieldSpan(span),
            .zst => &.{},
            else => Common.invariant("encode_to record requested for a non-record shape"),
        });
        defer self.allocator.free(record_fields);

        const str_ty = try self.builder.primitiveType(.str);
        var owned_renamed_field_locals: ?[]DraftLocalId = null;
        defer if (owned_renamed_field_locals) |locals| self.allocator.free(locals);
        var owned_renamed_field_values: ?[]DraftExprId = null;
        defer if (owned_renamed_field_values) |values| self.allocator.free(values);

        const precomputed = if (precomputed_plan) |plan| self.parserPlanGet(plan, shape_ty) else null;
        const renamed_field_locals = if (precomputed) |record| blk: {
            if (record.renamed_field_locals.len != record_fields.len) Common.invariant("encode_to precomputed renamed field arity differed from record field count");
            break :blk record.renamed_field_locals;
        } else blk: {
            const locals = try self.allocator.alloc(DraftLocalId, record_fields.len);
            const values = try self.allocator.alloc(DraftExprId, record_fields.len);
            owned_renamed_field_locals = locals;
            owned_renamed_field_values = values;
            for (record_fields, 0..) |field, index| {
                locals[index] = try self.addLocal(self.builder.symbols.fresh(), str_ty);
                values[index] = try self.renamedRecordFieldNameExpr(encoding_expr, encoding_ty, field, str_ty);
            }
            break :blk locals;
        };

        const begin_try = try self.lowerEncodeFormatMethod("begin_record", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const begin_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const fields_body = try self.lowerEncodeRecordFieldNamesFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(begin_state_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            0,
        );
        var body = try self.sequenceEncodeTry(begin_try, ret_ty, begin_state_local, fields_body, ret_ty);
        if (owned_renamed_field_values) |renamed_field_values| {
            var index = renamed_field_locals.len;
            while (index > 0) {
                index -= 1;
                body = try self.wrapLet(renamed_field_locals[index], str_ty, renamed_field_values[index], body, ret_ty);
            }
        }
        return body;
    }

    fn lowerEncodeRecordFieldNamesFrom(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
        record_fields: []const Type.Field,
        renamed_field_locals: []const DraftLocalId,
        field_index: usize,
    ) Allocator.Error!DraftExprId {
        if (field_index >= record_fields.len) {
            return try self.lowerEncodeFormatMethod("end_record", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        }

        const field = record_fields[field_index];
        const field_value_expr = try self.addExpr(.{
            .ty = field.ty,
            .data = .{ .field_access = .{
                .receiver = value_expr,
                .field = field.name,
            } },
        });

        if (self.tryJsonInfo(field.ty)) |optional_info| {
            if (!optional_info.has_missing) {
                return try self.lowerEncodePresentRecordFieldFrom(
                    shape_ty,
                    value_expr,
                    encoding_expr,
                    encoding_ty,
                    state_expr,
                    state_ty,
                    ret_ty,
                    precomputed_plan,
                    record_fields,
                    renamed_field_locals,
                    field_index,
                    field.ty,
                    field_value_expr,
                );
            }
            return try self.lowerEncodeOptionalRecordFieldFrom(
                shape_ty,
                value_expr,
                encoding_expr,
                encoding_ty,
                state_expr,
                state_ty,
                ret_ty,
                precomputed_plan,
                record_fields,
                renamed_field_locals,
                field_index,
                field_value_expr,
                optional_info,
            );
        }

        return try self.lowerEncodePresentRecordFieldFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            state_expr,
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            field_index,
            field.ty,
            field_value_expr,
        );
    }

    fn lowerEncodePresentRecordFieldFrom(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
        record_fields: []const Type.Field,
        renamed_field_locals: []const DraftLocalId,
        field_index: usize,
        field_value_ty: Type.TypeId,
        field_value_expr: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const str_ty = try self.builder.primitiveType(.str);
        const renamed_field_expr = try self.localExpr(renamed_field_locals[field_index], str_ty);
        const field_name_try = try self.lowerEncodeFormatMethod("encode_record_field", &.{ renamed_field_expr, state_expr }, &.{ str_ty, state_ty }, encoding_ty, ret_ty);
        const after_name_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);

        const value_try = try self.lowerEncodeShapeToState(
            field_value_ty,
            field_value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(after_name_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
        );
        const after_value_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const rest_body = try self.lowerEncodeRecordFieldNamesFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(after_value_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            field_index + 1,
        );
        const value_body = try self.sequenceEncodeTry(value_try, ret_ty, after_value_local, rest_body, ret_ty);
        return try self.sequenceEncodeTry(field_name_try, ret_ty, after_name_local, value_body, ret_ty);
    }

    fn lowerEncodeNullRecordFieldFrom(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
        record_fields: []const Type.Field,
        renamed_field_locals: []const DraftLocalId,
        field_index: usize,
    ) Allocator.Error!DraftExprId {
        const str_ty = try self.builder.primitiveType(.str);
        const renamed_field_expr = try self.localExpr(renamed_field_locals[field_index], str_ty);
        const field_name_try = try self.lowerEncodeFormatMethod("encode_record_field", &.{ renamed_field_expr, state_expr }, &.{ str_ty, state_ty }, encoding_ty, ret_ty);
        const after_name_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const null_try = try self.lowerEncodeFormatMethod("encode_null", &.{try self.localExpr(after_name_local, state_ty)}, &.{state_ty}, encoding_ty, ret_ty);
        const after_null_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const rest_body = try self.lowerEncodeRecordFieldNamesFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            try self.localExpr(after_null_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            field_index + 1,
        );
        const null_body = try self.sequenceEncodeTry(null_try, ret_ty, after_null_local, rest_body, ret_ty);
        return try self.sequenceEncodeTry(field_name_try, ret_ty, after_name_local, null_body, ret_ty);
    }

    fn lowerEncodeOptionalRecordFieldFrom(
        self: *BodyContext,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
        record_fields: []const Type.Field,
        renamed_field_locals: []const DraftLocalId,
        field_index: usize,
        field_value_expr: DraftExprId,
        optional_info: TryJsonInfo,
    ) Allocator.Error!DraftExprId {
        const field_ty = record_fields[field_index].ty;
        const try_info = self.tryInfo(field_ty);
        if (!self.sameType(try_info.ok_ty, optional_info.ok_payload_ty)) Common.invariant("optional encode_to field Ok payload differed from optional info");
        if (!self.sameType(try_info.err_ty, optional_info.err_ty)) Common.invariant("optional encode_to field Err payload differed from optional info");

        const ok_payload_local = try self.addLocal(self.builder.symbols.fresh(), optional_info.ok_payload_ty);
        const ok_payload_pat = try self.bindPat(ok_payload_local, optional_info.ok_payload_ty);
        const ok_backing_pat = try self.addPat(.{ .ty = optional_info.backing_ty, .data = .{ .tag = .{
            .name = try_info.ok_tag.name,
            .payloads = try self.addPatSpan(&[_]DraftPatId{ok_payload_pat}),
        } } });
        const ok_pat = try self.addPat(.{
            .ty = field_ty,
            .data = .{ .nominal = ok_backing_pat },
        });
        const ok_body = try self.lowerEncodePresentRecordFieldFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            state_expr,
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            field_index,
            optional_info.ok_payload_ty,
            try self.localExpr(ok_payload_local, optional_info.ok_payload_ty),
        );

        const missing_tag = self.monoTagByText(optional_info.err_ty, "Missing");
        if (self.builder.program.types.span(missing_tag.payloads).len != 0) Common.invariant("JSON Missing marker unexpectedly had payloads");
        const missing_payload_pat = try self.addPat(.{ .ty = optional_info.err_ty, .data = .{ .tag = .{
            .name = missing_tag.name,
            .payloads = .empty(),
        } } });
        const missing_backing_pat = try self.addPat(.{ .ty = optional_info.backing_ty, .data = .{ .tag = .{
            .name = try_info.err_tag.name,
            .payloads = try self.addPatSpan(&[_]DraftPatId{missing_payload_pat}),
        } } });
        const missing_pat = try self.addPat(.{
            .ty = field_ty,
            .data = .{ .nominal = missing_backing_pat },
        });
        const missing_body = try self.lowerEncodeRecordFieldNamesFrom(
            shape_ty,
            value_expr,
            encoding_expr,
            encoding_ty,
            state_expr,
            state_ty,
            ret_ty,
            precomputed_plan,
            record_fields,
            renamed_field_locals,
            field_index + 1,
        );

        var branches = std.ArrayList(DraftBranch).empty;
        defer branches.deinit(self.allocator);
        try branches.append(self.allocator, .{ .pat = ok_pat, .body = ok_body });
        try branches.append(self.allocator, .{ .pat = missing_pat, .body = missing_body });

        if (optional_info.has_null) {
            const null_tag = self.monoTagByText(optional_info.err_ty, "Null");
            if (self.builder.program.types.span(null_tag.payloads).len != 0) Common.invariant("JSON Null marker unexpectedly had payloads");
            const null_payload_pat = try self.addPat(.{ .ty = optional_info.err_ty, .data = .{ .tag = .{
                .name = null_tag.name,
                .payloads = .empty(),
            } } });
            const null_backing_pat = try self.addPat(.{ .ty = optional_info.backing_ty, .data = .{ .tag = .{
                .name = try_info.err_tag.name,
                .payloads = try self.addPatSpan(&[_]DraftPatId{null_payload_pat}),
            } } });
            const null_pat = try self.addPat(.{
                .ty = field_ty,
                .data = .{ .nominal = null_backing_pat },
            });
            const null_body = try self.lowerEncodeNullRecordFieldFrom(
                shape_ty,
                value_expr,
                encoding_expr,
                encoding_ty,
                state_expr,
                state_ty,
                ret_ty,
                precomputed_plan,
                record_fields,
                renamed_field_locals,
                field_index,
            );
            try branches.append(self.allocator, .{ .pat = null_pat, .body = null_body });
        }

        return try self.addExpr(.{ .ty = ret_ty, .data = .{ .match_ = .{
            .scrutinee = field_value_expr,
            .branches = try self.addBranchSpan(branches.items),
        } } });
    }

    fn lowerEncodeTagUnionToState(
        self: *BodyContext,
        tags_span: Type.Span,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const tags = try self.allocator.dupe(Type.Tag, self.builder.program.types.tagSpan(tags_span));
        defer self.allocator.free(tags);
        if (tags.len == 0) Common.invariant("encode_to selected an empty tag union");

        const value_ty = try self.exprType(value_expr);
        const branches = try self.allocator.alloc(DraftBranch, tags.len);
        defer self.allocator.free(branches);

        for (tags, 0..) |tag, tag_index| {
            const payload_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(tag.payloads));
            defer self.allocator.free(payload_tys);

            const payload_pats = try self.allocator.alloc(DraftPatId, payload_tys.len);
            defer self.allocator.free(payload_pats);
            const payload_exprs = try self.allocator.alloc(DraftExprId, payload_tys.len);
            defer self.allocator.free(payload_exprs);

            for (payload_tys, 0..) |payload_ty, payload_index| {
                const payload_local = try self.addLocal(self.builder.symbols.fresh(), payload_ty);
                payload_pats[payload_index] = try self.bindPat(payload_local, payload_ty);
                payload_exprs[payload_index] = try self.localExpr(payload_local, payload_ty);
            }

            const pat = try self.addPat(.{ .ty = value_ty, .data = .{ .tag = .{
                .name = tag.name,
                .payloads = try self.addPatSpan(payload_pats),
            } } });
            branches[tag_index] = .{
                .pat = pat,
                .body = try self.lowerEncodeTagUnionBranchToState(
                    tag,
                    payload_exprs,
                    payload_tys,
                    encoding_expr,
                    encoding_ty,
                    state_expr,
                    state_ty,
                    ret_ty,
                    precomputed_plan,
                ),
            };
        }

        return try self.addExpr(.{ .ty = ret_ty, .data = .{ .match_ = .{
            .scrutinee = value_expr,
            .branches = try self.addBranchSpan(branches),
        } } });
    }

    fn lowerEncodeTagUnionBranchToState(
        self: *BodyContext,
        tag: Type.Tag,
        payload_exprs: []const DraftExprId,
        payload_tys: []const Type.TypeId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        if (payload_exprs.len != payload_tys.len) Common.invariant("tag union encode payload arity mismatch");

        const tag_name_expr = try self.stringExpr(self.builder.program.names.tagLabelText(tag.name), try self.builder.primitiveType(.str));
        if (payload_tys.len == 0) {
            return try self.lowerEncodeFormatMethod(
                "encode_str",
                &.{ tag_name_expr, state_expr },
                &.{ try self.builder.primitiveType(.str), state_ty },
                encoding_ty,
                ret_ty,
            );
        }

        const begin_outer_try = try self.lowerEncodeFormatMethod("begin_record", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const outer_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const tag_name_try = try self.lowerEncodeFormatMethod(
            "encode_record_field",
            &.{ tag_name_expr, try self.localExpr(outer_state_local, state_ty) },
            &.{ try self.builder.primitiveType(.str), state_ty },
            encoding_ty,
            ret_ty,
        );
        const after_name_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);

        const payload_try = if (payload_tys.len == 1)
            try self.lowerEncodeShapeToState(
                payload_tys[0],
                payload_exprs[0],
                encoding_expr,
                encoding_ty,
                try self.localExpr(after_name_local, state_ty),
                state_ty,
                ret_ty,
                precomputed_plan,
            )
        else
            try self.lowerEncodePayloadArrayToState(
                payload_exprs,
                payload_tys,
                encoding_expr,
                encoding_ty,
                try self.localExpr(after_name_local, state_ty),
                state_ty,
                ret_ty,
                precomputed_plan,
            );
        const after_payload_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const end_outer_try = try self.lowerEncodeFormatMethod(
            "end_record",
            &.{try self.localExpr(after_payload_local, state_ty)},
            &.{state_ty},
            encoding_ty,
            ret_ty,
        );
        const payload_body = try self.sequenceEncodeTry(payload_try, ret_ty, after_payload_local, end_outer_try, ret_ty);
        const tag_body = try self.sequenceEncodeTry(tag_name_try, ret_ty, after_name_local, payload_body, ret_ty);
        return try self.sequenceEncodeTry(begin_outer_try, ret_ty, outer_state_local, tag_body, ret_ty);
    }

    fn lowerEncodePayloadArrayToState(
        self: *BodyContext,
        payload_exprs: []const DraftExprId,
        payload_tys: []const Type.TypeId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        const begin_try = try self.lowerEncodeFormatMethod("begin_array", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const begin_state_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const body = try self.lowerEncodePayloadArrayItemsFromState(
            payload_exprs,
            payload_tys,
            encoding_expr,
            encoding_ty,
            try self.localExpr(begin_state_local, state_ty),
            state_ty,
            ret_ty,
            0,
            precomputed_plan,
        );
        return try self.sequenceEncodeTry(begin_try, ret_ty, begin_state_local, body, ret_ty);
    }

    fn lowerEncodePayloadArrayItemsFromState(
        self: *BodyContext,
        payload_exprs: []const DraftExprId,
        payload_tys: []const Type.TypeId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
        item_index: usize,
        precomputed_plan: ?*const ParserPrecomputedPlan,
    ) Allocator.Error!DraftExprId {
        if (item_index == payload_tys.len) {
            return try self.lowerEncodeFormatMethod("end_array", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        }

        const element_start_try = try self.lowerEncodeFormatMethod("encode_array_element", &.{state_expr}, &.{state_ty}, encoding_ty, ret_ty);
        const element_start_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const item_try = try self.lowerEncodeShapeToState(
            payload_tys[item_index],
            payload_exprs[item_index],
            encoding_expr,
            encoding_ty,
            try self.localExpr(element_start_local, state_ty),
            state_ty,
            ret_ty,
            precomputed_plan,
        );
        const item_done_local = try self.addLocal(self.builder.symbols.fresh(), state_ty);
        const rest = try self.lowerEncodePayloadArrayItemsFromState(
            payload_exprs,
            payload_tys,
            encoding_expr,
            encoding_ty,
            try self.localExpr(item_done_local, state_ty),
            state_ty,
            ret_ty,
            item_index + 1,
            precomputed_plan,
        );
        const after_item = try self.sequenceEncodeTry(item_try, ret_ty, item_done_local, rest, ret_ty);
        return try self.sequenceEncodeTry(element_start_try, ret_ty, element_start_local, after_item, ret_ty);
    }

    fn encodeRecordFieldPayloadType(self: *BodyContext, field_ty: Type.TypeId) Type.TypeId {
        if (self.tryJsonInfo(field_ty)) |optional_info| {
            if (optional_info.has_missing) return optional_info.ok_payload_ty;
        }
        return field_ty;
    }

    fn encodeRecordFieldTypeIsSupported(self: *BodyContext, field_ty: Type.TypeId) bool {
        if (self.tryJsonInfo(field_ty)) |info| return self.encodeFieldTypeIsSupported(info.ok_payload_ty);
        return self.encodeFieldTypeIsSupported(self.encodeRecordFieldPayloadType(field_ty));
    }

    fn encodeTagUnionTypeIsSupported(self: *BodyContext, tags_span: Type.Span) bool {
        const tags = self.builder.program.types.tagSpan(tags_span);
        if (tags.len == 0) return false;
        for (tags) |tag| {
            const payloads = self.builder.program.types.span(tag.payloads);
            for (payloads) |payload_ty| {
                if (!self.encodeFieldTypeIsSupported(payload_ty)) return false;
            }
        }
        return true;
    }

    fn lowerCustomEncodeToState(
        self: *BodyContext,
        lookup: MethodLookup,
        shape_ty: Type.TypeId,
        value_expr: DraftExprId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_expr: DraftExprId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const runtime_fn_ty = try self.builder.program.types.add(.{ .func = .{
            .args = try self.builder.program.types.addSpan(&.{state_ty}),
            .ret = ret_ty,
        } });
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &.{ shape_ty, encoding_ty }, runtime_fn_ty);
        const encode_fn = self.builder.functionShape(callable_mono_ty, "custom encode_to target was not a function");
        const encode_arg_tys = self.builder.program.types.span(encode_fn.args);
        if (encode_arg_tys.len != 2) Common.invariant("custom encode_to target had an unexpected arity");
        if (!self.sameType(encode_arg_tys[0], shape_ty)) Common.invariant("custom encode_to value type differed from encoded shape");
        if (!self.sameType(encode_arg_tys[1], encoding_ty)) Common.invariant("custom encode_to encoding type differed from input encoding type");
        if (!self.sameType(encode_fn.ret, runtime_fn_ty)) Common.invariant("custom encode_to runtime function type differed from expected type");

        const encoder_expr = try self.addExpr(.{
            .ty = runtime_fn_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(&[_]DraftExprId{ value_expr, encoding_expr }),
            } },
        });
        return try self.addExpr(.{
            .ty = ret_ty,
            .data = .{ .call_value = .{
                .callee = encoder_expr,
                .args = try self.addExprSpan(&[_]DraftExprId{state_expr}),
            } },
        });
    }

    fn lowerEncodeFormatMethod(
        self: *BodyContext,
        method_name: []const u8,
        arg_exprs: []const DraftExprId,
        arg_tys: []const Type.TypeId,
        encoding_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const lookup = self.methodLookupForTypeName(encoding_ty, method_name);
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, arg_tys, ret_ty);
        const encode_fn = self.builder.functionShape(callable_mono_ty, "encode_to target method was not a function");
        const actual_arg_tys = self.builder.program.types.span(encode_fn.args);
        if (actual_arg_tys.len != arg_tys.len) Common.invariant("encode_to target method had an unexpected arity");
        for (actual_arg_tys, arg_tys) |actual, expected| {
            if (!self.sameType(actual, expected)) Common.invariant("encode_to target method argument type differed from expected type");
        }
        if (!self.sameType(encode_fn.ret, ret_ty)) Common.invariant("encode_to target method return type differed from expected type");
        return try self.addExpr(.{
            .ty = ret_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(arg_exprs),
            } },
        });
    }

    fn lowerParseFormatMethod(
        self: *BodyContext,
        method_name: []const u8,
        arg_exprs: []const DraftExprId,
        arg_tys: []const Type.TypeId,
        encoding_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const lookup = self.methodLookupForTypeName(encoding_ty, method_name);
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, arg_tys, ret_ty);
        const parse_fn = self.builder.functionShape(callable_mono_ty, "parser_for target method was not a function");
        const actual_arg_tys = self.builder.program.types.span(parse_fn.args);
        if (actual_arg_tys.len != arg_tys.len) Common.invariant("parser_for target method had an unexpected arity");
        for (actual_arg_tys, arg_tys) |actual, expected| {
            if (!self.sameType(actual, expected)) Common.invariant("parser_for target method argument type differed from expected type");
        }
        if (!self.sameType(parse_fn.ret, ret_ty)) Common.invariant("parser_for target method return type differed from expected type");
        return try self.addExpr(.{
            .ty = ret_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(arg_exprs),
            } },
        });
    }

    fn cloneNamedTypeWithArgs(
        self: *BodyContext,
        template_ty: Type.TypeId,
        args: []const Type.TypeId,
        backing_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        const template = switch (self.builder.program.types.get(template_ty)) {
            .named => |named| named,
            else => Common.invariant("Parse compiler helper expected a named template type"),
        };
        return try self.builder.program.types.add(.{ .named = .{
            .named_type = template.named_type,
            .def = template.def,
            .kind = template.kind,
            .builtin_owner = template.builtin_owner,
            .args = try self.builder.program.types.addSpan(args),
            .backing = .{ .ty = backing_ty, .use = template.backing.?.use },
            .declared_order = template.declared_order,
        } });
    }

    const TryJsonInfo = struct {
        backing_ty: Type.TypeId,
        ok_payload_ty: Type.TypeId,
        err_ty: Type.TypeId,
        has_missing: bool,
        has_null: bool,
    };

    const JsonTryErrInfo = struct {
        has_missing: bool,
        has_null: bool,
    };

    const TryInfo = struct {
        backing_ty: Type.TypeId,
        ok_ty: Type.TypeId,
        err_ty: Type.TypeId,
        ok_tag: Type.Tag,
        err_tag: Type.Tag,
    };

    const RecordFieldMatchMode = enum {
        direct,
        exact,
        caseless,
    };

    const StaticFieldLane = struct {
        offset: u32,
        active_len: u32,
    };

    fn recordPresenceWordCount(field_count: usize) usize {
        return (field_count + 63) / 64;
    }

    fn recordPresenceWordIndex(field_index: usize) usize {
        return field_index / 64;
    }

    fn recordPresenceMask(field_index: usize) u64 {
        return @as(u64, 1) << @as(u6, @intCast(field_index % 64));
    }

    fn selectStaticFieldLane(lengths: []const u32, texts: []const []const u8, length: u32) StaticFieldLane {
        if (lengths.len != texts.len) Common.invariant("record parser dispatch text arity did not match field lengths");
        if (length == 0 or length > 24) Common.invariant("static field lane requested for an unsupported field length");

        var group_count: usize = 0;
        for (lengths, texts) |field_len, text| {
            if (field_len != length) continue;
            if (text.len != length) Common.invariant("record parser dispatch text length did not match precomputed length");
            group_count += 1;
        }
        if (group_count == 0) Common.invariant("static field lane requested for an empty length bucket");

        var best = StaticFieldLane{ .offset = 0, .active_len = @min(length, 8) };
        var best_distinct: usize = 0;
        const offsets = [_]u32{ 0, 8, 16 };
        for (offsets) |offset| {
            if (offset >= length) continue;
            const active_len: u32 = @min(length - offset, 8);
            var distinct: usize = 0;
            for (texts, lengths, 0..) |text, field_len, text_index| {
                if (field_len != length) continue;
                const word = staticFieldLaneWord(text, offset, active_len);
                var seen = false;
                var previous: usize = 0;
                while (previous < text_index) : (previous += 1) {
                    if (lengths[previous] != length) continue;
                    if (staticFieldLaneWord(texts[previous], offset, active_len) == word) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) distinct += 1;
            }
            if (distinct > best_distinct) {
                best = .{ .offset = offset, .active_len = active_len };
                best_distinct = distinct;
                if (distinct == group_count) break;
            }
        }
        return best;
    }

    fn staticFieldLaneWord(text: []const u8, offset: u32, active_len: u32) u64 {
        if (active_len > 8) Common.invariant("static field lane exceeded one word");
        const offset_usize: usize = @intCast(offset);
        const active_len_usize: usize = @intCast(active_len);
        if (offset_usize > text.len or active_len_usize > text.len - offset_usize) Common.invariant("static field lane exceeded field text");
        var word: u64 = 0;
        var index: u32 = 0;
        while (index < active_len) : (index += 1) {
            word |= @as(u64, text[offset_usize + @as(usize, @intCast(index))]) << @intCast(index * 8);
        }
        return word;
    }

    fn fieldLengthAlreadyHandled(lengths: []const u32, index: usize, length: u32) bool {
        var i = index + 1;
        while (i < lengths.len) : (i += 1) {
            if (lengths[i] == length) return true;
        }
        return false;
    }

    fn tryInfo(self: *BodyContext, try_ty: Type.TypeId) TryInfo {
        const backing_ty = self.builder.namedBackingType(try_ty) orelse Common.invariant("expected a named Try type");
        const ok_tag = self.monoTagByText(backing_ty, "Ok");
        const err_tag = self.monoTagByText(backing_ty, "Err");
        const ok_payloads = self.builder.program.types.span(ok_tag.payloads);
        const err_payloads = self.builder.program.types.span(err_tag.payloads);
        if (ok_payloads.len != 1 or err_payloads.len != 1) Common.invariant("Try tags must each carry one payload");
        return .{
            .backing_ty = backing_ty,
            .ok_ty = ok_payloads[0],
            .err_ty = err_payloads[0],
            .ok_tag = ok_tag,
            .err_tag = err_tag,
        };
    }

    fn tryInfoOptional(self: *BodyContext, try_ty: Type.TypeId) ?TryInfo {
        const backing_ty = self.builder.namedBackingType(try_ty) orelse return null;
        const ok_tag = self.monoTagByTextOptional(backing_ty, "Ok") orelse return null;
        const err_tag = self.monoTagByTextOptional(backing_ty, "Err") orelse return null;
        const ok_payloads = self.builder.program.types.span(ok_tag.payloads);
        const err_payloads = self.builder.program.types.span(err_tag.payloads);
        if (ok_payloads.len != 1 or err_payloads.len != 1) return null;
        return .{
            .backing_ty = backing_ty,
            .ok_ty = ok_payloads[0],
            .err_ty = err_payloads[0],
            .ok_tag = ok_tag,
            .err_tag = err_tag,
        };
    }

    fn optionalParseTryInfo(self: *BodyContext, try_ty: Type.TypeId) ?TryInfo {
        if (self.typeHasParserForTarget(try_ty)) return null;
        if (self.tryJsonInfo(try_ty)) |info| {
            if (!info.has_missing) return null;
            return self.tryInfoOptional(try_ty) orelse Common.invariant("JSON Try info was not backed by a Try type");
        }
        return self.tryInfoOptional(try_ty);
    }

    fn tryTypeLike(
        self: *BodyContext,
        template_try_ty: Type.TypeId,
        ok_ty: Type.TypeId,
        err_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        const template_backing = self.builder.namedBackingType(template_try_ty) orelse Common.invariant("Try template type had no backing");
        const template_tags = switch (self.builder.shapeContent(template_backing)) {
            .tag_union => |span| self.builder.program.types.tagSpan(span),
            else => Common.invariant("Try template backing type was not a tag union"),
        };
        const tags = try self.allocator.alloc(Type.Tag, template_tags.len);
        defer self.allocator.free(tags);

        var found_ok = false;
        var found_err = false;
        for (template_tags, 0..) |tag, index| {
            const text = self.builder.program.names.tagLabelText(tag.name);
            const payload_ty = if (Ident.textEql(text, "Ok")) blk: {
                found_ok = true;
                break :blk ok_ty;
            } else if (Ident.textEql(text, "Err")) blk: {
                found_err = true;
                break :blk err_ty;
            } else {
                Common.invariant("Try backing type contained an unexpected tag");
            };
            tags[index] = .{
                .name = tag.name,
                .checked_name = tag.checked_name,
                .payloads = try self.builder.program.types.addSpan(&[_]Type.TypeId{payload_ty}),
            };
        }
        if (!found_ok or !found_err) Common.invariant("Try backing type did not contain Ok and Err tags");

        const backing_ty = try self.builder.program.types.add(.{ .tag_union = try self.builder.program.types.addTagVariants(&self.builder.program.names, tags) });
        const args = [_]Type.TypeId{ ok_ty, err_ty };
        return try self.cloneNamedTypeWithArgs(template_try_ty, &args, backing_ty);
    }

    fn tryOk(self: *BodyContext, try_ty: Type.TypeId, value_expr: DraftExprId) Allocator.Error!DraftExprId {
        const info = self.tryInfo(try_ty);
        const value_ty = try self.exprType(value_expr);
        if (!self.sameType(value_ty, info.ok_ty)) Common.invariant("Try.Ok payload type differed from Try Ok type");
        const backing_expr = try self.addExpr(.{
            .ty = info.backing_ty,
            .data = .{ .tag = .{
                .name = info.ok_tag.name,
                .payloads = try self.addExprSpan(&[_]DraftExprId{value_expr}),
            } },
        });
        return try self.addExpr(.{
            .ty = try_ty,
            .data = .{ .nominal = backing_expr },
        });
    }

    fn tryErr(self: *BodyContext, try_ty: Type.TypeId, err_expr: DraftExprId) Allocator.Error!DraftExprId {
        const info = self.tryInfo(try_ty);
        const err_ty = try self.exprType(err_expr);
        if (!self.sameType(err_ty, info.err_ty)) Common.invariant("Try.Err payload type differed from Try Err type");
        const backing_expr = try self.addExpr(.{
            .ty = info.backing_ty,
            .data = .{ .tag = .{
                .name = info.err_tag.name,
                .payloads = try self.addExprSpan(&[_]DraftExprId{err_expr}),
            } },
        });
        return try self.addExpr(.{
            .ty = try_ty,
            .data = .{ .nominal = backing_expr },
        });
    }

    fn sequenceTry(
        self: *BodyContext,
        try_expr: DraftExprId,
        try_ty: Type.TypeId,
        ok_local: DraftLocalId,
        ok_body: DraftExprId,
        out_try_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const info = self.tryInfo(try_ty);
        const out_info = self.tryInfo(out_try_ty);
        if (!self.sameType(info.err_ty, out_info.err_ty)) Common.invariant("sequenced Try error type differed from output Try error type");

        return try self.addExpr(.{ .ty = out_try_ty, .data = .{ .try_sequence = .{
            .try_expr = try_expr,
            .ok_local = ok_local,
            .err_is_cold = true,
            .ok_body = ok_body,
        } } });
    }

    fn sequenceEncodeTry(
        self: *BodyContext,
        try_expr: DraftExprId,
        try_ty: Type.TypeId,
        ok_local: DraftLocalId,
        ok_body: DraftExprId,
        out_try_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const info = self.tryInfo(try_ty);
        const out_info = self.tryInfo(out_try_ty);
        if (!self.sameType(info.err_ty, out_info.err_ty)) Common.invariant("sequenced encode_to Try error type differed from output Try error type");

        if (!self.typeIsClosedEmptyTagUnion(info.err_ty)) {
            return try self.sequenceTry(try_expr, try_ty, ok_local, ok_body, out_try_ty);
        }

        const ok_payload_pat = try self.bindPat(ok_local, info.ok_ty);
        const ok_backing_pat = try self.addPat(.{ .ty = info.backing_ty, .data = .{ .tag = .{
            .name = info.ok_tag.name,
            .payloads = try self.addPatSpan(&[_]DraftPatId{ok_payload_pat}),
        } } });
        const ok_pat = try self.addPat(.{ .ty = try_ty, .data = .{ .nominal = ok_backing_pat } });
        const branches = [_]DraftBranch{.{ .pat = ok_pat, .body = ok_body }};
        return try self.addExpr(.{ .ty = out_try_ty, .data = .{ .match_ = .{
            .scrutinee = try_expr,
            .branches = try self.addBranchSpan(&branches),
        } } });
    }

    fn typeIsClosedEmptyTagUnion(self: *BodyContext, ty: Type.TypeId) bool {
        return switch (self.builder.shapeContent(ty)) {
            .tag_union => |span| self.builder.program.types.tagSpan(span).len == 0,
            else => false,
        };
    }

    fn sequenceTryRecord(
        self: *BodyContext,
        try_expr: DraftExprId,
        try_ty: Type.TypeId,
        value_local: DraftLocalId,
        value_field: names.RecordFieldNameId,
        rest_local: DraftLocalId,
        rest_field: names.RecordFieldNameId,
        ok_body: DraftExprId,
        out_try_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const info = self.tryInfo(try_ty);
        const out_info = self.tryInfo(out_try_ty);
        if (!self.sameType(info.err_ty, out_info.err_ty)) Common.invariant("sequenced Try record error type differed from output Try error type");
        if (!self.sameType(self.recordFieldType(info.ok_ty, value_field), try self.localType(value_local))) {
            Common.invariant("sequenced Try record value local type differed from Ok record field");
        }
        if (!self.sameType(self.recordFieldType(info.ok_ty, rest_field), try self.localType(rest_local))) {
            Common.invariant("sequenced Try record rest local type differed from Ok record field");
        }

        return try self.addExpr(.{ .ty = out_try_ty, .data = .{ .try_record_sequence = .{
            .try_expr = try_expr,
            .value_local = value_local,
            .value_field = value_field,
            .rest_local = rest_local,
            .rest_field = rest_field,
            .err_is_cold = true,
            .ok_body = ok_body,
        } } });
    }

    fn recordFieldType(self: *BodyContext, record_ty: Type.TypeId, field_name: names.RecordFieldNameId) Type.TypeId {
        return switch (self.builder.shapeContent(record_ty)) {
            .record => |fields_span| {
                for (self.builder.program.types.fieldSpan(fields_span)) |field| {
                    if (field.name == field_name) return field.ty;
                }
                Common.invariant("record field was absent from monotype record");
            },
            else => Common.invariant("record field operation expected a record type"),
        };
    }

    fn parseFieldTypeIsSupported(self: *BodyContext, ty: Type.TypeId, allow_missing: bool) bool {
        if (self.jsonParseScalarMethodName(ty) != null) return true;
        if (self.tryJsonInfo(ty)) |info| {
            if (info.has_missing and !allow_missing) return false;
            return self.parseFieldTypeIsSupported(info.ok_payload_ty, false);
        }
        if (self.optionalParseTryInfo(ty)) |info| {
            if (!allow_missing) return false;
            return self.parseFieldTypeIsSupported(info.ok_ty, false);
        }
        if (self.customParserLookup(ty) != null) return true;
        if (self.setPayloadType(ty)) |payload_ty| return self.parseFieldTypeIsSupported(payload_ty, false);
        if (self.dictEntryShape(ty)) |dict| return self.jsonObjectKeyTypeIsSupported(dict.key_ty) and self.parseFieldTypeIsSupported(dict.value_ty, false);
        return switch (self.builder.shapeContent(ty)) {
            .list => |elem_ty| self.parseFieldTypeIsSupported(elem_ty, false),
            .box => |payload_ty| self.parseFieldTypeIsSupported(payload_ty, false),
            .tuple => |span| blk: {
                for (self.builder.program.types.span(span)) |elem_ty| {
                    if (!self.parseFieldTypeIsSupported(elem_ty, false)) break :blk false;
                }
                break :blk true;
            },
            .record => |fields_span| blk: {
                for (self.builder.program.types.fieldSpan(fields_span)) |field| {
                    if (!self.parseFieldTypeIsSupported(field.ty, true)) break :blk false;
                }
                break :blk true;
            },
            .tag_union => |tags_span| blk: {
                const tags = self.builder.program.types.tagSpan(tags_span);
                if (tags.len == 0) break :blk false;
                for (tags) |tag| {
                    for (self.builder.program.types.span(tag.payloads)) |payload_ty| {
                        if (!self.parseFieldTypeIsSupported(payload_ty, false)) break :blk false;
                    }
                }
                break :blk true;
            },
            .zst => true,
            else => false,
        };
    }

    fn encodeFieldTypeIsSupported(self: *BodyContext, ty: Type.TypeId) bool {
        if (self.jsonEncodeScalarMethodName(ty) != null) return true;
        if (self.tryJsonInfo(ty)) |info| {
            if (info.has_missing) return false;
            return self.encodeFieldTypeIsSupported(info.ok_payload_ty);
        }
        if (self.customEncodeToLookup(ty) != null) return true;
        if (self.setPayloadType(ty)) |payload_ty| return self.encodeFieldTypeIsSupported(payload_ty);
        if (self.dictEntryShape(ty)) |dict| return self.jsonObjectKeyTypeIsSupported(dict.key_ty) and self.encodeFieldTypeIsSupported(dict.value_ty);
        return switch (self.builder.shapeContent(ty)) {
            .list => |elem_ty| self.encodeFieldTypeIsSupported(elem_ty),
            .box => |payload_ty| self.encodeFieldTypeIsSupported(payload_ty),
            .tuple => |span| blk: {
                for (self.builder.program.types.span(span)) |elem_ty| {
                    if (!self.encodeFieldTypeIsSupported(elem_ty)) break :blk false;
                }
                break :blk true;
            },
            .record => |fields_span| blk: {
                for (self.builder.program.types.fieldSpan(fields_span)) |field| {
                    if (!self.encodeRecordFieldTypeIsSupported(field.ty)) break :blk false;
                }
                break :blk true;
            },
            .tag_union => |tags_span| self.encodeTagUnionTypeIsSupported(tags_span),
            .zst => true,
            else => false,
        };
    }

    fn customParserLookup(self: *BodyContext, ty: Type.TypeId) ?MethodLookup {
        const named = switch (self.builder.program.types.get(ty)) {
            .named => |named| named,
            else => return null,
        };
        if (named.builtin_owner != null) return null;
        switch (named.kind) {
            .nominal, .@"opaque" => {},
            .alias => return null,
        }
        const owner = methodOwnerFromType(&self.builder.program.types, ty) orelse
            Common.invariant("custom named parser type had no method owner");
        const lookup = self.builder.lookupMethodTargetByName(owner, "parser_for") orelse
            Common.invariant("checked method registry is missing custom parser_for target");
        return switch (lookup.target.kind) {
            .generated_structural_parser => null,
            .generated_structural_encoder => Common.invariant("parser_for lookup resolved to generated encode_to target"),
            .procedure,
            .local_proc,
            => lookup,
        };
    }

    fn typeHasParserForTarget(self: *BodyContext, ty: Type.TypeId) bool {
        const named = switch (self.builder.program.types.get(ty)) {
            .named => |named| named,
            else => return false,
        };
        if (named.builtin_owner != null) return false;
        const owner = methodOwnerFromType(&self.builder.program.types, ty) orelse return false;
        return self.builder.lookupMethodTargetByName(owner, "parser_for") != null;
    }

    fn customEncodeToLookup(self: *BodyContext, ty: Type.TypeId) ?MethodLookup {
        const named = switch (self.builder.program.types.get(ty)) {
            .named => |named| named,
            else => return null,
        };
        if (named.builtin_owner != null) return null;
        switch (named.kind) {
            .nominal, .@"opaque" => {},
            .alias => return null,
        }
        const owner = methodOwnerFromType(&self.builder.program.types, ty) orelse
            Common.invariant("custom named encode_to type had no method owner");
        const lookup = self.builder.lookupMethodTargetByName(owner, "encode_to") orelse
            Common.invariant("checked method registry is missing custom encode_to target");
        return switch (lookup.target.kind) {
            .generated_structural_encoder => null,
            .generated_structural_parser => Common.invariant("encode_to lookup resolved to generated parser_for target"),
            .procedure,
            .local_proc,
            => lookup,
        };
    }

    fn tryJsonInfo(self: *BodyContext, ty: Type.TypeId) ?TryJsonInfo {
        const backing_ty = self.builder.namedBackingType(ty) orelse return null;
        const ok_tag = self.monoTagByTextOptional(backing_ty, "Ok") orelse return null;
        const err_tag = self.monoTagByTextOptional(backing_ty, "Err") orelse return null;
        const ok_payloads = self.builder.program.types.span(ok_tag.payloads);
        const err_payloads = self.builder.program.types.span(err_tag.payloads);
        if (ok_payloads.len != 1 or err_payloads.len != 1) return null;
        const err_info = self.jsonTryErrInfo(err_payloads[0]) orelse return null;
        return .{
            .backing_ty = backing_ty,
            .ok_payload_ty = ok_payloads[0],
            .err_ty = err_payloads[0],
            .has_missing = err_info.has_missing,
            .has_null = err_info.has_null,
        };
    }

    fn jsonTryErrInfo(self: *BodyContext, err_ty: Type.TypeId) ?JsonTryErrInfo {
        const tags = switch (self.builder.shapeContent(err_ty)) {
            .tag_union => |span| self.builder.program.types.tagSpan(span),
            else => return null,
        };
        if (tags.len == 0) return null;

        var has_missing = false;
        var has_null = false;
        for (tags) |tag| {
            if (self.builder.program.types.span(tag.payloads).len != 0) return null;
            const text = self.builder.program.names.tagLabelText(tag.name);
            if (Ident.textEql(text, "Missing")) {
                has_missing = true;
            } else if (Ident.textEql(text, "Null")) {
                has_null = true;
            } else {
                return null;
            }
        }
        return .{ .has_missing = has_missing, .has_null = has_null };
    }

    fn tagUnionValueWithoutPayload(self: *BodyContext, ty: Type.TypeId, tag_text: []const u8) Allocator.Error!DraftExprId {
        const tag = self.monoTagByText(ty, tag_text);
        if (self.builder.program.types.span(tag.payloads).len != 0) Common.invariant("JSON Try marker tag unexpectedly had payloads");
        return try self.addExpr(.{
            .ty = ty,
            .data = .{ .tag = .{
                .name = tag.name,
                .payloads = .empty(),
            } },
        });
    }

    fn finishOptionalRecordFieldFromPresencePayload(
        self: *BodyContext,
        next_body: DraftExprId,
        ret_ty: Type.TypeId,
        record_slots: ParseRecordSlots,
        field: Type.Field,
        field_index: usize,
        field_local: DraftLocalId,
        rest_local: DraftLocalId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        renamed_field_local: DraftLocalId,
    ) Allocator.Error!DraftExprId {
        const field_ty = field.ty;
        const optional_info = self.optionalParseTryInfo(field_ty) orelse
            Common.invariant("optional record finish requested for a non-optional Try field");
        const payload_local = record_slots.payload_locals[field_index];
        const payload_ty = record_slots.payload_tys[field_index];
        if (!self.sameType(payload_ty, field_ty)) {
            Common.invariant("generated optional record payload type differed from field type");
        }
        if (!self.sameType(try self.localType(field_local), field_ty)) {
            Common.invariant("record finish field local type differed from optional field type");
        }

        const renamed_field_ty = try self.localType(renamed_field_local);
        if (!self.typeHasBuiltinOwner(renamed_field_ty, .str)) Common.invariant("record parser renamed field local was not Str");
        const renamed_field_expr = try self.localExpr(renamed_field_local, renamed_field_ty);
        const missing_error = try self.missingOptionalFieldError(encoding_expr, renamed_field_expr, rest_local, encoding_ty, state_ty, optional_info.err_ty);
        const missing_field = try self.tryErr(field_ty, missing_error);
        const present_field = try self.localExpr(payload_local, payload_ty);
        const presence_word = recordPresenceWordIndex(field_index);
        const is_present_expr = try self.localExpr(record_slots.presence_locals[presence_word], record_slots.presence_tys[presence_word]);
        const field_value = try self.addExpr(.{ .ty = field_ty, .data = .{ .if_initialized_payload = .{
            .cond = is_present_expr,
            .cond_mask = recordPresenceMask(field_index),
            .payload = payload_local,
            .uninitialized_is_cold = false,
            .initialized = present_field,
            .uninitialized = missing_field,
        } } });
        return try self.wrapLet(field_local, field_ty, field_value, next_body, ret_ty);
    }

    fn parseRecordFieldFromPresencePayload(
        self: *BodyContext,
        is_present_expr: DraftExprId,
        is_present_mask: u64,
        payload_local: DraftLocalId,
        payload_ty: Type.TypeId,
        field: Type.Field,
        field_try_ty: Type.TypeId,
        rest_local: DraftLocalId,
        encoding_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        renamed_field_local: DraftLocalId,
    ) Allocator.Error!DraftExprId {
        const field_ty = field.ty;
        const field_try_info = self.tryInfo(field_try_ty);
        if (!self.sameType(field_try_info.ok_ty, field_ty)) Common.invariant("structural parser field Try Ok type differed from field type");
        const renamed_field_ty = try self.localType(renamed_field_local);
        if (!self.typeHasBuiltinOwner(renamed_field_ty, .str)) Common.invariant("record parser renamed field local was not Str");
        const renamed_field_expr = try self.localExpr(renamed_field_local, renamed_field_ty);

        if (!self.sameType(payload_ty, field_ty)) {
            Common.invariant("generated record parse payload type differed from parsed field type");
        }
        const present_body = try self.tryOk(field_try_ty, try self.localExpr(payload_local, payload_ty));

        const absent_body = if (self.typeHasBuiltinOwner(field_ty, .str)) blk: {
            break :blk try self.tryErr(field_try_ty, try self.missingRecordFieldError(encoding_expr, renamed_field_expr, rest_local, encoding_ty, state_ty, field_try_info.err_ty));
        } else if (self.optionalParseTryInfo(field_ty)) |info| blk: {
            const missing_error = try self.missingOptionalFieldError(encoding_expr, renamed_field_expr, rest_local, encoding_ty, state_ty, info.err_ty);
            const missing_field = try self.tryErr(field_ty, missing_error);
            break :blk try self.tryOk(field_try_ty, missing_field);
        } else try self.tryErr(field_try_ty, try self.missingRecordFieldError(encoding_expr, renamed_field_expr, rest_local, encoding_ty, state_ty, field_try_info.err_ty));

        return try self.addExpr(.{ .ty = field_try_ty, .data = .{ .if_initialized_payload = .{
            .cond = is_present_expr,
            .cond_mask = is_present_mask,
            .payload = payload_local,
            .uninitialized_is_cold = true,
            .initialized = present_body,
            .uninitialized = absent_body,
        } } });
    }

    fn missingRecordFieldError(
        self: *BodyContext,
        encoding_expr: DraftExprId,
        field_name_expr: DraftExprId,
        rest_local: DraftLocalId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        err_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const str_ty = try self.builder.primitiveType(.str);
        const lookup = self.methodLookupForTypeName(encoding_ty, "missing_record_field");
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &.{ encoding_ty, str_ty, state_ty }, err_ty);
        const missing_fn = self.builder.functionShape(callable_mono_ty, "missing_record_field target method was not a function");
        const arg_tys = self.builder.program.types.span(missing_fn.args);
        if (arg_tys.len != 3) Common.invariant("missing_record_field target method had an unexpected arity");
        if (!self.sameType(arg_tys[0], encoding_ty)) Common.invariant("missing_record_field encoding type differed from record encoding type");
        if (!self.sameType(arg_tys[1], str_ty)) Common.invariant("missing_record_field name type differed from Str");
        if (!self.sameType(arg_tys[2], state_ty)) Common.invariant("missing_record_field state type differed from record rest state type");
        if (!self.sameType(missing_fn.ret, err_ty)) Common.invariant("missing_record_field return type differed from parse error type");

        const args = [_]DraftExprId{
            encoding_expr,
            field_name_expr,
            try self.localExpr(rest_local, state_ty),
        };
        return try self.addExpr(.{
            .ty = err_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(&args),
                .is_cold = true,
            } },
        });
    }

    fn invalidValueParseResult(
        self: *BodyContext,
        encoding_expr: DraftExprId,
        state_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const ret_info = self.tryInfo(ret_ty);
        return try self.tryErr(
            ret_ty,
            try self.invalidValueError(encoding_expr, state_expr, encoding_ty, state_ty, ret_info.err_ty),
        );
    }

    fn invalidValueError(
        self: *BodyContext,
        encoding_expr: DraftExprId,
        state_expr: DraftExprId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        err_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const lookup = self.methodLookupForTypeName(encoding_ty, "invalid_value");
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &.{ encoding_ty, state_ty }, err_ty);
        const invalid_fn = self.builder.functionShape(callable_mono_ty, "invalid_value target method was not a function");
        const arg_tys = self.builder.program.types.span(invalid_fn.args);
        if (arg_tys.len != 2) Common.invariant("invalid_value target method had an unexpected arity");
        if (!self.sameType(arg_tys[0], encoding_ty)) Common.invariant("invalid_value encoding type differed from parser encoding type");
        if (!self.sameType(arg_tys[1], state_ty)) Common.invariant("invalid_value state type differed from parser state type");
        if (!self.sameType(invalid_fn.ret, err_ty)) Common.invariant("invalid_value return type differed from parse error type");

        return try self.addExpr(.{
            .ty = err_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(&[_]DraftExprId{ encoding_expr, state_expr }),
                .is_cold = true,
            } },
        });
    }

    fn missingOptionalFieldError(
        self: *BodyContext,
        encoding_expr: DraftExprId,
        field_name_expr: DraftExprId,
        rest_local: DraftLocalId,
        encoding_ty: Type.TypeId,
        state_ty: Type.TypeId,
        err_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const str_ty = try self.builder.primitiveType(.str);
        const lookup = self.methodLookupForTypeName(encoding_ty, "missing_optional_field");
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &.{ encoding_ty, str_ty, state_ty }, err_ty);
        const missing_fn = self.builder.functionShape(callable_mono_ty, "missing_optional_field target method was not a function");
        const arg_tys = self.builder.program.types.span(missing_fn.args);
        if (arg_tys.len != 3) Common.invariant("missing_optional_field target method had an unexpected arity");
        if (!self.sameType(arg_tys[0], encoding_ty)) Common.invariant("missing_optional_field encoding type differed from record encoding type");
        if (!self.sameType(arg_tys[1], str_ty)) Common.invariant("missing_optional_field name type differed from Str");
        if (!self.sameType(arg_tys[2], state_ty)) Common.invariant("missing_optional_field state type differed from record rest state type");
        if (!self.sameType(missing_fn.ret, err_ty)) Common.invariant("missing_optional_field return type differed from optional field error type");

        const args = [_]DraftExprId{
            encoding_expr,
            field_name_expr,
            try self.localExpr(rest_local, state_ty),
        };
        return try self.addExpr(.{
            .ty = err_ty,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
                .args = try self.addExprSpan(&args),
            } },
        });
    }

    fn lowerDirectStructuralEq(
        self: *BodyContext,
        checked_ret_ty: checked.CheckedTypeId,
        eq: anytype,
    ) Allocator.Error!DraftExprId {
        const ret_ty = try self.lowerTypeView(checked_ret_ty);
        return try self.lowerDirectStructuralEqAtType(eq, ret_ty);
    }

    fn lowerDirectStructuralEqAtType(
        self: *BodyContext,
        eq: anytype,
        ret_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const operand_ty = try self.structuralEqualityOperandType(eq);
        const lhs = try self.lowerExprAtType(eq.lhs, operand_ty);
        const rhs = try self.lowerExprAtType(eq.rhs, operand_ty);
        var result = try self.lowerEqualityExpr(operand_ty, lhs, rhs, "is_eq", ret_ty);
        if (eq.negated) {
            result = try self.lowLevelExpr(.bool_not, &.{result}, ret_ty);
        }
        return result;
    }

    fn structuralEqualityOperandType(self: *BodyContext, eq: anytype) Allocator.Error!Type.TypeId {
        const lhs_checked_ty = self.view.bodies.expr(eq.lhs).ty;
        const rhs_checked_ty = self.view.bodies.expr(eq.rhs).ty;
        const conflict_message = "checked structural equality operand type conflicted with an existing Monotype constraint";

        try self.constrainCheckedTypeRelations(lhs_checked_ty, self, rhs_checked_ty);

        if (try self.structuralEqualityExprResultType(eq.lhs, null)) |lhs_ty| {
            return try self.constrainStructuralEqualityOperandType(lhs_ty, eq.rhs, rhs_checked_ty, conflict_message);
        }
        if (try self.structuralEqualityExprResultType(eq.rhs, null)) |rhs_ty| {
            return try self.constrainStructuralEqualityOperandType(rhs_ty, eq.lhs, lhs_checked_ty, conflict_message);
        }

        return try self.lowerTypeView(lhs_checked_ty);
    }

    /// Resolves the Monotype an equality operand evaluates to, when that operand is a
    /// result-producing expression (call, dispatch, lookup, field access). The shared
    /// equality operand type is taken from this result so an open tag literal on the other
    /// side cannot narrow it. Returns null for any other expression shape (e.g. a tag
    /// literal): the caller then falls through to the concrete-shape ladder in
    /// structuralEqualityOperandType, so this must not fall back to lowerType itself.
    fn structuralEqualityExprResultType(
        self: *BodyContext,
        expr_id: checked.CheckedExprId,
        expected_ty: ?Type.TypeId,
    ) Allocator.Error!?Type.TypeId {
        const expr = self.view.bodies.expr(expr_id);
        return switch (expr.data) {
            .call => |call| try self.callResultMonoType(expr.ty, call, expected_ty),
            .dispatch_call => |plan| try self.dispatchResultMonoType(expr.ty, plan, expected_ty),
            .interpolation => |interpolation| try self.dispatchResultMonoType(expr.ty, interpolation.plan, expected_ty),
            .type_dispatch_call => |plan| try self.dispatchResultMonoType(expr.ty, plan, expected_ty),
            .method_eq => |plan| try self.dispatchResultMonoType(expr.ty, plan, expected_ty),
            .lookup_local => |lookup| try self.lookupExprMonoType(expr.ty, lookup.resolved),
            .lookup_external => |resolved| try self.lookupExprMonoType(expr.ty, resolved),
            .lookup_required => |resolved| try self.lookupExprMonoType(expr.ty, resolved),
            .field_access => |field| blk: {
                if (expected_ty) |ty| {
                    try self.constrainTypeToMono(expr.ty, ty);
                    break :blk ty;
                }
                break :blk try self.fieldAccessMonoType(field.receiver, field.field_name);
            },
            else => null,
        };
    }

    fn constrainStructuralEqualityOperandType(
        self: *BodyContext,
        operand_ty: Type.TypeId,
        other_expr_id: checked.CheckedExprId,
        other_checked_ty: checked.CheckedTypeId,
        comptime conflict_message: []const u8,
    ) Allocator.Error!Type.TypeId {
        try self.constrainTypeToMono(other_checked_ty, operand_ty);
        if (try self.structuralEqualityExprResultType(other_expr_id, operand_ty)) |other_ty| {
            if (!self.sameType(operand_ty, other_ty)) Common.invariant(conflict_message);
        }
        return operand_ty;
    }

    /// Whether `shape` is a type the structural-derivation ladders (is_eq /
    /// to_hash) expand a layer at a time, guarding recursion through an
    /// expansion stack. Aggregates and transparent nominals expand; scalars,
    /// owned wrappers (List/Box), and opaque nominals bottom out instead.
    fn structurallyExpands(shape: Type.Content) bool {
        return switch (shape) {
            .record, .tuple, .tag_union => true,
            .named => |named| named.backing != null,
            else => false,
        };
    }

    fn lowerEqualityExpr(
        self: *BodyContext,
        ty: Type.TypeId,
        lhs: DraftExprId,
        rhs: DraftExprId,
        method_name: []const u8,
        bool_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        return try self.lowerDerivation(EqDeriver, ty, .{ .lhs = lhs, .rhs = rhs }, .{
            .method_name = method_name,
            .result_ty = bool_ty,
        });
    }

    /// Hash `value` (of `value_ty`) into `hasher`, producing a new Hasher of
    /// `hasher_ty`. The threading is "innermost first": each component feeds the
    /// hasher accumulated so far.
    fn lowerHashExpr(
        self: *BodyContext,
        value_ty: Type.TypeId,
        value: DraftExprId,
        hasher: DraftExprId,
        hasher_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        return try self.lowerDerivation(HashDeriver, value_ty, .{ .value = value, .hasher = hasher }, .{
            .method_name = "to_hash",
            .result_ty = hasher_ty,
        });
    }

    // Generic structural-derivation driver.
    //
    // is_eq and to_hash share one recursive ladder: walk a type one layer at a
    // time, decomposing aggregates (records/tuples/tag unions) and transparent
    // nominals, dispatching owned types (List) to their real method, and
    // emitting a leaf node (`structural_eq` / `structural_hash`) for scalars,
    // opaque nominals, and other inline-handled leaves. Recursion is broken by
    // an expansion stack plus a memoized generated helper def.
    //
    // The per-derivation specifics are supplied by a comptime `Deriver` type
    // (`EqDeriver` / `HashDeriver`). A Deriver provides:
    //   - `Operand`: the operands threaded into one derivation step (equality
    //     holds two `DraftExprId`; hashing holds the value plus the running
    //     hasher accumulator).
    //   - the expansion-stack and memoized-def-cache accessors plus the helper
    //     fn type, so recursion breaks identically for both.
    //   - `leaf`: emit the leaf node for inline-handled shapes.
    //   - `componentForField` / `componentForTuple`: build a component's
    //     operands from the aggregate operands and the running fold state.
    //   - `combineSeed` / `combine` plus `forward`: fold the per-component
    //     results (equality conjoins component bools with AND; hashing threads
    //     the accumulator left to right).
    //   - `ownedCall` / `named` / `tagUnion`: the shapes whose decomposition
    //     differs structurally between the two derivations.
    //
    // A `DerivationCtx` carries the runtime parameters shared by every step:
    // the derivation's result type (Bool / Hasher) and the method name.

    const DerivationCtx = struct {
        method_name: []const u8,
        result_ty: Type.TypeId,
    };

    fn lowerDerivation(
        self: *BodyContext,
        comptime D: type,
        ty: Type.TypeId,
        operand: D.Operand,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftExprId {
        const shape = self.builder.program.types.get(ty);
        const expands_structurally = structurallyExpands(shape);
        var remove_active_expansion = false;
        const stack = D.expansionStack(self);
        defer if (remove_active_expansion) {
            _ = stack.remove(ty);
        };
        if (expands_structurally) {
            if (stack.contains(ty)) {
                return try self.derivationCall(D, ty, operand, ctx);
            }
            try stack.put(ty, {});
            remove_active_expansion = true;
        }

        return switch (shape) {
            .list => try D.ownedCall(self, ty, operand, ctx),
            .record => |fields| try self.derivationRecord(D, self.builder.program.types.fieldSpan(fields), operand, ctx),
            .tuple => |items| try self.derivationTuple(D, self.builder.program.types.span(items), operand, ctx),
            .tag_union => |tags| try D.tagUnion(self, ty, tags, operand, ctx),
            .named => |named| if (named.backing) |backing|
                try D.named(self, ty, backing.ty, operand, ctx)
            else
                try D.leaf(self, operand, ctx),
            .primitive,
            .zst,
            .func,
            .erased,
            .box,
            => try D.leaf(self, operand, ctx),
        };
    }

    /// Emit a call to the memoized recursive helper for `ty`, generating its def
    /// on first request.
    fn derivationCall(
        self: *BodyContext,
        comptime D: type,
        ty: Type.TypeId,
        operand: D.Operand,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftExprId {
        const def_id = try self.derivationDefForType(D, ty, ctx);
        const callee = try self.addExprWithTypeCell(
            try D.fnType(self, ty, ctx.result_ty),
            .{ .def_ref = .{ .draft = def_id } },
        );
        const args = D.callArgs(operand);
        return try self.addExpr(.{
            .ty = ctx.result_ty,
            .data = .{ .call_value = .{
                .callee = callee,
                .args = try self.addExprSpan(&args),
            } },
        });
    }

    /// Dispatch an owned (non-structural) type to its real derived method,
    /// shared by every derivation. The argument types and the per-derivation
    /// invariant wording come from the comptime `Deriver`; the operand-to-args
    /// mapping reuses `D.callArgs`.
    fn derivationOwnedCall(
        self: *BodyContext,
        comptime D: type,
        ty: Type.TypeId,
        operand: D.Operand,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftExprId {
        const owner = methodOwnerFromType(&self.builder.program.types, ty) orelse
            Common.invariant(D.owned_missing_owner_msg);
        const lookup = self.builder.lookupMethodTargetByName(owner, ctx.method_name) orelse
            Common.invariant(D.owned_missing_target_msg);

        const arg_tys = D.ownedArgTypes(ty, ctx.result_ty);
        const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &arg_tys, ctx.result_ty);
        const args = D.callArgs(operand);
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .call_proc = .{
            .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, callable_mono_ty))),
            .args = try self.addExprSpan(&args),
        } } });
    }

    fn derivationDefForType(
        self: *BodyContext,
        comptime D: type,
        value_ty: Type.TypeId,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftDefId {
        const cache = D.defCache(self);
        const address = D.defAddress(value_ty, ctx.result_ty);
        if (cache.get(address)) |entry| return entry.id();

        const def_id = try self.draft.reserveDef();
        try cache.put(address, .{ .reserved = def_id });

        // A helper takes two args: the value (`value_ty`) and a second operand
        // whose type is derivation-specific (the other equality operand at
        // `value_ty`, or the running hasher at `result_ty`).
        const second_ty = D.helperSecondArgType(value_ty, ctx.result_ty);
        const self_local = try self.addLocal(self.builder.symbols.fresh(), value_ty);
        const aux_local = try self.addLocal(self.builder.symbols.fresh(), second_ty);
        const self_expr = try self.localExpr(self_local, value_ty);
        const aux_expr = try self.localExpr(aux_local, second_ty);
        const operand = D.helperOperand(self_expr, aux_expr);

        // The helper body is the structural expansion for this type. Temporarily
        // remove the caller's active mark so the body expands exactly one layer
        // and only recursive edges inside that layer call back to the reserved
        // helper.
        const stack = D.expansionStack(self);
        if (!stack.remove(value_ty)) {
            Common.invariant("recursive structural derivation helper requested outside an active expansion");
        }
        defer stack.putAssumeCapacity(value_ty, {});

        const body = try self.lowerDerivation(D, value_ty, operand, ctx);
        const args = try self.addTypedLocalSpan(&.{
            .{ .local = self_local, .ty = value_ty },
            .{ .local = aux_local, .ty = second_ty },
        });
        self.draft.setDef(def_id, .{
            .symbol = self.builder.symbols.fresh(),
            .fn_def = null,
            .args = args,
            .body = .{ .roc = body },
            .ret = try self.draftTypeCell(ctx.result_ty),
        });
        try cache.put(address, .{ .ready = def_id });
        return def_id;
    }

    fn derivationRecord(
        self: *BodyContext,
        comptime D: type,
        fields: []const Type.Field,
        operand: D.Operand,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftExprId {
        // Copy because recursive lowerDerivation may reallocate types.fields, invalidating the slice.
        const fields_copy = try self.allocator.dupe(Type.Field, fields);
        defer self.allocator.free(fields_copy);
        var state = try D.combineSeed(self, operand, ctx);
        var i: usize = 0;
        while (i < fields_copy.len) : (i += 1) {
            const field = fields_copy[if (D.forward) i else fields_copy.len - 1 - i];
            const component = try D.componentForField(self, operand, state, field);
            const result = try self.lowerDerivation(D, field.ty, component, ctx);
            state = try D.combine(self, state, result, ctx);
        }
        return state;
    }

    fn derivationTuple(
        self: *BodyContext,
        comptime D: type,
        items: []const Type.TypeId,
        operand: D.Operand,
        ctx: DerivationCtx,
    ) Allocator.Error!DraftExprId {
        // Copy because recursive lowerDerivation may reallocate types.spans, invalidating the slice.
        const items_copy = try self.allocator.dupe(Type.TypeId, items);
        defer self.allocator.free(items_copy);
        var state = try D.combineSeed(self, operand, ctx);
        var i: usize = 0;
        while (i < items_copy.len) : (i += 1) {
            const index = if (D.forward) i else items_copy.len - 1 - i;
            const item_ty = items_copy[index];
            const component = try D.componentForTuple(self, operand, state, item_ty, index);
            const result = try self.lowerDerivation(D, item_ty, component, ctx);
            state = try D.combine(self, state, result, ctx);
        }
        return state;
    }

    fn boolLiteral(self: *BodyContext, value: bool, bool_ty: Type.TypeId) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const lhs = try self.intLiteralExpr(0, u64_ty);
        const rhs = try self.intLiteralExpr(if (value) 0 else 1, u64_ty);
        return try self.lowLevelExpr(.num_is_eq, &.{ lhs, rhs }, bool_ty);
    }

    fn lowerDirectStructuralHash(
        self: *BodyContext,
        checked_ret_ty: checked.CheckedTypeId,
        h: anytype,
    ) Allocator.Error!DraftExprId {
        const ret_ty = try self.lowerTypeView(checked_ret_ty);
        return try self.lowerDirectStructuralHashAtType(h, ret_ty);
    }

    fn lowerDirectStructuralHashAtType(
        self: *BodyContext,
        h: anytype,
        hasher_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const value_ty = try self.lowerExprType(h.value);
        const value = try self.lowerExprAtType(h.value, value_ty);
        const hasher = try self.lowerExprAtType(h.hasher, hasher_ty);
        return try self.lowerHashExpr(value_ty, value, hasher, hasher_ty);
    }

    /// Emit `Hasher.write_u64(hasher, value)` as a low-level operation.
    fn hasherWriteU64(
        self: *BodyContext,
        hasher: DraftExprId,
        value: u64,
        hasher_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const value_expr = try self.intLiteralExpr(value, u64_ty);
        return try self.lowLevelExpr(.hasher_write_u64, &.{ hasher, value_expr }, hasher_ty);
    }

    const MatchOutput = union(enum) {
        value: Type.TypeId,
        state_result: struct {
            result_ty: Type.TypeId,
            state_ty: Type.TypeId,
            merge_binders: []const MergeBinder,
        },
        state_only: struct {
            state_ty: Type.TypeId,
            merge_binders: []const MergeBinder,
        },
    };

    fn matchOutputType(_: *BodyContext, output: MatchOutput) Type.TypeId {
        return switch (output) {
            .value => |ty| ty,
            .state_result => |state| state.state_ty,
            .state_only => |state| state.state_ty,
        };
    }

    fn lowerMatchBranchBody(
        self: *BodyContext,
        body: checked.CheckedExprId,
        output: MatchOutput,
    ) Allocator.Error!DraftExprId {
        return switch (output) {
            .value => |result_ty| try self.lowerBranchValueAtType(body, result_ty),
            .state_result => |state| try self.lowerBodyThenStateResult(
                body,
                state.result_ty,
                state.state_ty,
                state.merge_binders,
            ),
            .state_only => |state| try self.lowerBodyThenStateOnly(
                body,
                state.state_ty,
                state.merge_binders,
            ),
        };
    }

    fn lowerBranchValueAtType(
        self: *BodyContext,
        body: checked.CheckedExprId,
        result_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        if (self.checkedExprDivergesInLoweredRuntime(body)) {
            return try self.lowerDivergentExprAtType(body, result_ty);
        }
        return try self.lowerExprAtType(body, result_ty);
    }

    fn lowerMatchExpr(self: *BodyContext, expr_id: checked.CheckedExprId, match: anytype, result_ty: Type.TypeId) Allocator.Error!DraftExprId {
        const comptime_site = try self.matchComptimeSite(expr_id, match);
        const merge_binders = try self.stateMergeBinders(expr_id);
        defer self.allocator.free(merge_binders);
        if (merge_binders.len == 0) {
            return try self.lowerMatchExprWithOutput(match, .{ .value = result_ty }, comptime_site);
        }

        const state_ty = try self.stateResultType(merge_binders, result_ty);
        const state_expr = try self.lowerMatchExprWithOutput(match, .{ .state_result = .{
            .result_ty = result_ty,
            .state_ty = state_ty,
            .merge_binders = merge_binders,
        } }, comptime_site);

        const pattern_items = try self.allocator.alloc(DraftPatId, merge_binders.len + 1);
        defer self.allocator.free(pattern_items);
        for (merge_binders, 0..) |merge, i| {
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), merge.ty, merge.binder);
            try self.bindLocalName(local, merge.binder);
            try self.binders.put(merge.binder, local);
            pattern_items[i] = try self.addPat(.{ .ty = merge.ty, .data = .{ .bind = local } });
        }

        const result_local = try self.addLocal(self.builder.symbols.fresh(), result_ty);
        pattern_items[merge_binders.len] = try self.addPat(.{ .ty = result_ty, .data = .{ .bind = result_local } });
        const bind_pat = try self.addPat(.{ .ty = state_ty, .data = .{ .tuple = try self.addPatSpan(pattern_items) } });
        const rest = try self.localExpr(result_local, result_ty);

        return try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
            .bind = bind_pat,
            .value = state_expr,
            .rest = rest,
        } } });
    }

    fn lowerMatchExprWithOutput(
        self: *BodyContext,
        match: anytype,
        output: MatchOutput,
        comptime_site: ?DraftComptimeSiteId,
    ) Allocator.Error!DraftExprId {
        const output_ty = self.matchOutputType(output);
        return try self.addExpr(.{
            .ty = output_ty,
            .data = try self.lowerMatch(match, output, comptime_site),
        });
    }

    fn patternNeedsExplicitBinding(self: *BodyContext, pattern_id: checked.CheckedPatternId) bool {
        const pattern = self.view.bodies.pattern(pattern_id);
        return switch (pattern.data) {
            .list => true,
            .record_destructure => |destructs| self.recordDestructsNeedExplicitRest(destructs),
            .assign,
            .as,
            .applied_tag,
            .nominal,
            .tuple,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .str_interpolation,
            .underscore,
            .pending,
            .runtime_error,
            => false,
        };
    }

    fn patternCanMiss(self: *BodyContext, pattern_id: checked.CheckedPatternId) bool {
        const pattern = self.view.bodies.pattern(pattern_id);
        return switch (pattern.data) {
            .assign,
            .underscore,
            => false,
            .as => |as| self.patternCanMiss(as.pattern),
            .nominal => |nominal| self.patternCanMiss(nominal.backing_pattern),
            .tuple => |items| blk: {
                for (items) |child| {
                    if (self.patternCanMiss(child)) break :blk true;
                }
                break :blk false;
            },
            .record_destructure => |destructs| blk: {
                for (destructs) |destruct| {
                    const child = switch (destruct.kind) {
                        .required, .sub_pattern, .rest => |child_pattern| child_pattern,
                    };
                    if (self.patternCanMiss(child)) break :blk true;
                }
                break :blk false;
            },
            .applied_tag,
            .list,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .str_interpolation,
            => true,
            .pending,
            .runtime_error,
            => false,
        };
    }

    fn recordDestructsNeedExplicitRest(self: *BodyContext, destructs: []const checked.CheckedRecordDestruct) bool {
        for (destructs) |destruct| {
            switch (destruct.kind) {
                .rest => |child| if (!self.patternIsIgnored(child)) return true,
                .required, .sub_pattern => {},
            }
        }
        return false;
    }

    fn listPatternCondition(
        self: *BodyContext,
        scrutinee: DraftExprId,
        list: anytype,
    ) Allocator.Error!DraftExprId {
        const u64_ty = try self.builder.primitiveType(.u64);
        const bool_ty = try self.builder.primitiveType(.bool);
        const len = try self.lowLevelExpr(.list_len, &.{scrutinee}, u64_ty);
        const required = try self.intLiteralExpr(list.patterns.len, u64_ty);
        const op: can.CIR.Expr.LowLevel = if (list.rest == null) .num_is_eq else .num_is_gte;
        return try self.lowLevelExpr(op, &.{ len, required }, bool_ty);
    }

    fn applyListCheck(
        self: *BodyContext,
        scrutinee: DraftExprId,
        scrutinee_ty: Type.TypeId,
        list: anytype,
        body: DraftExprId,
        fallback: DraftExprId,
        output_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const elem_ty = self.constListElemType(scrutinee_ty);
        const u64_ty = try self.builder.primitiveType(.u64);
        const needs_len = if (list.rest) |rest| rest.index < list.patterns.len or rest.pattern != null else false;
        const len = if (needs_len) try self.lowLevelExpr(.list_len, &.{scrutinee}, u64_ty) else null;

        const values = try self.allocator.alloc(DraftExprId, list.patterns.len);
        defer self.allocator.free(values);
        const patterns = try self.allocator.alloc(DraftPatId, list.patterns.len);
        defer self.allocator.free(patterns);
        const sub_checks_per_elem = try self.allocator.alloc(std.ArrayList(CollectedListPattern), list.patterns.len);
        defer {
            for (sub_checks_per_elem) |*sub| sub.deinit(self.allocator);
            self.allocator.free(sub_checks_per_elem);
        }
        for (sub_checks_per_elem) |*sub| sub.* = std.ArrayList(CollectedListPattern).empty;
        const literal_guards_per_elem = try self.allocator.alloc([]PatternLiteralGuard, list.patterns.len);
        defer {
            for (literal_guards_per_elem) |guards| self.allocator.free(guards);
            self.allocator.free(literal_guards_per_elem);
        }
        for (literal_guards_per_elem) |*guards| guards.* = &.{};

        for (list.patterns, 0..) |pattern_id, index| {
            const item_index = try self.listPatternItemIndex(index, list.patterns.len, list.rest, len, u64_ty);
            values[index] = try self.lowLevelExpr(.list_get_unsafe, &.{ scrutinee, item_index }, elem_ty);
            const guards_start = self.pattern_literal_guards.items.len;
            patterns[index] = try self.lowerPatternAtTypeCollectingLists(pattern_id, elem_ty, &sub_checks_per_elem[index]);
            literal_guards_per_elem[index] = try self.drainPatternLiteralGuards(guards_start);
        }

        var rest_pat: ?DraftPatId = null;
        var rest_value: ?DraftExprId = null;
        var rest_sub_checks = std.ArrayList(CollectedListPattern).empty;
        defer rest_sub_checks.deinit(self.allocator);
        var rest_literal_guards: []PatternLiteralGuard = &.{};
        defer self.allocator.free(rest_literal_guards);
        if (list.rest) |rest| {
            if (rest.pattern) |rest_pattern| {
                const list_len = len orelse try self.lowLevelExpr(.list_len, &.{scrutinee}, u64_ty);
                const fixed_count = try self.intLiteralExpr(list.patterns.len, u64_ty);
                const rest_len = try self.lowLevelExpr(.num_minus, &.{ list_len, fixed_count }, u64_ty);
                const rest_start = try self.intLiteralExpr(rest.index, u64_ty);
                const range = try self.sublistRangeExpr(rest_start, rest_len, u64_ty);
                rest_value = try self.lowLevelExpr(.list_sublist, &.{ scrutinee, range }, scrutinee_ty);
                const guards_start = self.pattern_literal_guards.items.len;
                rest_pat = try self.lowerPatternAtTypeCollectingLists(rest_pattern, scrutinee_ty, &rest_sub_checks);
                rest_literal_guards = try self.drainPatternLiteralGuards(guards_start);
            }
        }

        var success = body;

        var index = patterns.len;
        while (index > 0) {
            index -= 1;
            var elem_success = success;
            var sub_index = sub_checks_per_elem[index].items.len;
            while (sub_index > 0) {
                sub_index -= 1;
                const sub = sub_checks_per_elem[index].items[sub_index];
                const sub_scrut = try self.localExpr(sub.local, sub.ty);
                elem_success = try self.applyListCheck(sub_scrut, sub.ty, sub, elem_success, fallback, output_ty);
            }
            elem_success = try self.applyPatternLiteralGuards(literal_guards_per_elem[index], elem_success, fallback, output_ty);
            success = try self.wrapPatternMatch(values[index], elem_ty, patterns[index], elem_success, fallback, output_ty);
        }

        if (rest_pat) |pat| {
            var rest_success = success;
            var sub_index = rest_sub_checks.items.len;
            while (sub_index > 0) {
                sub_index -= 1;
                const sub = rest_sub_checks.items[sub_index];
                const sub_scrut = try self.localExpr(sub.local, sub.ty);
                rest_success = try self.applyListCheck(sub_scrut, sub.ty, sub, rest_success, fallback, output_ty);
            }
            rest_success = try self.applyPatternLiteralGuards(rest_literal_guards, rest_success, fallback, output_ty);
            success = try self.wrapPatternMatch(
                rest_value orelse Common.invariant("list rest pattern had no lowered rest value"),
                scrutinee_ty,
                pat,
                rest_success,
                fallback,
                output_ty,
            );
        }

        const cond = try self.listPatternCondition(scrutinee, list);
        return try self.ifExpr(cond, success, fallback, output_ty);
    }

    fn preRegisterPatternBinders(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        ty: Type.TypeId,
    ) Allocator.Error!void {
        const pattern = self.view.bodies.pattern(pattern_id);
        switch (pattern.data) {
            .assign => |binder| {
                if (self.binders.get(binder) == null) {
                    const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), ty, binder);
                    try self.bindLocalName(local, binder);
                    try self.binders.put(binder, local);
                }
            },
            .as => |as| {
                if (self.binders.get(as.binder) == null) {
                    const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), ty, as.binder);
                    try self.bindLocalName(local, as.binder);
                    try self.binders.put(as.binder, local);
                }
                try self.preRegisterPatternBinders(as.pattern, ty);
            },
            .applied_tag => |tag| {
                const name = try self.builder.tagName(self.view, tag.name);
                const payload_tys = self.builder.tagPayloadTypes(ty, name);
                if (tag.args.len != payload_tys.len) Common.invariant("pattern arity differs from concrete checked type");
                for (tag.args, payload_tys) |arg, arg_ty| {
                    try self.preRegisterPatternBinders(arg, arg_ty);
                }
            },
            .nominal => |nominal| {
                try self.preRegisterPatternBinders(nominal.backing_pattern, self.builder.namedBackingType(ty) orelse ty);
            },
            .record_destructure => |destructs| {
                for (destructs) |destruct| {
                    switch (destruct.kind) {
                        .required, .sub_pattern => |child| {
                            const name = try self.builder.recordFieldName(self.view, destruct.label);
                            const child_ty = self.builder.recordFieldType(ty, name);
                            try self.preRegisterPatternBinders(child, child_ty);
                        },
                        .rest => |rest_pattern| {
                            if (!self.patternIsIgnored(rest_pattern)) {
                                Common.invariant("record rest pattern must be lowered to explicit rest-record construction before Monotype output");
                            }
                        },
                    }
                }
            },
            .list => |list| {
                const elem_ty = self.constListElemType(ty);
                for (list.patterns) |child| {
                    try self.preRegisterPatternBinders(child, elem_ty);
                }
                if (list.rest) |rest| {
                    if (rest.pattern) |rest_pattern| {
                        try self.preRegisterPatternBinders(rest_pattern, ty);
                    }
                }
            },
            .tuple => |items| {
                const item_tys = self.builder.tupleItemTypes(ty);
                if (items.len != item_tys.len) Common.invariant("pattern arity differs from concrete checked type");
                for (items, item_tys) |item, item_ty| {
                    try self.preRegisterPatternBinders(item, item_ty);
                }
            },
            .str_interpolation => |str| {
                for (str.steps) |step| {
                    if (step.capture) |capture| {
                        try self.preRegisterPatternBinders(capture, ty);
                    }
                }
            },
            .pending,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .underscore,
            .runtime_error,
            => {},
        }
    }

    fn preRegisterPatternBindersFromCheckedTypes(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
    ) Allocator.Error!void {
        const pattern = self.view.bodies.pattern(pattern_id);
        switch (pattern.data) {
            .assign => |binder| {
                if (self.binders.get(binder) == null) {
                    const local = try self.addLocalWithBinderCell(self.builder.symbols.fresh(), try self.lowerTypeCell(pattern.ty), binder);
                    try self.bindLocalName(local, binder);
                    try self.binders.put(binder, local);
                }
            },
            .as => |as| {
                if (self.binders.get(as.binder) == null) {
                    const local = try self.addLocalWithBinderCell(self.builder.symbols.fresh(), try self.lowerTypeCell(pattern.ty), as.binder);
                    try self.bindLocalName(local, as.binder);
                    try self.binders.put(as.binder, local);
                }
                try self.preRegisterPatternBindersFromCheckedTypes(as.pattern);
            },
            .applied_tag => |tag| {
                for (tag.args) |arg| try self.preRegisterPatternBindersFromCheckedTypes(arg);
            },
            .nominal => |nominal| try self.preRegisterPatternBindersFromCheckedTypes(nominal.backing_pattern),
            .record_destructure => |destructs| {
                for (destructs) |destruct| {
                    switch (destruct.kind) {
                        .required, .sub_pattern => |child| try self.preRegisterPatternBindersFromCheckedTypes(child),
                        .rest => |rest_pattern| {
                            if (!self.patternIsIgnored(rest_pattern)) {
                                Common.invariant("record rest pattern must be lowered to explicit rest-record construction before Monotype output");
                            }
                        },
                    }
                }
            },
            .list => |list| {
                for (list.patterns) |child| try self.preRegisterPatternBindersFromCheckedTypes(child);
                if (list.rest) |rest| {
                    if (rest.pattern) |rest_pattern| try self.preRegisterPatternBindersFromCheckedTypes(rest_pattern);
                }
            },
            .tuple => |items| {
                for (items) |item| try self.preRegisterPatternBindersFromCheckedTypes(item);
            },
            .str_interpolation => |str| {
                for (str.steps) |step| {
                    if (step.capture) |capture| try self.preRegisterPatternBindersFromCheckedTypes(capture);
                }
            },
            .pending,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .underscore,
            .runtime_error,
            => {},
        }
    }

    fn lowerPatternAtTypeCollectingLists(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        ty: Type.TypeId,
        checks_out: *std.ArrayList(CollectedListPattern),
    ) Allocator.Error!DraftPatId {
        const pattern = self.view.bodies.pattern(pattern_id);
        try self.constrainTypeToMono(pattern.ty, ty);
        const data: BodyPatData = switch (pattern.data) {
            .pending,
            .runtime_error,
            => Common.invariant("non-runtime checked pattern reached Monotype lowering"),
            .assign => |binder| blk: {
                const local = if (self.binders.get(binder)) |existing| existing else inner: {
                    const new_local = try self.addLocalWithBinder(self.builder.symbols.fresh(), ty, binder);
                    try self.bindLocalName(new_local, binder);
                    try self.binders.put(binder, new_local);
                    break :inner new_local;
                };
                break :blk .{ .bind = local };
            },
            .as => |as| blk: {
                const local = if (self.binders.get(as.binder)) |existing| existing else inner: {
                    const new_local = try self.addLocalWithBinder(self.builder.symbols.fresh(), ty, as.binder);
                    try self.bindLocalName(new_local, as.binder);
                    try self.binders.put(as.binder, new_local);
                    break :inner new_local;
                };
                break :blk .{ .as = .{
                    .pattern = try self.lowerPatternAtTypeCollectingLists(as.pattern, ty, checks_out),
                    .local = local,
                } };
            },
            .applied_tag => |tag| try self.lowerTagPatternCollectingLists(tag, ty, checks_out),
            .nominal => |nominal| .{ .nominal = try self.lowerPatternAtTypeCollectingLists(nominal.backing_pattern, self.builder.namedBackingType(ty) orelse ty, checks_out) },
            .record_destructure => |destructs| try self.lowerRecordPatternCollectingLists(destructs, ty, checks_out),
            .list => |list| blk: {
                const local = try self.addLocal(self.builder.symbols.fresh(), ty);
                try checks_out.append(self.allocator, .{
                    .local = local,
                    .ty = ty,
                    .patterns = list.patterns,
                    .rest = list.rest,
                });
                break :blk .{ .bind = local };
            },
            .tuple => |items| .{ .tuple = try self.lowerPatternSpanAtTypesCollectingLists(items, self.builder.tupleItemTypes(ty), checks_out) },
            .num_literal => |num| if (num.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                self.lowerNumPattern(num.value, ty),
            .small_dec_literal => |dec| if (dec.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                Common.invariant("small decimal pattern reached Monotype after numeric finalization"),
            .dec_literal => |dec| if (dec.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                .{ .dec_lit = dec.value },
            .frac_f32_literal => |value| .{ .frac_f32_lit = value },
            .frac_f64_literal => |value| .{ .frac_f64_lit = value },
            .str_literal => |str| if (str.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                .{ .str_lit = try self.lowerStringLiteral(str.literal) },
            .str_interpolation => |str| try self.lowerStrPatternCollectingLists(str, ty, checks_out),
            .underscore => .wildcard,
        };
        return try self.addPat(.{ .ty = ty, .data = data });
    }

    fn lowerStrPatternCollectingLists(
        self: *BodyContext,
        str: anytype,
        ty: Type.TypeId,
        checks_out: *std.ArrayList(CollectedListPattern),
    ) Allocator.Error!BodyPatData {
        const steps = try self.allocator.alloc(DraftStrPatternStep, str.steps.len);
        defer self.allocator.free(steps);

        for (str.steps, 0..) |step, i| {
            steps[i] = .{
                .capture = if (step.capture) |capture| try self.lowerPatternAtTypeCollectingLists(capture, ty, checks_out) else null,
                .delimiter = try self.lowerStringLiteral(step.delimiter),
            };
        }

        return .{ .str_pattern = .{
            .prefix = try self.lowerStringLiteral(str.prefix),
            .steps = try self.addStrPatternStepSpan(steps),
            .end = switch (str.end) {
                .exact => .exact,
                .tail => .tail,
            },
        } };
    }

    fn lowerPatternSpanAtTypesCollectingLists(
        self: *BodyContext,
        checked_patterns: []const checked.CheckedPatternId,
        tys: []const Type.TypeId,
        checks_out: *std.ArrayList(CollectedListPattern),
    ) Allocator.Error!DraftSpan(DraftPatId) {
        if (checked_patterns.len != tys.len) Common.invariant("pattern arity differs from concrete checked type");
        const lowered = try self.allocator.alloc(DraftPatId, checked_patterns.len);
        defer self.allocator.free(lowered);
        for (checked_patterns, tys, 0..) |child, child_ty, i| {
            lowered[i] = try self.lowerPatternAtTypeCollectingLists(child, child_ty, checks_out);
        }
        return try self.addPatSpan(lowered);
    }

    fn lowerTagPatternCollectingLists(
        self: *BodyContext,
        tag: anytype,
        ty: Type.TypeId,
        checks_out: *std.ArrayList(CollectedListPattern),
    ) Allocator.Error!BodyPatData {
        const name = try self.builder.tagName(self.view, tag.name);
        return .{ .tag = .{
            .name = name,
            .payloads = try self.lowerPatternSpanAtTypesCollectingLists(tag.args, self.builder.tagPayloadTypes(ty, name), checks_out),
        } };
    }

    fn lowerRecordPatternCollectingLists(
        self: *BodyContext,
        destructs: []const checked.CheckedRecordDestruct,
        ty: Type.TypeId,
        checks_out: *std.ArrayList(CollectedListPattern),
    ) Allocator.Error!BodyPatData {
        var lowered = std.ArrayList(DraftRecordDestruct).empty;
        defer lowered.deinit(self.allocator);
        for (destructs) |destruct| {
            const child = switch (destruct.kind) {
                .required => |pattern| pattern,
                .sub_pattern => |pattern| pattern,
                .rest => |pattern| {
                    if (self.patternIsIgnored(pattern)) continue;
                    Common.invariant("record rest pattern must be lowered to explicit rest-record construction before Monotype output");
                },
            };
            const name = try self.builder.recordFieldName(self.view, destruct.label);
            const child_ty = switch (destruct.kind) {
                .required, .sub_pattern => self.builder.recordFieldType(ty, name),
                .rest => unreachable,
            };
            try lowered.append(self.allocator, .{
                .name = name,
                .pattern = try self.lowerPatternAtTypeCollectingLists(child, child_ty, checks_out),
            });
        }
        return .{ .record = try self.addRecordDestructSpan(lowered.items) };
    }

    fn wrapPatternMatch(
        self: *BodyContext,
        value: DraftExprId,
        value_ty: Type.TypeId,
        pattern: DraftPatId,
        success: DraftExprId,
        miss: DraftExprId,
        result_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const wildcard = try self.addPat(.{ .ty = value_ty, .data = .wildcard });
        const branches = [_]DraftBranch{
            .{ .pat = pattern, .body = success },
            .{ .pat = wildcard, .body = miss },
        };
        return try self.addExpr(.{ .ty = result_ty, .data = .{ .match_ = .{
            .scrutinee = value,
            .branches = try self.addBranchSpan(&branches),
        } } });
    }

    fn lowerBindingContinuation(
        self: *BodyContext,
        continuation: BindingContinuation,
        result_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        return switch (continuation) {
            .expr => |expr| expr,
            .checked_expr => |expr| try self.lowerExprAtType(expr, result_ty),
            .materialized_args => |args| blk: {
                if (args.index >= args.args.len) break :blk try self.lowerExprAtType(args.body, result_ty);
                const arg = args.args[args.index];
                const miss = try self.runtimeCrashExpr(result_ty, "pattern match failed");
                break :blk try self.lowerMaterializedPatternThen(
                    arg.pattern,
                    arg.value,
                    arg.ty,
                    result_ty,
                    .{ .materialized_args = .{
                        .args = args.args,
                        .index = args.index + 1,
                        .body = args.body,
                    } },
                    miss,
                );
            },
            .iterator_body => |body| try self.lowerIteratorBodyThenContinue(
                body.body,
                body.result_ty,
                body.rest_expr,
                body.carries,
            ),
        };
    }

    fn lowerMaterializedPatternValueThen(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        value: DraftExprId,
        value_ty: Type.TypeId,
        result_ty: Type.TypeId,
        continuation: BindingContinuation,
        miss: DraftExprId,
    ) Allocator.Error!DraftExprId {
        if (!self.patternNeedsExplicitBinding(pattern_id)) {
            const pat = try self.lowerPatternAtType(pattern_id, value_ty);
            const rest = try self.lowerBindingContinuation(continuation, result_ty);
            return try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
                .bind = pat,
                .value = value,
                .rest = rest,
            } } });
        }

        const local = try self.addLocal(self.builder.symbols.fresh(), value_ty);
        const local_expr = try self.localExpr(local, value_ty);
        const rest = try self.lowerMaterializedPatternThen(pattern_id, local_expr, value_ty, result_ty, continuation, miss);
        return try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
            .bind = try self.bindPat(local, value_ty),
            .value = value,
            .rest = rest,
        } } });
    }

    fn lowerMaterializedPatternThen(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        value: DraftExprId,
        value_ty: Type.TypeId,
        result_ty: Type.TypeId,
        continuation: BindingContinuation,
        miss: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const pattern = self.view.bodies.pattern(pattern_id);
        return switch (pattern.data) {
            .list => |list| try self.lowerListPatternBindingThen(value, value_ty, list, result_ty, continuation, miss),
            .record_destructure => |destructs| if (self.recordDestructsNeedExplicitRest(destructs))
                try self.lowerRecordRestPatternBindingThen(value, value_ty, destructs, result_ty, continuation)
            else
                try self.lowerMaterializedPatternValueThen(pattern_id, value, value_ty, result_ty, continuation, miss),
            .assign,
            .as,
            .applied_tag,
            .nominal,
            .tuple,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .str_interpolation,
            .underscore,
            .pending,
            .runtime_error,
            => try self.lowerMaterializedPatternValueThen(pattern_id, value, value_ty, result_ty, continuation, miss),
        };
    }

    fn lowerListPatternBindingThen(
        self: *BodyContext,
        value: DraftExprId,
        value_ty: Type.TypeId,
        list: anytype,
        result_ty: Type.TypeId,
        continuation: BindingContinuation,
        miss: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const success = try self.lowerListPatternBindingSuccess(value, value_ty, list, result_ty, continuation, miss);
        const cond = try self.listPatternCondition(value, list);
        return try self.ifExpr(cond, success, miss, result_ty);
    }

    fn listPatternItemIndex(
        self: *BodyContext,
        index: usize,
        pattern_count: usize,
        rest: ?checked.CheckedListRestPattern,
        len: ?DraftExprId,
        u64_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        if (rest) |rest_info| {
            if (index >= rest_info.index) {
                const list_len = len orelse Common.invariant("list pattern trailing item index required list length");
                const trailing_count = try self.intLiteralExpr(pattern_count - index, u64_ty);
                return try self.lowLevelExpr(.num_minus, &.{ list_len, trailing_count }, u64_ty);
            }
        }
        return try self.intLiteralExpr(index, u64_ty);
    }

    fn sublistRangeExpr(
        self: *BodyContext,
        start: DraftExprId,
        len: DraftExprId,
        u64_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const len_name = try self.builder.program.names.internRecordFieldLabel("len");
        const start_name = try self.builder.program.names.internRecordFieldLabel("start");
        const fields = [_]Type.Field{
            .{ .name = len_name, .ty = u64_ty },
            .{ .name = start_name, .ty = u64_ty },
        };
        const ty = try self.builder.program.types.add(.{ .record = try self.builder.program.types.addRecordFields(&self.builder.program.names, &fields) });
        const exprs = [_]DraftFieldExpr{
            .{ .name = len_name, .value = len },
            .{ .name = start_name, .value = start },
        };
        return try self.addExpr(.{ .ty = ty, .data = .{ .record = try self.addFieldExprSpan(&exprs) } });
    }

    fn lowerListPatternBindingSuccess(
        self: *BodyContext,
        value: DraftExprId,
        value_ty: Type.TypeId,
        list: anytype,
        result_ty: Type.TypeId,
        continuation: BindingContinuation,
        miss: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const elem_ty = self.constListElemType(value_ty);
        const values = try self.allocator.alloc(DraftExprId, list.patterns.len);
        defer self.allocator.free(values);
        const patterns = try self.allocator.alloc(DraftPatId, list.patterns.len);
        defer self.allocator.free(patterns);
        const u64_ty = try self.builder.primitiveType(.u64);
        const needs_len = if (list.rest) |rest| rest.index < list.patterns.len or rest.pattern != null else false;
        const len = if (needs_len) try self.lowLevelExpr(.list_len, &.{value}, u64_ty) else null;

        for (list.patterns, 0..) |pattern_id, index| {
            const item_index = try self.listPatternItemIndex(index, list.patterns.len, list.rest, len, u64_ty);
            values[index] = try self.lowLevelExpr(.list_get_unsafe, &.{ value, item_index }, elem_ty);
            patterns[index] = try self.lowerPatternAtType(pattern_id, elem_ty);
        }

        var rest_pat: ?DraftPatId = null;
        var rest_value: ?DraftExprId = null;
        if (list.rest) |rest| {
            if (rest.pattern) |rest_pattern| {
                const list_len = len orelse try self.lowLevelExpr(.list_len, &.{value}, u64_ty);
                const fixed_count = try self.intLiteralExpr(list.patterns.len, u64_ty);
                const rest_len = try self.lowLevelExpr(.num_minus, &.{ list_len, fixed_count }, u64_ty);
                const rest_start = try self.intLiteralExpr(rest.index, u64_ty);
                const range = try self.sublistRangeExpr(rest_start, rest_len, u64_ty);
                rest_value = try self.lowLevelExpr(.list_sublist, &.{ value, range }, value_ty);
                rest_pat = try self.lowerPatternAtType(rest_pattern, value_ty);
            }
        }

        var success = try self.lowerBindingContinuation(continuation, result_ty);
        var index = patterns.len;
        while (index > 0) {
            index -= 1;
            success = try self.wrapPatternMatch(values[index], elem_ty, patterns[index], success, miss, result_ty);
        }
        if (rest_pat) |pat| {
            success = try self.wrapPatternMatch(
                rest_value orelse Common.invariant("list rest pattern had no lowered rest value"),
                value_ty,
                pat,
                success,
                miss,
                result_ty,
            );
        }
        return success;
    }

    fn lowerRecordRestPatternBindingThen(
        self: *BodyContext,
        value: DraftExprId,
        value_ty: Type.TypeId,
        destructs: []const checked.CheckedRecordDestruct,
        result_ty: Type.TypeId,
        continuation: BindingContinuation,
    ) Allocator.Error!DraftExprId {
        var success = try self.lowerBindingContinuation(continuation, result_ty);
        var i = destructs.len;
        while (i > 0) {
            i -= 1;
            const destruct = destructs[i];
            switch (destruct.kind) {
                .required, .sub_pattern => |child| {
                    const name = try self.builder.recordFieldName(self.view, destruct.label);
                    const field_ty = self.builder.recordFieldType(value_ty, name);
                    const field_value = try self.addExpr(.{
                        .ty = field_ty,
                        .data = .{ .field_access = .{
                            .receiver = value,
                            .field = name,
                        } },
                    });
                    const pat = try self.lowerPatternAtType(child, field_ty);
                    success = try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
                        .bind = pat,
                        .value = field_value,
                        .rest = success,
                    } } });
                },
                .rest => |child| {
                    if (self.patternIsIgnored(child)) continue;
                    const rest_node = try self.lowerTypeNode(self.view.bodies.pattern(child).ty);
                    const rest_cell = DraftTypeCell.fromGraphNode(rest_node);
                    const rest_ty = try self.activeTypeFromNode(rest_node);
                    const rest_value = try self.lowerRecordRestValueWithTypeCell(value, rest_cell, rest_ty);
                    const pat = try self.lowerPatternAtTypeCell(child, rest_cell, rest_ty);
                    success = try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
                        .bind = pat,
                        .value = rest_value,
                        .rest = success,
                    } } });
                },
            }
        }
        return success;
    }

    fn lowerRecordRestValueWithTypeCell(
        self: *BodyContext,
        value: DraftExprId,
        rest_cell: DraftTypeCell,
        rest_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const rest_fields = self.constRecordFields(rest_ty);
        const fields = try self.allocator.alloc(DraftFieldExpr, rest_fields.len);
        defer self.allocator.free(fields);
        for (rest_fields, 0..) |field, i| {
            fields[i] = .{
                .name = field.name,
                .value = try self.addExpr(.{
                    .ty = field.ty,
                    .data = .{ .field_access = .{
                        .receiver = value,
                        .field = field.name,
                    } },
                }),
            };
        }
        return try self.addExprWithTypeCell(rest_cell, .{
            .record = try self.addFieldExprSpan(fields),
        });
    }

    fn runtimeCrashExpr(self: *BodyContext, ty: Type.TypeId, message: []const u8) Allocator.Error!DraftExprId {
        return try self.addExpr(.{
            .ty = ty,
            .data = .{ .crash = try self.addStringLiteral(message) },
        });
    }

    fn comptimeExhaustivenessFailedExpr(self: *BodyContext, ty: Type.TypeId, site: DraftComptimeSiteId) Allocator.Error!DraftExprId {
        return try self.addExpr(.{
            .ty = ty,
            .data = .{ .comptime_exhaustiveness_failed = site },
        });
    }

    fn addComptimeSite(
        self: *BodyContext,
        kind: Ast.ComptimeSiteKind,
        region: base.Region,
        checked_site: ?checked.CheckedExhaustivenessSiteId,
        branch_regions: []const base.Region,
    ) Allocator.Error!DraftComptimeSiteId {
        return try self.draft.addComptimeSite(kind, region, checked_site, branch_regions);
    }

    fn wrapComptimeBranch(
        self: *BodyContext,
        site: ?DraftComptimeSiteId,
        branch_index: usize,
        body: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const actual_site = site orelse return body;
        return try self.addExprWithTypeCell(self.exprTypeCell(body), .{ .comptime_branch_taken = .{
            .site = actual_site,
            .branch_index = @intCast(branch_index),
            .body = body,
        } });
    }

    fn matchComptimeSite(self: *BodyContext, expr_id: checked.CheckedExprId, match: anytype) Allocator.Error!?DraftComptimeSiteId {
        if (!self.inComptimeExhaustivenessContext()) return null;
        if (match.skip_exhaustiveness) return null;
        const branch_regions = try self.matchBranchRegions(match.branches);
        defer self.allocator.free(branch_regions);
        const expr = self.view.bodies.expr(expr_id);
        const site_kind: Ast.ComptimeSiteKind = switch (match.comptime_site_kind) {
            .match => .match,
            .destructure => .destructure,
        };
        const checked_site = switch (match.comptime_site_kind) {
            .match => self.view.exhaustiveness_sites.lookupByMatchExpr(expr_id),
            .destructure => blk: {
                if (match.branches.len != 1) break :blk null;
                const patterns = match.branches[0].patternsSlice(self.view.bodies);
                if (patterns.len != 1) break :blk null;
                break :blk self.view.exhaustiveness_sites.lookupByDestructurePattern(patterns[0].pattern);
            },
        };
        return try self.addComptimeSite(site_kind, expr.source_region, checked_site, branch_regions);
    }

    fn matchBranchRegions(self: *BodyContext, branches: []const checked.CheckedMatchBranch) Allocator.Error![]base.Region {
        const regions = try self.allocator.alloc(base.Region, branchCount(branches));
        var index: usize = 0;
        for (branches) |branch| {
            for (branch.patternsSlice(self.view.bodies)) |pattern| {
                regions[index] = self.view.bodies.pattern(pattern.pattern).source_region;
                index += 1;
            }
        }
        return regions;
    }

    fn ifComptimeSite(self: *BodyContext, expr_id: checked.CheckedExprId, if_: anytype) Allocator.Error!?DraftComptimeSiteId {
        if (!self.inComptimeExhaustivenessContext()) return null;
        if (!if_.warn_unused_branches) return null;
        const branch_regions = try self.ifBranchRegions(if_);
        defer self.allocator.free(branch_regions);
        const expr = self.view.bodies.expr(expr_id);
        return try self.addComptimeSite(.if_, expr.source_region, null, branch_regions);
    }

    fn ifBranchRegions(self: *BodyContext, if_: anytype) Allocator.Error![]base.Region {
        const regions = try self.allocator.alloc(base.Region, if_.branches.len + 1);
        for (if_.branches, 0..) |branch, index| {
            regions[index] = self.view.bodies.expr(branch.cond).source_region;
        }
        regions[if_.branches.len] = self.view.bodies.expr(if_.final_else).source_region;
        return regions;
    }

    fn lowerMatch(self: *BodyContext, match: anytype, output: MatchOutput, comptime_site: ?DraftComptimeSiteId) Allocator.Error!BodyExprData {
        const scrutinee_ty = try self.matchScrutineeType(match);
        const scrutinee = try self.lowerExprAtType(match.cond, scrutinee_ty);
        const branches = try self.allocator.alloc(DraftBranch, branchCount(match.branches));
        defer self.allocator.free(branches);
        var index: usize = 0;
        for (match.branches) |branch| {
            for (branch.patternsSlice(self.view.bodies)) |pattern| {
                var branch_ctx = try self.childContext(self.current_fn_key);
                defer branch_ctx.deinit();
                var saved = std.ArrayList(BinderRestore).empty;
                defer saved.deinit(self.allocator);
                try branch_ctx.saveMatchPatternBinders(pattern, &saved);
                defer branch_ctx.restoreBinders(saved.items);

                const pat = try branch_ctx.lowerPatternAtType(pattern.pattern, scrutinee_ty);
                try branch_ctx.applyAlternativeBinderRemaps(pattern.binderRemapsSlice(self.view.bodies));
                const user_guard = if (branch.guard) |guard_expr| try branch_ctx.lowerExpr(guard_expr) else null;
                const guard = try branch_ctx.conjoinPatternLiteralGuards(user_guard);
                const body = try branch_ctx.wrapComptimeBranch(
                    comptime_site,
                    index,
                    try branch_ctx.lowerMatchBranchBody(branch.value, output),
                );
                branches[index] = .{
                    .pat = pat,
                    .guard = guard,
                    .body = body,
                };
                index += 1;
            }
        }
        return .{ .match_ = .{
            .scrutinee = scrutinee,
            .branches = try self.addBranchSpan(branches),
            .comptime_site = comptime_site,
        } };
    }

    fn matchScrutineeType(self: *BodyContext, match: anytype) Allocator.Error!Type.TypeId {
        return try self.lowerExprType(match.cond);
    }

    fn saveMatchPatternBinders(
        self: *BodyContext,
        pattern: checked.CheckedMatchBranchPattern,
        saved: *std.ArrayList(BinderRestore),
    ) Allocator.Error!void {
        try self.savePatternBinders(pattern.pattern, saved);
        for (pattern.binderRemapsSlice(self.view.bodies)) |remap| {
            try self.saveBinder(remap.candidate_binder, saved);
            try self.saveBinder(remap.representative_binder, saved);
        }
    }

    fn savePatternBinders(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        saved: *std.ArrayList(BinderRestore),
    ) Allocator.Error!void {
        const pattern = self.view.bodies.pattern(pattern_id);
        switch (pattern.data) {
            .assign => |binder| try self.saveBinder(binder, saved),
            .as => |as| {
                try self.savePatternBinders(as.pattern, saved);
                try self.saveBinder(as.binder, saved);
            },
            .applied_tag => |tag| for (tag.args) |arg| try self.savePatternBinders(arg, saved),
            .nominal => |nominal| try self.savePatternBinders(nominal.backing_pattern, saved),
            .record_destructure => |destructs| {
                for (destructs) |destruct| {
                    const child = switch (destruct.kind) {
                        .required => |child_pattern| child_pattern,
                        .sub_pattern => |child_pattern| child_pattern,
                        .rest => |child_pattern| child_pattern,
                    };
                    try self.savePatternBinders(child, saved);
                }
            },
            .list => |list| {
                for (list.patterns) |child| try self.savePatternBinders(child, saved);
                if (list.rest) |rest| if (rest.pattern) |rest_pattern| try self.savePatternBinders(rest_pattern, saved);
            },
            .tuple => |items| for (items) |child| try self.savePatternBinders(child, saved),
            .str_interpolation => |str| {
                for (str.steps) |step| {
                    if (step.capture) |capture| try self.savePatternBinders(capture, saved);
                }
            },
            .pending,
            .num_literal,
            .small_dec_literal,
            .dec_literal,
            .frac_f32_literal,
            .frac_f64_literal,
            .str_literal,
            .underscore,
            .runtime_error,
            => {},
        }
    }

    fn saveBinder(
        self: *BodyContext,
        binder: checked.PatternBinderId,
        saved: *std.ArrayList(BinderRestore),
    ) Allocator.Error!void {
        for (saved.items) |item| {
            if (item.binder == binder) return;
        }
        try saved.append(self.allocator, .{
            .binder = binder,
            .previous = self.binders.get(binder),
        });
    }

    fn applyAlternativeBinderRemaps(
        self: *BodyContext,
        remaps: []const checked.CheckedAlternativeBinderRemap,
    ) Allocator.Error!void {
        for (remaps) |remap| {
            const local = self.binders.get(remap.candidate_binder) orelse
                Common.invariant("match alternative binder remap referenced an unbound candidate binder");
            try self.binders.put(remap.representative_binder, local);
        }
    }

    fn restoreBinders(self: *BodyContext, saved: []const BinderRestore) void {
        var index = saved.len;
        while (index > 0) {
            index -= 1;
            if (saved[index].previous) |previous| {
                self.binders.put(saved[index].binder, previous) catch |err| switch (err) {
                    error.OutOfMemory => Common.invariant("restoring a previously inserted binder cannot reallocate"),
                };
            } else {
                _ = self.binders.remove(saved[index].binder);
            }
        }
    }

    fn lowerIfExpr(
        self: *BodyContext,
        expr_id: checked.CheckedExprId,
        if_: anytype,
        result_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const comptime_site = try self.ifComptimeSite(expr_id, if_);
        const merge_binders = try self.stateMergeBinders(expr_id);
        defer self.allocator.free(merge_binders);

        if (merge_binders.len == 0) {
            return try self.addExpr(.{
                .ty = result_ty,
                .data = try self.lowerIf(if_, result_ty, result_ty, &.{}, comptime_site),
            });
        }

        const state_ty = try self.stateResultType(merge_binders, result_ty);
        const state_expr = try self.addExpr(.{
            .ty = state_ty,
            .data = try self.lowerIf(if_, result_ty, state_ty, merge_binders, comptime_site),
        });

        const pattern_items = try self.allocator.alloc(DraftPatId, merge_binders.len + 1);
        defer self.allocator.free(pattern_items);
        for (merge_binders, 0..) |merge, i| {
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), merge.ty, merge.binder);
            try self.bindLocalName(local, merge.binder);
            try self.binders.put(merge.binder, local);
            pattern_items[i] = try self.addPat(.{ .ty = merge.ty, .data = .{ .bind = local } });
        }

        const result_local = try self.addLocal(self.builder.symbols.fresh(), result_ty);
        pattern_items[merge_binders.len] = try self.addPat(.{ .ty = result_ty, .data = .{ .bind = result_local } });
        const bind_pat = try self.addPat(.{ .ty = state_ty, .data = .{ .tuple = try self.addPatSpan(pattern_items) } });
        const rest = try self.localExpr(result_local, result_ty);

        return try self.addExpr(.{ .ty = result_ty, .data = .{ .let_ = .{
            .bind = bind_pat,
            .value = state_expr,
            .rest = rest,
        } } });
    }

    fn stateMergeBinders(self: *BodyContext, expr_id: checked.CheckedExprId) Allocator.Error![]MergeBinder {
        var reassigned = std.ArrayList(checked.PatternBinderId).empty;
        defer reassigned.deinit(self.allocator);
        try self.collectReassignedBindersInExpr(expr_id, &reassigned);

        var merge_binders = std.ArrayList(MergeBinder).empty;
        errdefer merge_binders.deinit(self.allocator);
        for (reassigned.items) |binder| {
            const before = self.binders.get(binder) orelse continue;
            const ty = try self.localType(before);
            try merge_binders.append(self.allocator, .{
                .binder = binder,
                .before = before,
                .ty = ty,
            });
        }
        return try merge_binders.toOwnedSlice(self.allocator);
    }

    fn stateResultType(
        self: *BodyContext,
        merge_binders: []const MergeBinder,
        result_ty: Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        const tys = try self.allocator.alloc(Type.TypeId, merge_binders.len + 1);
        defer self.allocator.free(tys);
        for (merge_binders, 0..) |merge, i| tys[i] = merge.ty;
        tys[merge_binders.len] = result_ty;
        return try self.builder.program.types.add(.{ .tuple = try self.builder.program.types.addSpan(tys) });
    }

    fn stateOnlyType(
        self: *BodyContext,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!Type.TypeId {
        if (merge_binders.len == 0) return try self.unitType();
        if (merge_binders.len == 1) return merge_binders[0].ty;

        const tys = try self.allocator.alloc(Type.TypeId, merge_binders.len);
        defer self.allocator.free(tys);
        for (merge_binders, 0..) |merge, i| tys[i] = merge.ty;
        return try self.builder.program.types.add(.{ .tuple = try self.builder.program.types.addSpan(tys) });
    }

    fn lowerIf(
        self: *BodyContext,
        if_: anytype,
        result_ty: Type.TypeId,
        branch_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
        comptime_site: ?DraftComptimeSiteId,
    ) Allocator.Error!BodyExprData {
        const branches = try self.allocator.alloc(DraftIfBranch, if_.branches.len);
        defer self.allocator.free(branches);
        for (if_.branches, 0..) |branch, i| {
            const cond = try self.lowerExpr(branch.cond);
            var branch_ctx = try self.childContext(self.current_fn_key);
            defer branch_ctx.deinit();
            branches[i] = .{
                .cond = cond,
                .body = try branch_ctx.wrapComptimeBranch(
                    comptime_site,
                    i,
                    try branch_ctx.lowerIfBranchBody(branch.body, result_ty, branch_ty, merge_binders),
                ),
            };
        }
        var else_ctx = try self.childContext(self.current_fn_key);
        defer else_ctx.deinit();
        return .{ .if_ = .{
            .branches = try self.addIfBranchSpan(branches),
            .final_else = try else_ctx.wrapComptimeBranch(
                comptime_site,
                if_.branches.len,
                try else_ctx.lowerIfBranchBody(if_.final_else, result_ty, branch_ty, merge_binders),
            ),
        } };
    }

    fn lowerIfBranchBody(
        self: *BodyContext,
        body: checked.CheckedExprId,
        result_ty: Type.TypeId,
        branch_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!DraftExprId {
        if (merge_binders.len == 0) return try self.lowerBranchValueAtType(body, result_ty);

        return try self.lowerBodyThenStateResult(body, result_ty, branch_ty, merge_binders);
    }

    fn lowerIfStateOnly(
        self: *BodyContext,
        if_: anytype,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
        comptime_site: ?DraftComptimeSiteId,
    ) Allocator.Error!BodyExprData {
        const branches = try self.allocator.alloc(DraftIfBranch, if_.branches.len);
        defer self.allocator.free(branches);
        for (if_.branches, 0..) |branch, i| {
            const cond = try self.lowerExpr(branch.cond);
            var branch_ctx = try self.childContext(self.current_fn_key);
            defer branch_ctx.deinit();
            branches[i] = .{
                .cond = cond,
                .body = try branch_ctx.wrapComptimeBranch(
                    comptime_site,
                    i,
                    try branch_ctx.lowerBodyThenStateOnly(branch.body, state_ty, merge_binders),
                ),
            };
        }
        var else_ctx = try self.childContext(self.current_fn_key);
        defer else_ctx.deinit();
        return .{ .if_ = .{
            .branches = try self.addIfBranchSpan(branches),
            .final_else = try else_ctx.wrapComptimeBranch(
                comptime_site,
                if_.branches.len,
                try else_ctx.lowerBodyThenStateOnly(if_.final_else, state_ty, merge_binders),
            ),
        } };
    }

    fn lowerBodyThenStateResult(
        self: *BodyContext,
        body: checked.CheckedExprId,
        result_ty: Type.TypeId,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!DraftExprId {
        if (self.checkedExprDivergesInLoweredRuntime(body)) return try self.lowerDivergentExprAtType(body, state_ty);

        const checked_body = self.view.bodies.expr(body);
        switch (checked_body.data) {
            .block => |block| {
                const statements = try self.lowerBlockStatements(block.statements);
                defer self.allocator.free(statements.items);
                const value = if (statements.diverges)
                    try self.unreachableAfterDivergentStatementExpr(result_ty)
                else if (self.checkedExprDivergesInLoweredRuntime(block.final_expr))
                    try self.lowerDivergentExprAtType(block.final_expr, result_ty)
                else
                    try self.lowerExprAtType(block.final_expr, result_ty);
                return try self.addExpr(.{ .ty = state_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(statements.items[0..statements.len]),
                    .final_expr = try self.stateResultAfterValue(state_ty, merge_binders, result_ty, value),
                } } });
            },
            else => {
                const value = try self.lowerExprAtType(body, result_ty);
                return try self.stateResultAfterValue(state_ty, merge_binders, result_ty, value);
            },
        }
    }

    fn lowerBodyThenStateOnly(
        self: *BodyContext,
        body: checked.CheckedExprId,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!DraftExprId {
        if (self.checkedExprDivergesInLoweredRuntime(body)) return try self.lowerDivergentExprAtType(body, state_ty);

        const checked_body = self.view.bodies.expr(body);
        switch (checked_body.data) {
            .block => |block| {
                var statements = try self.lowerBlockStatements(block.statements);
                defer self.allocator.free(statements.items);
                if (!statements.diverges) {
                    const final_stmt = try self.lowerDiscardedExprStatement(
                        block.final_expr,
                        try self.lowerTypeView(checked_body.ty),
                    );
                    try statements.append(self.allocator, final_stmt);
                }
                return try self.addExpr(.{ .ty = state_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(statements.items[0..statements.len]),
                    .final_expr = try self.stateOnlyTupleExpr(state_ty, merge_binders),
                } } });
            },
            else => {
                const stmt = try self.lowerDiscardedExprStatement(body, try self.lowerTypeView(checked_body.ty));
                return try self.addExpr(.{ .ty = state_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(&[_]DraftStmtId{stmt}),
                    .final_expr = try self.stateOnlyTupleExpr(state_ty, merge_binders),
                } } });
            },
        }
    }

    fn lowerDiscardedExprStatement(
        self: *BodyContext,
        expr_id: checked.CheckedExprId,
        divergent_ty: Type.TypeId,
    ) Allocator.Error!DraftStmtId {
        if (self.checkedExprDivergesInLoweredRuntime(expr_id)) {
            return try self.addStmt(.{ .expr = try self.lowerDivergentExprAtType(expr_id, divergent_ty) });
        }
        return try self.addStmt(try self.lowerExprStatement(expr_id));
    }

    fn stateResultTupleExpr(
        self: *BodyContext,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
        result: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const items = try self.allocator.alloc(DraftExprId, merge_binders.len + 1);
        defer self.allocator.free(items);
        for (merge_binders, 0..) |merge, i| {
            const current = self.binders.get(merge.binder) orelse merge.before;
            items[i] = try self.localExpr(current, merge.ty);
        }
        items[merge_binders.len] = result;
        return try self.addExpr(.{ .ty = state_ty, .data = .{ .tuple = try self.addExprSpan(items) } });
    }

    fn stateResultAfterValue(
        self: *BodyContext,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
        result_ty: Type.TypeId,
        value: DraftExprId,
    ) Allocator.Error!DraftExprId {
        const local = try self.addLocal(self.builder.symbols.fresh(), result_ty);
        const local_expr = try self.localExpr(local, result_ty);
        return try self.addExpr(.{ .ty = state_ty, .data = .{ .let_ = .{
            .bind = try self.bindPat(local, result_ty),
            .value = value,
            .rest = try self.stateResultTupleExpr(state_ty, merge_binders, local_expr),
        } } });
    }

    fn stateOnlyTupleExpr(
        self: *BodyContext,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!DraftExprId {
        if (merge_binders.len == 0) {
            return try self.addExpr(.{ .ty = state_ty, .data = .unit });
        }
        if (merge_binders.len == 1) {
            const merge = merge_binders[0];
            const current = self.binders.get(merge.binder) orelse merge.before;
            return try self.localExpr(current, merge.ty);
        }

        const items = try self.allocator.alloc(DraftExprId, merge_binders.len);
        defer self.allocator.free(items);
        for (merge_binders, 0..) |merge, i| {
            const current = self.binders.get(merge.binder) orelse merge.before;
            items[i] = try self.localExpr(current, merge.ty);
        }
        return try self.addExpr(.{ .ty = state_ty, .data = .{ .tuple = try self.addExprSpan(items) } });
    }

    fn stateOnlyPattern(
        self: *BodyContext,
        state_ty: Type.TypeId,
        merge_binders: []const MergeBinder,
    ) Allocator.Error!DraftPatId {
        if (merge_binders.len == 0) return try self.addPat(.{ .ty = state_ty, .data = .wildcard });
        if (merge_binders.len == 1) {
            const merge = merge_binders[0];
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), merge.ty, merge.binder);
            try self.bindLocalName(local, merge.binder);
            try self.binders.put(merge.binder, local);
            return try self.addPat(.{ .ty = state_ty, .data = .{ .bind = local } });
        }

        const pattern_items = try self.allocator.alloc(DraftPatId, merge_binders.len);
        defer self.allocator.free(pattern_items);
        for (merge_binders, 0..) |merge, i| {
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), merge.ty, merge.binder);
            try self.bindLocalName(local, merge.binder);
            try self.binders.put(merge.binder, local);
            pattern_items[i] = try self.addPat(.{ .ty = merge.ty, .data = .{ .bind = local } });
        }
        return try self.addPat(.{ .ty = state_ty, .data = .{ .tuple = try self.addPatSpan(pattern_items) } });
    }

    fn lowerBlock(self: *BodyContext, block: anytype, ty: Type.TypeId) Allocator.Error!BodyExprData {
        const stmts = try self.lowerBlockStatements(block.statements);
        defer self.allocator.free(stmts.items);
        return .{ .block = .{
            .statements = try self.addStmtSpan(stmts.items[0..stmts.len]),
            .final_expr = if (stmts.diverges)
                try self.unreachableAfterDivergentStatementExpr(ty)
            else if (self.checkedExprDivergesInLoweredRuntime(block.final_expr))
                try self.lowerDivergentExprAtType(block.final_expr, ty)
            else
                try self.lowerExprAtType(block.final_expr, ty),
        } };
    }

    const LoweredStatements = struct {
        items: []DraftStmtId,
        len: usize,
        diverges: bool,

        fn append(self: *LoweredStatements, allocator: Allocator, stmt: DraftStmtId) Allocator.Error!void {
            if (self.len == self.items.len) {
                const grown = try allocator.realloc(self.items, self.items.len + 1);
                self.items = grown;
            }
            self.items[self.len] = stmt;
            self.len += 1;
        }
    };

    fn lowerBlockStatements(self: *BodyContext, checked_statements: []const checked.CheckedStatementId) Allocator.Error!LoweredStatements {
        const items = try self.allocator.alloc(DraftStmtId, checked_statements.len);
        var lowered = LoweredStatements{
            .items = items,
            .len = 0,
            .diverges = false,
        };
        for (checked_statements) |statement| {
            if (!self.checkedStatementHasRuntimeEffect(statement)) continue;
            if (!try self.appendExpandedPatternStatement(statement, &lowered)) {
                try lowered.append(self.allocator, try self.lowerStatement(statement));
            }
            if (self.checkedStatementDivergesInLoweredRuntime(statement)) lowered.diverges = true;
        }
        return lowered;
    }

    fn appendExpandedPatternStatement(
        self: *BodyContext,
        statement_id: checked.CheckedStatementId,
        lowered: *LoweredStatements,
    ) Allocator.Error!bool {
        const statement = self.view.bodies.statement(statement_id);
        const saved_loc = self.builder.program.current_loc;
        defer self.builder.program.current_loc = saved_loc;
        const saved_region = self.builder.program.current_region;
        defer self.builder.program.current_region = saved_region;
        self.builder.program.current_loc = try self.sourceLocFor(statement.source_region);
        self.builder.program.current_region = statement.source_region;
        const pattern, const expr = switch (statement.data) {
            .decl => |decl| blk: {
                if (self.statementValueIsLocalProc(decl.expr)) return false;
                break :blk .{ decl.pattern, decl.expr };
            },
            .var_ => |decl| .{ decl.pattern, decl.expr },
            .reassign => |decl| .{ decl.pattern, decl.expr },
            else => return false,
        };

        const pattern_data = self.view.bodies.pattern(pattern).data;
        const destructs = switch (pattern_data) {
            .record_destructure => |destructs| destructs,
            else => return false,
        };
        if (!self.recordDestructsNeedExplicitRest(destructs)) return false;

        const value = try self.lowerExpr(expr);
        const value_ty = try self.exprType(value);
        const source_local = try self.addLocal(self.builder.symbols.fresh(), value_ty);
        try lowered.append(self.allocator, try self.addStmt(.{ .let_ = .{
            .pat = try self.bindPat(source_local, value_ty),
            .value = value,
        } }));

        const source_expr = try self.localExpr(source_local, value_ty);
        const comptime_site = if (self.inComptimeExhaustivenessContext() and self.patternCanMiss(pattern))
            try self.addComptimeSite(.destructure, statement.source_region, self.view.exhaustiveness_sites.lookupByDestructurePattern(pattern), &.{})
        else
            null;
        try self.appendRecordRestPatternStatements(source_expr, value_ty, destructs, lowered, comptime_site);
        return true;
    }

    fn appendRecordRestPatternStatements(
        self: *BodyContext,
        value: DraftExprId,
        value_ty: Type.TypeId,
        destructs: []const checked.CheckedRecordDestruct,
        lowered: *LoweredStatements,
        comptime_site: ?DraftComptimeSiteId,
    ) Allocator.Error!void {
        for (destructs) |destruct| {
            switch (destruct.kind) {
                .required, .sub_pattern => |child| {
                    const name = try self.builder.recordFieldName(self.view, destruct.label);
                    const field_ty = self.builder.recordFieldType(value_ty, name);
                    const field_value = try self.addExpr(.{
                        .ty = field_ty,
                        .data = .{ .field_access = .{
                            .receiver = value,
                            .field = name,
                        } },
                    });
                    try lowered.append(self.allocator, try self.addStmt(.{ .let_ = .{
                        .pat = try self.lowerPatternAtType(child, field_ty),
                        .value = field_value,
                        .comptime_site = if (self.patternCanMiss(child)) comptime_site else null,
                    } }));
                },
                .rest => |child| {
                    if (self.patternIsIgnored(child)) continue;
                    const rest_node = try self.lowerTypeNode(self.view.bodies.pattern(child).ty);
                    const rest_cell = DraftTypeCell.fromGraphNode(rest_node);
                    const rest_ty = try self.activeTypeFromNode(rest_node);
                    const rest_value = try self.lowerRecordRestValueWithTypeCell(value, rest_cell, rest_ty);
                    try lowered.append(self.allocator, try self.addStmt(.{ .let_ = .{
                        .pat = try self.lowerPatternAtTypeCell(child, rest_cell, rest_ty),
                        .value = rest_value,
                        .comptime_site = if (self.patternCanMiss(child)) comptime_site else null,
                    } }));
                },
            }
        }
    }

    fn checkedStatementHasRuntimeEffect(self: *BodyContext, statement_id: checked.CheckedStatementId) bool {
        const raw = @intFromEnum(statement_id);
        if (raw >= self.view.bodies.statementCount()) {
            Common.invariant("checked runtime statement filter referenced a missing statement");
        }
        return switch (self.view.bodies.statement(@enumFromInt(raw)).data) {
            .decl => |decl| self.view.hoisted_constants.lookupByPattern(decl.pattern) == null,
            .var_,
            .var_uninitialized,
            .reassign,
            .crash,
            .dbg,
            .expr,
            .for_,
            .while_,
            .infinite_loop,
            .breakable_loop,
            .break_,
            .return_,
            => true,
            .expect => self.builder.inline_expects == .run,
            .import_,
            .alias_decl,
            .nominal_decl,
            .type_anno,
            .type_var_alias,
            => false,
            .pending,
            .runtime_error,
            => Common.invariant("invalid checked statement reached Monotype runtime statement filter"),
        };
    }

    fn lowerDivergentExprAtType(
        self: *BodyContext,
        checked_expr_id: checked.CheckedExprId,
        ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const checked_expr = self.view.bodies.expr(checked_expr_id);
        switch (checked_expr.data) {
            .match_ => |match| return try self.lowerMatchExpr(checked_expr_id, match, ty),
            .if_ => |if_| return try self.lowerIfExpr(checked_expr_id, if_, ty),
            else => {},
        }

        return try self.addExpr(.{
            .ty = ty,
            .data = try self.lowerDivergentExprDataAtType(checked_expr_id, ty),
        });
    }

    fn exprIdAsDivergentData(self: *BodyContext, expr: DraftExprId) Allocator.Error!BodyExprData {
        return .{ .block = .{
            .statements = try self.addStmtSpan(&[_]DraftStmtId{}),
            .final_expr = expr,
        } };
    }

    fn lowerDivergentExprDataAtType(
        self: *BodyContext,
        checked_expr_id: checked.CheckedExprId,
        ty: Type.TypeId,
    ) Allocator.Error!BodyExprData {
        const checked_expr = self.view.bodies.expr(checked_expr_id);
        return switch (checked_expr.data) {
            .block => |block| try self.lowerBlock(block, ty),
            .match_ => |match| try self.exprIdAsDivergentData(try self.lowerMatchExpr(checked_expr_id, match, ty)),
            .if_ => |if_| try self.exprIdAsDivergentData(try self.lowerIfExpr(checked_expr_id, if_, ty)),
            .ellipsis => .{ .crash = try self.addStringLiteral("not implemented") },
            .crash => |msg| .{ .crash = try self.lowerStringLiteral(msg) },
            .runtime_error => .{ .crash = try self.addStringLiteral("runtime error") },
            .expect_err => |expect_err| .{ .expect_err = .{
                .msg = try self.lowerExpectErrMessage(expect_err.expr, expect_err.snippet),
                .region = checked_expr.source_region,
            } },
            .break_ => try self.breakCurrentLoopExprData(),
            .return_ => |ret| .{ .return_ = try self.lowerReturn(ret) },
            else => Common.invariant("checked expression was marked divergent but has no divergent lowering path"),
        };
    }

    fn unreachableAfterDivergentStatementExpr(self: *BodyContext, ty: Type.TypeId) Allocator.Error!DraftExprId {
        return try self.addExpr(.{
            .ty = ty,
            .data = .{ .crash = try self.addStringLiteral("reached code after checked control transfer") },
        });
    }

    fn checkedExprDiverges(self: *BodyContext, expr_id: checked.CheckedExprId) bool {
        const raw = @intFromEnum(expr_id);
        if (raw >= self.view.bodies.exprCount()) {
            Common.invariant("checked divergence referenced a missing expression");
        }
        return self.view.bodies.exprDiverges(expr_id);
    }

    fn checkedStatementDiverges(self: *BodyContext, statement_id: checked.CheckedStatementId) bool {
        const raw = @intFromEnum(statement_id);
        if (raw >= self.view.bodies.statementCount()) {
            Common.invariant("checked divergence referenced a missing statement");
        }
        return self.view.bodies.statementDiverges(statement_id);
    }

    /// Checked divergence is computed before this lowering pass can omit inline
    /// expects, so optimized builds need a divergence view of the lowered code.
    fn checkedStatementDivergesInLoweredRuntime(self: *BodyContext, statement_id: checked.CheckedStatementId) bool {
        if (!self.checkedStatementDiverges(statement_id)) return false;
        if (self.builder.inline_expects == .run) return true;

        return switch (self.view.bodies.statement(statement_id).data) {
            .crash,
            .break_,
            .return_,
            => true,
            .decl => |decl| self.checkedExprDivergesInLoweredRuntime(decl.expr),
            .var_ => |var_| self.checkedExprDivergesInLoweredRuntime(var_.expr),
            .var_uninitialized => false,
            .reassign => |reassign| self.checkedExprDivergesInLoweredRuntime(reassign.expr),
            .dbg,
            .expr,
            => |expr| self.checkedExprDivergesInLoweredRuntime(expr),
            .expect => false,
            .for_ => |for_| self.checkedExprDivergesInLoweredRuntime(for_.expr),
            .while_ => |while_| self.checkedExprDivergesInLoweredRuntime(while_.cond),
            .infinite_loop => true,
            .breakable_loop => |loop| self.checkedExprDivergesInLoweredRuntime(loop.cond),
            .pending,
            .import_,
            .alias_decl,
            .nominal_decl,
            .type_anno,
            .type_var_alias,
            .runtime_error,
            => false,
        };
    }

    fn checkedAnyExprDivergesInLoweredRuntime(self: *BodyContext, items: []const checked.CheckedExprId) bool {
        for (items) |item| {
            if (self.checkedExprDivergesInLoweredRuntime(item)) return true;
        }
        return false;
    }

    fn checkedExprDivergesInLoweredRuntime(self: *BodyContext, expr_id: checked.CheckedExprId) bool {
        if (!self.checkedExprDiverges(expr_id)) return false;
        if (self.builder.inline_expects == .run) return true;

        return switch (self.view.bodies.expr(expr_id).data) {
            .crash,
            .ellipsis,
            .break_,
            .return_,
            => true,
            .str => |items| self.checkedAnyExprDivergesInLoweredRuntime(items),
            .list => |items| self.checkedAnyExprDivergesInLoweredRuntime(items),
            .tuple => |items| self.checkedAnyExprDivergesInLoweredRuntime(items),
            .match_ => |match| blk: {
                if (self.checkedExprDivergesInLoweredRuntime(match.cond)) break :blk true;
                if (match.branches.len == 0) break :blk false;
                for (match.branches) |branch| {
                    if (branch.guard != null) break :blk false;
                    if (!self.checkedExprDivergesInLoweredRuntime(branch.value)) break :blk false;
                }
                break :blk true;
            },
            .if_ => |if_| blk: {
                if (if_.branches.len > 0 and self.checkedExprDivergesInLoweredRuntime(if_.branches[0].cond)) {
                    break :blk true;
                }
                for (if_.branches) |branch| {
                    if (!self.checkedExprDivergesInLoweredRuntime(branch.body)) break :blk false;
                }
                break :blk self.checkedExprDivergesInLoweredRuntime(if_.final_else);
            },
            .call => |call| blk: {
                if (self.checkedExprDivergesInLoweredRuntime(call.func)) break :blk true;
                break :blk self.checkedAnyExprDivergesInLoweredRuntime(call.args);
            },
            .record => |record| blk: {
                if (record.ext) |ext| {
                    if (self.checkedExprDivergesInLoweredRuntime(ext)) break :blk true;
                }
                for (record.fields) |field| {
                    if (self.checkedExprDivergesInLoweredRuntime(field.value)) break :blk true;
                }
                break :blk false;
            },
            .block => |block| blk: {
                for (block.statements) |statement| {
                    if (self.checkedStatementDivergesInLoweredRuntime(statement)) break :blk true;
                }
                break :blk self.checkedExprDivergesInLoweredRuntime(block.final_expr);
            },
            .tag => |tag| self.checkedAnyExprDivergesInLoweredRuntime(tag.args),
            .nominal => |nominal| self.checkedExprDivergesInLoweredRuntime(nominal.backing_expr),
            .closure,
            .lambda,
            => false,
            .binop => |binop| self.checkedExprDivergesInLoweredRuntime(binop.lhs) or
                self.checkedExprDivergesInLoweredRuntime(binop.rhs),
            .unary_minus,
            .unary_not,
            .dbg,
            => |child| self.checkedExprDivergesInLoweredRuntime(child),
            .expect => false,
            .expect_err => true,
            .field_access => |field| self.checkedExprDivergesInLoweredRuntime(field.receiver),
            .structural_eq => |eq| self.checkedExprDivergesInLoweredRuntime(eq.lhs) or
                self.checkedExprDivergesInLoweredRuntime(eq.rhs),
            .structural_hash => |hash| self.checkedExprDivergesInLoweredRuntime(hash.value) or
                self.checkedExprDivergesInLoweredRuntime(hash.hasher),
            .tuple_access => |access| self.checkedExprDivergesInLoweredRuntime(access.tuple),
            .for_ => |for_| self.checkedExprDivergesInLoweredRuntime(for_.expr),
            .run_low_level => |low_level| self.checkedAnyExprDivergesInLoweredRuntime(low_level.args),
            .pending,
            .num,
            .frac_f32,
            .frac_f64,
            .dec,
            .dec_small,
            .num_from_numeral,
            .typed_int,
            .typed_frac,
            .typed_num_from_numeral,
            .str_from_quote,
            .str_segment,
            .bytes_literal,
            .lookup_local,
            .lookup_external,
            .lookup_required,
            .empty_list,
            .empty_record,
            .zero_argument_tag,
            .dispatch_call,
            .interpolation,
            .method_eq,
            .type_dispatch_call,
            .runtime_error,
            .anno_only,
            .hosted_lambda,
            => false,
        };
    }

    const LoopCarry = struct {
        binder: checked.PatternBinderId,
        initial_local: DraftLocalId,
        param_local: DraftLocalId,
        ty: Type.TypeId,
    };

    const LoopContext = struct {
        result_ty: Type.TypeId,
        carries: []const LoopCarry,
    };

    fn lowerIteratorFor(
        self: *BodyContext,
        for_: anytype,
        result_ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!BodyExprData {
        const plan_id = for_.plan orelse Common.invariant("checked iterator for reached Monotype without an iterator dispatch plan");
        const plan = self.view.static_dispatch_plans.iterator_for_plans[@intFromEnum(plan_id)];

        const step = try self.iteratorStepShape(plan.step_ty);
        const initial_iterator = try self.lowerIteratorDispatch(plan.iter, null, null);
        const iterator_ty = try self.exprType(initial_iterator);
        try self.constrainTypeToMono(plan.iterator_ty, iterator_ty);
        try self.constrainTypeToMono(step.one_rest.ty, iterator_ty);
        try self.constrainTypeToMono(step.skip_rest.ty, iterator_ty);
        const item_ty = try self.lowerTypeView(step.one_item.ty);
        try self.constrainTypeToMono(plan.item_ty, item_ty);
        const step_expected_ty = try self.lowerTypeView(plan.step_ty);
        const iterator_local = try self.addLocal(self.builder.symbols.fresh(), iterator_ty);
        const iterator_param = BodyTypedLocal{ .local = iterator_local, .ty = iterator_ty };

        var saved = std.ArrayList(BinderRestore).empty;
        defer saved.deinit(self.allocator);
        for (carries) |carry| {
            try self.saveBinder(carry.binder, &saved);
            try self.binders.put(carry.binder, carry.param_local);
        }
        defer self.restoreBinders(saved.items);

        try self.pushLoopContext(result_ty, carries);
        defer self.popLoopContext();

        const step_expr = try self.lowerIteratorDispatch(plan.next, iterator_param, step_expected_ty);
        try self.constrainTypeToMono(plan.step_ty, try self.exprType(step_expr));
        const done_body = if (carries.len == 0)
            try self.addExpr(.{ .ty = result_ty, .data = .{ .break_ = null } })
        else
            try self.addExpr(.{ .ty = result_ty, .data = .{ .break_ = try self.loopStateExpr(result_ty, carries) } });

        var branches: [3]DraftBranch = undefined;
        branches[0] = .{
            .pat = try self.iteratorDonePattern(step),
            .body = done_body,
        };
        branches[1] = try self.iteratorOneBranch(for_, result_ty, step, iterator_ty, carries);
        branches[2] = try self.iteratorSkipBranch(result_ty, step, iterator_ty, carries);

        const match_expr = try self.addExpr(.{
            .ty = result_ty,
            .data = .{ .match_ = .{
                .scrutinee = step_expr,
                .branches = try self.addBranchSpan(&branches),
            } },
        });

        const params = try self.allocator.alloc(BodyTypedLocal, 1 + carries.len);
        defer self.allocator.free(params);
        params[0] = iterator_param;
        for (carries, 0..) |carry, i| params[i + 1] = .{ .local = carry.param_local, .ty = carry.ty };

        const initial_values = try self.allocator.alloc(DraftExprId, 1 + carries.len);
        defer self.allocator.free(initial_values);
        initial_values[0] = initial_iterator;
        for (carries, 0..) |carry, i| {
            initial_values[i + 1] = try self.localExpr(carry.initial_local, carry.ty);
        }

        return .{ .loop_ = .{
            .params = try self.addTypedLocalSpan(params),
            .initial_values = try self.addExprSpan(initial_values),
            .body = match_expr,
        } };
    }

    fn lowerWhile(
        self: *BodyContext,
        while_: anytype,
        result_ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!BodyExprData {
        var saved = std.ArrayList(BinderRestore).empty;
        defer saved.deinit(self.allocator);
        for (carries) |carry| {
            try self.saveBinder(carry.binder, &saved);
            try self.binders.put(carry.binder, carry.param_local);
        }
        defer self.restoreBinders(saved.items);

        try self.pushLoopContext(result_ty, carries);
        defer self.popLoopContext();

        const cond = try self.lowerExpr(while_.cond);
        const break_body = try self.breakCurrentLoopExpr();
        const continue_body = try self.lowerWhileBodyThenContinue(while_.body, result_ty, carries);
        const branches = [_]DraftIfBranch{.{ .cond = cond, .body = continue_body }};
        const body = try self.addExpr(.{ .ty = result_ty, .data = .{ .if_ = .{
            .branches = try self.addIfBranchSpan(&branches),
            .final_else = break_body,
        } } });

        const params = try self.allocator.alloc(BodyTypedLocal, carries.len);
        defer self.allocator.free(params);
        for (carries, 0..) |carry, i| params[i] = .{ .local = carry.param_local, .ty = carry.ty };

        const initial_values = try self.allocator.alloc(DraftExprId, carries.len);
        defer self.allocator.free(initial_values);
        for (carries, 0..) |carry, i| {
            initial_values[i] = try self.localExpr(carry.initial_local, carry.ty);
        }

        return .{ .loop_ = .{
            .params = try self.addTypedLocalSpan(params),
            .initial_values = try self.addExprSpan(initial_values),
            .body = body,
        } };
    }

    fn lowerIteratorDispatch(
        self: *BodyContext,
        plan: static_dispatch.IteratorDispatchCall,
        loop_iterator: ?BodyTypedLocal,
        expected_ret_ty: ?Type.TypeId,
    ) Allocator.Error!DraftExprId {
        const plan_args = plan.argsSlice(self.view.static_dispatch_plans);
        if (plan.dispatcher_arg_index >= plan_args.len) Common.invariant("iterator dispatch plan dispatcher argument index was outside the argument span");

        var call_ctx = try BodyContext.init(self.allocator, self.builder, self.view, self.owner_template, self.graph, self.draft);
        defer call_ctx.deinit();
        call_ctx.owner_context_fn_key = self.owner_context_fn_key;
        call_ctx.current_fn_key = self.current_fn_key;
        call_ctx.source_region_override = self.source_region_override;
        call_ctx.current_entry_root = self.current_entry_root;

        const callable_mono_ty = try call_ctx.instantiateIteratorPlanCallTypeFromCaller(plan.callable_ty, self, plan_args, loop_iterator, expected_ret_ty);
        const plan_fn_data = self.builder.functionShape(callable_mono_ty, "checked iterator dispatch plan had a non-function type");
        const plan_arg_tys = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(plan_fn_data.args));
        defer self.allocator.free(plan_arg_tys);
        if (expected_ret_ty) |expected| {
            if (!self.sameType(plan_fn_data.ret, expected)) {
                Common.invariant("checked iterator dispatch plan return type differed from iterator-for expected type");
            }
        }

        const dispatcher_ty = plan_arg_tys[plan.dispatcher_arg_index];
        try call_ctx.constrainTypeToMono(plan.dispatcher_ty, dispatcher_ty);
        const actual_dispatcher_ty = (try self.iteratorOperandMonoType(plan_args[plan.dispatcher_arg_index], loop_iterator, dispatcher_ty)) orelse
            Common.invariant("iterator dispatch plan dispatcher operand did not match the checked dispatcher type");
        if (!self.sameType(dispatcher_ty, actual_dispatcher_ty)) {
            Common.invariant("iterator dispatch plan dispatcher operand differed from the checked dispatcher type");
        }
        const owner = methodOwnerFromType(&self.builder.program.types, dispatcher_ty) orelse
            Common.invariant("iterator dispatch plan had no method owner");
        const lookup = self.builder.lookupMethodTarget(owner, self.view, plan.method) orelse
            Common.invariant("checked iterator dispatch method registry is missing resolved target");

        const target_mono_ty = try self.methodTargetMonoTypeFromPlan(lookup, &call_ctx, plan.callable_ty, expected_ret_ty);
        try call_ctx.constrainTypeToMono(plan.callable_ty, target_mono_ty);
        if (!self.sameType(callable_mono_ty, target_mono_ty)) {
            Common.invariant("checked iterator dispatch target callable type differed from dispatch plan callable type");
        }

        const fn_data = self.builder.functionShape(target_mono_ty, "checked iterator dispatch target had a non-function type");
        if (expected_ret_ty) |expected| {
            if (!self.sameType(fn_data.ret, expected)) {
                Common.invariant("checked iterator dispatch target return type differed from iterator-for expected type");
            }
        }
        const args = try self.allocator.alloc(DraftExprId, plan_args.len);
        defer self.allocator.free(args);
        const arg_tys = self.builder.program.types.span(fn_data.args);
        for (plan_args, 0..) |operand, i| {
            args[i] = try self.lowerIteratorOperandAtType(operand, loop_iterator, arg_tys[i]);
        }

        return try self.addExpr(.{
            .ty = fn_data.ret,
            .data = .{ .call_proc = .{
                .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(try self.methodTargetCalleeWithMono(lookup, target_mono_ty))),
                .args = try self.addExprSpan(args),
            } },
        });
    }

    fn instantiateIteratorPlanCallTypeFromCaller(
        self: *BodyContext,
        source_fn_ty: checked.CheckedTypeId,
        caller: *BodyContext,
        operands: []const static_dispatch.IteratorDispatchOperand,
        loop_iterator: ?BodyTypedLocal,
        expected_ret_ty: ?Type.TypeId,
    ) Allocator.Error!Type.TypeId {
        const function = self.checkedFunctionType(source_fn_ty);
        if (function.args.len != operands.len) {
            Common.invariant("checked iterator dispatch target arity differs from its function type");
        }
        const fn_node = try self.instNode(source_fn_ty);
        for (function.args, operands) |formal_ty, operand| {
            const formal_node = try self.instNode(formal_ty);
            switch (operand) {
                .checked_expr => |checked_arg| {
                    const arg_ty = caller.view.bodies.expr(checked_arg).ty;
                    try self.graph.unify(formal_node, try caller.instNode(arg_ty));
                    if (try caller.callArgumentMonoType(checked_arg, null)) |evidence_ty| {
                        try self.graph.unify(formal_node, try self.graph.importMono(evidence_ty));
                    }
                },
                .loop_iterator_state => {
                    const iterator = loop_iterator orelse Common.invariant("iterator .next dispatch reached Monotype without a loop iterator local");
                    try self.graph.unify(formal_node, try self.graph.importMono(iterator.ty));
                },
            }
        }
        if (expected_ret_ty) |expected| {
            try self.graph.unify(try self.instNode(function.ret), try self.graph.importMono(expected));
        }
        try self.graph.drainDirty();
        return try self.activeTypeFromNode(fn_node);
    }

    fn iteratorOperandMonoType(
        self: *BodyContext,
        operand: static_dispatch.IteratorDispatchOperand,
        loop_iterator: ?BodyTypedLocal,
        expected_ty: ?Type.TypeId,
    ) Allocator.Error!?Type.TypeId {
        return switch (operand) {
            .checked_expr => |expr| try self.callArgumentMonoType(expr, expected_ty),
            .loop_iterator_state => if (loop_iterator) |iterator| iterator.ty else Common.invariant("iterator .next dispatch reached Monotype without a loop iterator local"),
        };
    }

    fn lowerIteratorOperandAtType(
        self: *BodyContext,
        operand: static_dispatch.IteratorDispatchOperand,
        loop_iterator: ?BodyTypedLocal,
        ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        return switch (operand) {
            .checked_expr => |expr| try self.lowerExprAtType(expr, ty),
            .loop_iterator_state => blk: {
                const iterator = loop_iterator orelse Common.invariant("iterator .next dispatch reached Monotype without a loop iterator local");
                if (!self.sameType(iterator.ty, ty)) Common.invariant("iterator .next operand type differed from instantiated callable argument type");
                break :blk try self.localExpr(iterator.local, iterator.ty);
            },
        };
    }

    fn iteratorDonePattern(self: *BodyContext, step: IterStepShape) Allocator.Error!DraftPatId {
        return try self.addPatWithTypeCell(try self.lowerTypeCell(step.step_ty), .{ .tag = .{
            .name = try self.builder.tagName(self.view, step.done_tag),
            .payloads = .empty(),
        } });
    }

    fn iteratorOneBranch(
        self: *BodyContext,
        for_: anytype,
        result_ty: Type.TypeId,
        step: IterStepShape,
        iterator_ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftBranch {
        var saved = std.ArrayList(BinderRestore).empty;
        defer saved.deinit(self.allocator);
        try self.savePatternBinders(for_.pattern, &saved);
        for (carries) |carry| try self.saveBinder(carry.binder, &saved);
        defer self.restoreBinders(saved.items);

        const item_ty = try self.lowerTypeView(step.one_item.ty);
        const rest_local = try self.addLocal(self.builder.symbols.fresh(), iterator_ty);
        const item_local: ?DraftLocalId = if (self.patternNeedsExplicitBinding(for_.pattern))
            try self.addLocal(self.builder.symbols.fresh(), item_ty)
        else
            null;
        const record_pat = try self.iteratorOnePayloadPattern(for_.pattern, step, item_ty, iterator_ty, rest_local, item_local);
        const tag_pat = try self.addPatWithTypeCell(try self.lowerTypeCell(step.step_ty), .{ .tag = .{
            .name = try self.builder.tagName(self.view, step.one_tag),
            .payloads = try self.addPatSpan(&[_]DraftPatId{record_pat}),
        } });

        const rest_expr = try self.localExpr(rest_local, iterator_ty);
        const block = if (item_local) |local| blk: {
            const item_expr = try self.localExpr(local, item_ty);
            const miss = try self.runtimeCrashExpr(result_ty, "pattern match failed");
            break :blk try self.lowerMaterializedPatternThen(
                for_.pattern,
                item_expr,
                item_ty,
                result_ty,
                .{ .iterator_body = .{
                    .body = for_.body,
                    .result_ty = result_ty,
                    .rest_expr = rest_expr,
                    .carries = carries,
                } },
                miss,
            );
        } else try self.lowerIteratorBodyThenContinue(for_.body, result_ty, rest_expr, carries);

        return .{ .pat = tag_pat, .body = block };
    }

    fn lowerIteratorBodyThenContinue(
        self: *BodyContext,
        body: checked.CheckedExprId,
        result_ty: Type.TypeId,
        rest_expr: DraftExprId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftExprId {
        const checked_body = self.view.bodies.expr(body);
        switch (checked_body.data) {
            .block => |block| {
                var statement_diverges = false;
                for (block.statements) |statement| {
                    if (self.checkedStatementDivergesInLoweredRuntime(statement)) statement_diverges = true;
                }
                const extra: usize = if (statement_diverges) 0 else 1;
                const lowered_statements = try self.allocator.alloc(DraftStmtId, block.statements.len + extra);
                defer self.allocator.free(lowered_statements);
                for (block.statements, 0..) |statement, i| {
                    lowered_statements[i] = try self.lowerStatement(statement);
                }
                if (!statement_diverges) {
                    lowered_statements[block.statements.len] = try self.lowerDiscardedExprStatement(block.final_expr, result_ty);
                }
                return try self.addExpr(.{ .ty = result_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(lowered_statements),
                    .final_expr = try self.continueWithState(result_ty, rest_expr, carries),
                } } });
            },
            else => {
                const body_stmt = try self.lowerDiscardedExprStatement(body, result_ty);
                return try self.addExpr(.{ .ty = result_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(&[_]DraftStmtId{body_stmt}),
                    .final_expr = try self.continueWithState(result_ty, rest_expr, carries),
                } } });
            },
        }
    }

    fn lowerWhileBodyThenContinue(
        self: *BodyContext,
        body: checked.CheckedExprId,
        result_ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftExprId {
        const checked_body = self.view.bodies.expr(body);
        switch (checked_body.data) {
            .block => |block| {
                var statement_diverges = false;
                for (block.statements) |statement| {
                    if (self.checkedStatementDivergesInLoweredRuntime(statement)) statement_diverges = true;
                }
                const extra: usize = if (statement_diverges) 0 else 1;
                const lowered_statements = try self.allocator.alloc(DraftStmtId, block.statements.len + extra);
                defer self.allocator.free(lowered_statements);
                for (block.statements, 0..) |statement, i| {
                    lowered_statements[i] = try self.lowerStatement(statement);
                }
                if (!statement_diverges) {
                    lowered_statements[block.statements.len] = try self.lowerDiscardedExprStatement(block.final_expr, result_ty);
                }
                return try self.addExpr(.{ .ty = result_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(lowered_statements),
                    .final_expr = try self.continueWithCurrentState(result_ty, carries),
                } } });
            },
            else => {
                const body_stmt = try self.lowerDiscardedExprStatement(body, result_ty);
                return try self.addExpr(.{ .ty = result_ty, .data = .{ .block = .{
                    .statements = try self.addStmtSpan(&[_]DraftStmtId{body_stmt}),
                    .final_expr = try self.continueWithCurrentState(result_ty, carries),
                } } });
            },
        }
    }

    fn iteratorSkipBranch(
        self: *BodyContext,
        result_ty: Type.TypeId,
        step: IterStepShape,
        iterator_ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftBranch {
        const rest_local = try self.addLocal(self.builder.symbols.fresh(), iterator_ty);
        const record_pat = try self.iteratorSkipPayloadPattern(step, iterator_ty, rest_local);
        const tag_pat = try self.addPatWithTypeCell(try self.lowerTypeCell(step.step_ty), .{ .tag = .{
            .name = try self.builder.tagName(self.view, step.skip_tag),
            .payloads = try self.addPatSpan(&[_]DraftPatId{record_pat}),
        } });
        const rest_expr = try self.localExpr(rest_local, iterator_ty);
        return .{
            .pat = tag_pat,
            .body = try self.continueWithState(result_ty, rest_expr, carries),
        };
    }

    fn iteratorOnePayloadPattern(
        self: *BodyContext,
        item_pattern: checked.CheckedPatternId,
        step: IterStepShape,
        item_ty: Type.TypeId,
        iterator_ty: Type.TypeId,
        rest_local: DraftLocalId,
        item_local: ?DraftLocalId,
    ) Allocator.Error!DraftPatId {
        const item_pat = if (item_local) |local|
            try self.bindPat(local, item_ty)
        else
            try self.lowerPatternAtType(item_pattern, item_ty);
        const item_field = try self.iteratorRecordDestruct(step.one_item.name, item_pat);
        const rest_field = try self.iteratorRecordDestruct(step.one_rest.name, try self.bindPat(rest_local, iterator_ty));
        const fields = [_]DraftRecordDestruct{ item_field, rest_field };
        return try self.addPatWithTypeCell(
            try self.lowerTypeCell(step.one_payload_ty),
            .{ .record = try self.addRecordDestructSpan(&fields) },
        );
    }

    fn iteratorSkipPayloadPattern(
        self: *BodyContext,
        step: IterStepShape,
        iterator_ty: Type.TypeId,
        rest_local: DraftLocalId,
    ) Allocator.Error!DraftPatId {
        const rest_field = try self.iteratorRecordDestruct(step.skip_rest.name, try self.bindPat(rest_local, iterator_ty));
        const fields = [_]DraftRecordDestruct{rest_field};
        return try self.addPatWithTypeCell(
            try self.lowerTypeCell(step.skip_payload_ty),
            .{ .record = try self.addRecordDestructSpan(&fields) },
        );
    }

    fn iteratorRecordDestruct(
        self: *BodyContext,
        field: names.RecordFieldNameId,
        pattern: DraftPatId,
    ) Allocator.Error!DraftRecordDestruct {
        return .{
            .name = try self.builder.recordFieldName(self.view, field),
            .pattern = pattern,
        };
    }

    fn pushLoopContext(self: *BodyContext, result_ty: Type.TypeId, carries: []const LoopCarry) Allocator.Error!void {
        try self.loop_contexts.append(self.allocator, .{
            .result_ty = result_ty,
            .carries = carries,
        });
    }

    fn popLoopContext(self: *BodyContext) void {
        _ = self.loop_contexts.pop();
    }

    fn currentLoopContext(self: *BodyContext) LoopContext {
        if (self.loop_contexts.items.len == 0) Common.invariant("break statement reached Monotype outside an explicit loop expression");
        return self.loop_contexts.items[self.loop_contexts.items.len - 1];
    }

    fn breakCurrentLoopExpr(self: *BodyContext) Allocator.Error!DraftExprId {
        const loop = self.currentLoopContext();
        const data = try self.breakCurrentLoopExprData();
        return try self.addExpr(.{ .ty = loop.result_ty, .data = data });
    }

    fn breakCurrentLoopExprData(self: *BodyContext) Allocator.Error!BodyExprData {
        const loop = self.currentLoopContext();
        return if (loop.carries.len == 0)
            .{ .break_ = null }
        else
            .{ .break_ = try self.loopStateExpr(loop.result_ty, loop.carries) };
    }

    fn continueWith(self: *BodyContext, ty: Type.TypeId, values: []const DraftExprId) Allocator.Error!DraftExprId {
        return try self.addExpr(.{ .ty = ty, .data = .{ .continue_ = .{
            .values = try self.addExprSpan(values),
        } } });
    }

    fn continueWithCurrentState(
        self: *BodyContext,
        ty: Type.TypeId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftExprId {
        if (carries.len == 0) return try self.continueWith(ty, &.{});

        const values = try self.allocator.alloc(DraftExprId, carries.len);
        defer self.allocator.free(values);
        for (carries, 0..) |carry, i| {
            const current = self.binders.get(carry.binder) orelse Common.invariant("loop-carried mutable binder was absent");
            values[i] = try self.localExpr(current, carry.ty);
        }
        return try self.continueWith(ty, values);
    }

    fn continueWithState(
        self: *BodyContext,
        ty: Type.TypeId,
        rest_expr: DraftExprId,
        carries: []const LoopCarry,
    ) Allocator.Error!DraftExprId {
        const values = try self.allocator.alloc(DraftExprId, 1 + carries.len);
        defer self.allocator.free(values);
        values[0] = rest_expr;
        for (carries, 0..) |carry, i| {
            const current = self.binders.get(carry.binder) orelse Common.invariant("loop-carried mutable binder was absent");
            values[i + 1] = try self.localExpr(current, carry.ty);
        }
        return try self.continueWith(ty, values);
    }

    fn loopStateExpr(self: *BodyContext, ty: Type.TypeId, carries: []const LoopCarry) Allocator.Error!DraftExprId {
        if (carries.len == 0) Common.invariant("empty loop state requested");
        if (carries.len == 1) {
            const current = self.binders.get(carries[0].binder) orelse Common.invariant("loop-carried mutable binder was absent");
            return try self.localExpr(current, carries[0].ty);
        }

        const items = try self.allocator.alloc(DraftExprId, carries.len);
        defer self.allocator.free(items);
        for (carries, 0..) |carry, i| {
            const current = self.binders.get(carry.binder) orelse Common.invariant("loop-carried mutable binder was absent");
            items[i] = try self.localExpr(current, carry.ty);
        }
        return try self.addExpr(.{ .ty = ty, .data = .{ .tuple = try self.addExprSpan(items) } });
    }

    fn loopStateType(self: *BodyContext, unit_ty: Type.TypeId, carries: []const LoopCarry) Allocator.Error!Type.TypeId {
        if (carries.len == 0) return unit_ty;
        if (carries.len == 1) return carries[0].ty;

        const tys = try self.allocator.alloc(Type.TypeId, carries.len);
        defer self.allocator.free(tys);
        for (carries, 0..) |carry, i| tys[i] = carry.ty;
        return try self.builder.program.types.add(.{ .tuple = try self.builder.program.types.addSpan(tys) });
    }

    fn unitType(self: *BodyContext) Allocator.Error!Type.TypeId {
        return try self.builder.program.types.add(.{ .record = .empty() });
    }

    fn prepareLoopCarries(self: *BodyContext, binders: []const checked.PatternBinderId) Allocator.Error![]LoopCarry {
        var carries = std.ArrayList(LoopCarry).empty;
        errdefer carries.deinit(self.allocator);
        for (binders) |binder| {
            const initial = self.binders.get(binder) orelse continue;
            const ty = try self.localType(initial);
            try carries.append(self.allocator, .{
                .binder = binder,
                .initial_local = initial,
                .param_local = try self.addLocal(self.builder.symbols.fresh(), ty),
                .ty = ty,
            });
        }
        return try carries.toOwnedSlice(self.allocator);
    }

    fn finalCarryPattern(self: *BodyContext, carries: []const LoopCarry, ty: Type.TypeId) Allocator.Error!DraftPatId {
        if (carries.len == 0) Common.invariant("empty loop carry pattern requested");
        if (carries.len == 1) {
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), carries[0].ty, carries[0].binder);
            try self.bindLocalName(local, carries[0].binder);
            try self.binders.put(carries[0].binder, local);
            return try self.addPat(.{ .ty = ty, .data = .{ .bind = local } });
        }

        const items = try self.allocator.alloc(DraftPatId, carries.len);
        defer self.allocator.free(items);
        for (carries, 0..) |carry, i| {
            const local = try self.addLocalWithBinder(self.builder.symbols.fresh(), carry.ty, carry.binder);
            try self.bindLocalName(local, carry.binder);
            try self.binders.put(carry.binder, local);
            items[i] = try self.addPat(.{ .ty = carry.ty, .data = .{ .bind = local } });
        }
        return try self.addPat(.{ .ty = ty, .data = .{ .tuple = try self.addPatSpan(items) } });
    }

    fn collectReassignedBindersInExpr(
        self: *BodyContext,
        expr_id: checked.CheckedExprId,
        out: *std.ArrayList(checked.PatternBinderId),
    ) Allocator.Error!void {
        const expr = self.view.bodies.expr(expr_id);
        switch (expr.data) {
            .str => |segments| for (segments) |segment| try self.collectReassignedBindersInExpr(segment, out),
            .list => |items| for (items) |item| try self.collectReassignedBindersInExpr(item, out),
            .tuple => |items| for (items) |item| try self.collectReassignedBindersInExpr(item, out),
            .match_ => |match| {
                try self.collectReassignedBindersInExpr(match.cond, out);
                for (match.branches) |branch| {
                    if (branch.guard) |guard| try self.collectReassignedBindersInExpr(guard, out);
                    try self.collectReassignedBindersInExpr(branch.value, out);
                }
            },
            .if_ => |if_| {
                for (if_.branches) |branch| {
                    try self.collectReassignedBindersInExpr(branch.cond, out);
                    try self.collectReassignedBindersInExpr(branch.body, out);
                }
                try self.collectReassignedBindersInExpr(if_.final_else, out);
            },
            .call => |call| {
                try self.collectReassignedBindersInExpr(call.func, out);
                for (call.args) |arg| try self.collectReassignedBindersInExpr(arg, out);
            },
            .record => |record| {
                if (record.ext) |ext| try self.collectReassignedBindersInExpr(ext, out);
                for (record.fields) |field| try self.collectReassignedBindersInExpr(field.value, out);
            },
            .block => |block| {
                for (block.statements) |statement| try self.collectReassignedBindersInStatement(statement, out);
                try self.collectReassignedBindersInExpr(block.final_expr, out);
            },
            .tag => |tag| for (tag.args) |arg| try self.collectReassignedBindersInExpr(arg, out),
            .nominal => |nominal| try self.collectReassignedBindersInExpr(nominal.backing_expr, out),
            .binop => |binop| {
                try self.collectReassignedBindersInExpr(binop.lhs, out);
                try self.collectReassignedBindersInExpr(binop.rhs, out);
            },
            .unary_minus,
            .unary_not,
            .dbg,
            => |child| try self.collectReassignedBindersInExpr(child, out),
            .expect => |child| if (self.builder.inline_expects == .run) {
                try self.collectReassignedBindersInExpr(child, out);
            },
            .expect_err => |expect_err| try self.collectReassignedBindersInExpr(expect_err.expr, out),
            .field_access => |field| try self.collectReassignedBindersInExpr(field.receiver, out),
            .structural_eq => |eq| {
                try self.collectReassignedBindersInExpr(eq.lhs, out);
                try self.collectReassignedBindersInExpr(eq.rhs, out);
            },
            .structural_hash => |h| {
                try self.collectReassignedBindersInExpr(h.value, out);
                try self.collectReassignedBindersInExpr(h.hasher, out);
            },
            .tuple_access => |access| try self.collectReassignedBindersInExpr(access.tuple, out),
            .return_ => |ret| try self.collectReassignedBindersInExpr(ret.expr, out),
            .for_ => |for_| {
                try self.collectReassignedBindersInExpr(for_.expr, out);
                try self.collectReassignedBindersInExpr(for_.body, out);
            },
            .run_low_level => |low_level| for (low_level.args) |arg| try self.collectReassignedBindersInExpr(arg, out),
            .lambda,
            .closure,
            .hosted_lambda,
            .pending,
            .num,
            .frac_f32,
            .frac_f64,
            .dec,
            .dec_small,
            .num_from_numeral,
            .typed_int,
            .typed_frac,
            .typed_num_from_numeral,
            .str_from_quote,
            .str_segment,
            .bytes_literal,
            .lookup_local,
            .lookup_external,
            .lookup_required,
            .empty_list,
            .empty_record,
            .zero_argument_tag,
            .dispatch_call,
            .interpolation,
            .method_eq,
            .type_dispatch_call,
            .runtime_error,
            .crash,
            .ellipsis,
            .anno_only,
            .break_,
            => {},
        }
    }

    fn collectReassignedBindersInStatement(
        self: *BodyContext,
        statement_id: checked.CheckedStatementId,
        out: *std.ArrayList(checked.PatternBinderId),
    ) Allocator.Error!void {
        const statement = self.view.bodies.statement(statement_id);
        switch (statement.data) {
            .decl => |decl| try self.collectReassignedBindersInExpr(decl.expr, out),
            .var_ => |var_| try self.collectReassignedBindersInExpr(var_.expr, out),
            .var_uninitialized => {},
            .reassign => |reassign| {
                for (reassign.reassigned_binders) |binder| try self.appendUniqueBinder(out, binder);
                try self.collectReassignedBindersInExpr(reassign.expr, out);
            },
            .dbg,
            .expr,
            => |expr| try self.collectReassignedBindersInExpr(expr, out),
            .expect => |expr| if (self.builder.inline_expects == .run) {
                try self.collectReassignedBindersInExpr(expr, out);
            },
            .for_ => |for_| {
                try self.collectReassignedBindersInExpr(for_.expr, out);
                try self.collectReassignedBindersInExpr(for_.body, out);
            },
            .while_ => |while_| {
                try self.collectReassignedBindersInExpr(while_.cond, out);
                try self.collectReassignedBindersInExpr(while_.body, out);
            },
            .infinite_loop => |loop| {
                try self.collectReassignedBindersInExpr(loop.cond, out);
                try self.collectReassignedBindersInExpr(loop.body, out);
            },
            .breakable_loop => |loop| {
                try self.collectReassignedBindersInExpr(loop.cond, out);
                try self.collectReassignedBindersInExpr(loop.body, out);
            },
            .return_ => |ret| try self.collectReassignedBindersInExpr(ret.expr, out),
            .pending,
            .crash,
            .break_,
            .import_,
            .alias_decl,
            .nominal_decl,
            .type_anno,
            .type_var_alias,
            .runtime_error,
            => {},
        }
    }

    fn appendUniqueBinder(
        self: *BodyContext,
        out: *std.ArrayList(checked.PatternBinderId),
        binder: checked.PatternBinderId,
    ) Allocator.Error!void {
        for (out.items) |existing| {
            if (existing == binder) return;
        }
        try out.append(self.allocator, binder);
    }

    const IterStepShape = struct {
        step_ty: checked.CheckedTypeId,
        done_tag: names.TagNameId,
        one_tag: names.TagNameId,
        skip_tag: names.TagNameId,
        one_payload_ty: checked.CheckedTypeId,
        skip_payload_ty: checked.CheckedTypeId,
        one_item: checked.CheckedRecordField,
        one_rest: checked.CheckedRecordField,
        skip_rest: checked.CheckedRecordField,
    };

    fn iteratorStepShape(self: *BodyContext, step_ty: checked.CheckedTypeId) Allocator.Error!IterStepShape {
        const step_payload = resolvedPayload(self.view, step_ty).payload;
        const step_tag_union = switch (step_payload) {
            .tag_union => |tag_union| tag_union,
            else => Common.invariant("iterator .next plan did not return a tag union"),
        };

        var done_tag: ?names.TagNameId = null;
        var one_tag: ?names.TagNameId = null;
        var skip_tag: ?names.TagNameId = null;
        var one_payload_ty: ?checked.CheckedTypeId = null;
        var skip_payload_ty: ?checked.CheckedTypeId = null;

        var seen = std.AutoHashMap(checked.CheckedTypeId, void).init(self.allocator);
        defer seen.deinit();

        var tags = step_tag_union.tags;
        var current: ?checked.CheckedTypeId = step_tag_union.ext;
        while (true) {
            for (tags) |tag| {
                const tag_args = tag.argsSlice(self.view.types);
                const tag_text = self.view.names.tagLabelText(tag.name);
                if (Ident.textEql(tag_text, "Done")) {
                    if (tag_args.len != 0) Common.invariant("iterator Done step carried payloads");
                    if (done_tag != null) Common.invariant("iterator step type had duplicate Done tags");
                    done_tag = tag.name;
                } else if (Ident.textEql(tag_text, "One")) {
                    if (tag_args.len != 1) Common.invariant("iterator One step did not carry one payload");
                    if (one_tag != null) Common.invariant("iterator step type had duplicate One tags");
                    one_tag = tag.name;
                    one_payload_ty = tag_args[0];
                } else if (Ident.textEql(tag_text, "Skip")) {
                    if (tag_args.len != 1) Common.invariant("iterator Skip step did not carry one payload");
                    if (skip_tag != null) Common.invariant("iterator step type had duplicate Skip tags");
                    skip_tag = tag.name;
                    skip_payload_ty = tag_args[0];
                }
            }

            const ext = current orelse break;
            if (seen.contains(ext)) break;
            try seen.put(ext, {});

            switch (checkedPayload(self.view, ext)) {
                .alias => |alias| {
                    tags = &.{};
                    current = alias.backing;
                },
                .empty_tag_union => break,
                .flex, .rigid => |variable| {
                    if (variable.row_default == .empty_tag_union) break;
                    Common.invariant("open non-tag iterator step row reached Monotype lowering");
                },
                .tag_union => |tag_union| {
                    tags = tag_union.tags;
                    current = tag_union.ext;
                },
                else => Common.invariant("open or non-tag iterator step row reached Monotype lowering"),
            }
        }

        const one_payload = one_payload_ty orelse Common.invariant("iterator step type was missing One");
        const skip_payload = skip_payload_ty orelse Common.invariant("iterator step type was missing Skip");

        return .{
            .step_ty = step_ty,
            .done_tag = done_tag orelse Common.invariant("iterator step type was missing Done"),
            .one_tag = one_tag orelse Common.invariant("iterator step type was missing One"),
            .skip_tag = skip_tag orelse Common.invariant("iterator step type was missing Skip"),
            .one_payload_ty = one_payload,
            .skip_payload_ty = skip_payload,
            .one_item = checkedRecordFieldByName(self.view, one_payload, "item"),
            .one_rest = checkedRecordFieldByName(self.view, one_payload, "rest"),
            .skip_rest = checkedRecordFieldByName(self.view, skip_payload, "rest"),
        };
    }

    fn lowerStatement(self: *BodyContext, statement_id: checked.CheckedStatementId) Allocator.Error!DraftStmtId {
        const statement = self.view.bodies.statement(statement_id);
        const saved_loc = self.builder.program.current_loc;
        defer self.builder.program.current_loc = saved_loc;
        const saved_region = self.builder.program.current_region;
        defer self.builder.program.current_region = saved_region;
        self.builder.program.current_loc = try self.sourceLocFor(statement.source_region);
        self.builder.program.current_region = statement.source_region;
        const stmt: DraftStmt = switch (statement.data) {
            .pending,
            .import_,
            .alias_decl,
            .nominal_decl,
            .type_anno,
            .type_var_alias,
            => Common.invariant("non-runtime checked statement reached Monotype lowering"),
            .runtime_error => .{ .crash = try self.addStringLiteral("runtime error") },
            .decl => |decl| blk: {
                if (self.statementValueIsLocalProc(decl.expr)) {
                    try self.registerLocalProc(decl.pattern);
                    const unit_ty = try self.unitType();
                    break :blk .{ .expr = try self.addExpr(.{ .ty = unit_ty, .data = .unit }) };
                }
                break :blk try self.lowerPatternStatement(decl.pattern, decl.expr, statement.source_region);
            },
            .var_ => |decl| try self.lowerPatternStatement(decl.pattern, decl.expr, statement.source_region),
            .var_uninitialized => |decl| .{ .uninitialized = try self.lowerUninitializedPatternStatement(decl.pattern) },
            .reassign => |decl| try self.lowerPatternStatement(decl.pattern, decl.expr, statement.source_region),
            .crash => |msg| .{ .crash = try self.lowerStringLiteral(msg) },
            .dbg => |child| .{ .dbg = try self.lowerDbgMessage(child) },
            .expr => |child| try self.lowerExprStatement(child),
            .expect => |child| if (self.builder.inline_expects == .omit) blk: {
                const unit_ty = try self.unitType();
                break :blk .{ .expr = try self.addExpr(.{ .ty = unit_ty, .data = .unit }) };
            } else .{ .expect = try self.lowerExpr(child) },
            .for_ => |for_| blk: {
                var reassigned = std.ArrayList(checked.PatternBinderId).empty;
                defer reassigned.deinit(self.allocator);
                try self.collectReassignedBindersInExpr(for_.body, &reassigned);

                const carries = try self.prepareLoopCarries(reassigned.items);
                defer self.allocator.free(carries);

                const unit_ty = try self.unitType();
                const loop_ty = try self.loopStateType(unit_ty, carries);
                const expr = try self.addExpr(.{ .ty = loop_ty, .data = try self.lowerIteratorFor(for_, loop_ty, carries) });
                if (carries.len == 0) break :blk .{ .expr = expr };

                break :blk .{ .let_ = .{
                    .pat = try self.finalCarryPattern(carries, loop_ty),
                    .value = expr,
                } };
            },
            .while_ => |while_| blk: {
                var reassigned = std.ArrayList(checked.PatternBinderId).empty;
                defer reassigned.deinit(self.allocator);
                try self.collectReassignedBindersInExpr(while_.cond, &reassigned);
                try self.collectReassignedBindersInExpr(while_.body, &reassigned);

                const carries = try self.prepareLoopCarries(reassigned.items);
                defer self.allocator.free(carries);

                const unit_ty = try self.unitType();
                const loop_ty = try self.loopStateType(unit_ty, carries);
                const expr = try self.addExpr(.{ .ty = loop_ty, .data = try self.lowerWhile(while_, loop_ty, carries) });
                if (carries.len == 0) break :blk .{ .expr = expr };

                break :blk .{ .let_ = .{
                    .pat = try self.finalCarryPattern(carries, loop_ty),
                    .value = expr,
                } };
            },
            .infinite_loop => |loop| blk: {
                var reassigned = std.ArrayList(checked.PatternBinderId).empty;
                defer reassigned.deinit(self.allocator);
                try self.collectReassignedBindersInExpr(loop.cond, &reassigned);
                try self.collectReassignedBindersInExpr(loop.body, &reassigned);

                const carries = try self.prepareLoopCarries(reassigned.items);
                defer self.allocator.free(carries);

                const unit_ty = try self.unitType();
                const loop_ty = try self.loopStateType(unit_ty, carries);
                const expr = try self.addExpr(.{ .ty = loop_ty, .data = try self.lowerWhile(loop, loop_ty, carries) });
                if (carries.len == 0) break :blk .{ .expr = expr };

                break :blk .{ .let_ = .{
                    .pat = try self.finalCarryPattern(carries, loop_ty),
                    .value = expr,
                } };
            },
            .breakable_loop => |loop| blk: {
                var reassigned = std.ArrayList(checked.PatternBinderId).empty;
                defer reassigned.deinit(self.allocator);
                try self.collectReassignedBindersInExpr(loop.cond, &reassigned);
                try self.collectReassignedBindersInExpr(loop.body, &reassigned);

                const carries = try self.prepareLoopCarries(reassigned.items);
                defer self.allocator.free(carries);

                const unit_ty = try self.unitType();
                const loop_ty = try self.loopStateType(unit_ty, carries);
                const expr = try self.addExpr(.{ .ty = loop_ty, .data = try self.lowerWhile(loop, loop_ty, carries) });
                if (carries.len == 0) break :blk .{ .expr = expr };

                break :blk .{ .let_ = .{
                    .pat = try self.finalCarryPattern(carries, loop_ty),
                    .value = expr,
                } };
            },
            .break_ => .{ .expr = try self.breakCurrentLoopExpr() },
            .return_ => |ret| .{ .return_ = try self.lowerReturn(ret) },
        };
        return try self.addStmt(stmt);
    }

    fn lowerUninitializedPatternStatement(
        self: *BodyContext,
        pattern: checked.CheckedPatternId,
    ) Allocator.Error!DraftPatId {
        const checked_pattern = self.view.bodies.pattern(pattern);
        const node = try self.lowerTypeNode(checked_pattern.ty);
        return try self.lowerPatternAtTypeCell(pattern, DraftTypeCell.fromGraphNode(node), try self.activeTypeFromNode(node));
    }

    fn lowerPatternStatement(
        self: *BodyContext,
        pattern: checked.CheckedPatternId,
        expr: checked.CheckedExprId,
        source_region: base.Region,
    ) Allocator.Error!DraftStmt {
        const value = try self.lowerExpr(expr);
        const value_ty = try self.exprType(value);
        const comptime_site = if (self.inComptimeExhaustivenessContext() and self.patternCanMiss(pattern))
            try self.addComptimeSite(.destructure, source_region, self.view.exhaustiveness_sites.lookupByDestructurePattern(pattern), &.{})
        else
            null;
        if (!self.patternNeedsExplicitBinding(pattern)) {
            return .{ .let_ = .{
                .pat = try self.lowerPatternAtType(pattern, value_ty),
                .value = value,
                .comptime_site = comptime_site,
            } };
        }

        const unit_ty = try self.unitType();
        var unit = try self.addExpr(.{ .ty = unit_ty, .data = .unit });
        unit = try self.wrapComptimeBranch(comptime_site, 0, unit);
        const miss = if (comptime_site) |site|
            try self.comptimeExhaustivenessFailedExpr(unit_ty, site)
        else
            try self.runtimeCrashExpr(unit_ty, "pattern match failed");
        return .{ .expr = try self.lowerMaterializedPatternValueThen(
            pattern,
            value,
            value_ty,
            unit_ty,
            .{ .expr = unit },
            miss,
        ) };
    }

    fn registerLocalProc(self: *BodyContext, pattern_id: checked.CheckedPatternId) Allocator.Error!void {
        const binder = self.localProcBinder(pattern_id);
        if (self.local_proc_contexts.get(binder)) |existing| {
            const current = try self.captureLocalProcContext();
            defer self.releaseLocalProcContext(current);
            if (!localProcContextEql(existing, current)) {
                Common.invariant("local procedure binder had two declaration contexts");
            }
            return;
        }
        try self.local_proc_contexts.put(binder, try self.captureLocalProcContext());
    }

    fn localProcBinder(self: *BodyContext, pattern_id: checked.CheckedPatternId) checked.PatternBinderId {
        const pattern = self.view.bodies.pattern(pattern_id);
        return switch (pattern.data) {
            .assign => |binder| binder,
            else => Common.invariant("local procedure declaration pattern was not a binder"),
        };
    }

    fn lowerExprStatement(self: *BodyContext, expr_id: checked.CheckedExprId) Allocator.Error!DraftStmt {
        const merge_binders = try self.stateMergeBinders(expr_id);
        defer self.allocator.free(merge_binders);
        if (merge_binders.len == 0) return .{ .expr = try self.lowerExpr(expr_id) };

        const state_ty = try self.stateOnlyType(merge_binders);
        const checked_expr = self.view.bodies.expr(expr_id);
        const state_expr = switch (checked_expr.data) {
            .if_ => |if_| try self.addExpr(.{
                .ty = state_ty,
                .data = try self.lowerIfStateOnly(if_, state_ty, merge_binders, try self.ifComptimeSite(expr_id, if_)),
            }),
            .match_ => |match| try self.lowerMatchExprWithOutput(match, .{ .state_only = .{
                .state_ty = state_ty,
                .merge_binders = merge_binders,
            } }, try self.matchComptimeSite(expr_id, match)),
            else => try self.lowerBodyThenStateOnly(expr_id, state_ty, merge_binders),
        };
        return .{ .let_ = .{
            .pat = try self.stateOnlyPattern(state_ty, merge_binders),
            .value = state_expr,
        } };
    }

    fn statementValueIsLocalProc(self: *BodyContext, expr_id: checked.CheckedExprId) bool {
        return switch (self.view.bodies.expr(expr_id).data) {
            .lambda,
            .closure,
            => true,
            else => false,
        };
    }

    fn lowerPatternAtType(self: *BodyContext, pattern_id: checked.CheckedPatternId, ty: Type.TypeId) Allocator.Error!DraftPatId {
        return try self.lowerPatternAtTypeCell(pattern_id, try self.draftTypeCell(ty), ty);
    }

    fn lowerPatternAtTypeCell(
        self: *BodyContext,
        pattern_id: checked.CheckedPatternId,
        ty_cell: DraftTypeCell,
        ty: Type.TypeId,
    ) Allocator.Error!DraftPatId {
        const pattern = self.view.bodies.pattern(pattern_id);
        switch (pattern.data) {
            .assign => {},
            else => try self.constrainTypeToCell(pattern.ty, ty_cell),
        }
        const data: BodyPatData = switch (pattern.data) {
            .pending,
            .runtime_error,
            => Common.invariant("non-runtime checked pattern reached Monotype lowering"),
            .assign => |binder| blk: {
                const local = try self.addLocalWithBinderCell(self.builder.symbols.fresh(), ty_cell, binder);
                try self.bindLocalName(local, binder);
                try self.binders.put(binder, local);
                break :blk .{ .bind = local };
            },
            .as => |as| blk: {
                const local = try self.addLocalWithBinderCell(self.builder.symbols.fresh(), ty_cell, as.binder);
                try self.bindLocalName(local, as.binder);
                try self.binders.put(as.binder, local);
                break :blk .{ .as = .{
                    .pattern = try self.lowerPatternAtTypeCell(as.pattern, ty_cell, ty),
                    .local = local,
                } };
            },
            .applied_tag => |tag| try self.lowerTagPattern(tag, ty),
            .nominal => |nominal| blk: {
                const backing_ty = self.builder.namedBackingType(ty) orelse ty;
                break :blk .{ .nominal = try self.lowerPatternAtTypeCell(
                    nominal.backing_pattern,
                    try self.draftTypeCell(backing_ty),
                    backing_ty,
                ) };
            },
            .record_destructure => |destructs| try self.lowerRecordPattern(destructs, ty),
            .list => |list| try self.lowerListPattern(list, ty),
            .tuple => |items| .{ .tuple = try self.lowerTuplePattern(items, ty) },
            .num_literal => |num| if (num.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                self.lowerNumPattern(num.value, ty),
            .small_dec_literal => |dec| if (dec.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                Common.invariant("small decimal pattern reached Monotype after numeric finalization"),
            .dec_literal => |dec| if (dec.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                .{ .dec_lit = dec.value },
            .frac_f32_literal => |value| .{ .frac_f32_lit = value },
            .frac_f64_literal => |value| .{ .frac_f64_lit = value },
            .str_literal => |str| if (str.conversion) |conversion|
                try self.bindLiteralGuardPattern(conversion, ty)
            else
                .{ .str_lit = try self.lowerStringLiteral(str.literal) },
            .str_interpolation => |str| try self.lowerStrPattern(str, ty),
            .underscore => .wildcard,
        };
        return try self.addPatWithTypeCell(ty_cell, data);
    }

    fn lowerStrPattern(
        self: *BodyContext,
        str: anytype,
        ty: Type.TypeId,
    ) Allocator.Error!BodyPatData {
        const steps = try self.allocator.alloc(DraftStrPatternStep, str.steps.len);
        defer self.allocator.free(steps);

        for (str.steps, 0..) |step, i| {
            steps[i] = .{
                .capture = if (step.capture) |capture| try self.lowerPatternAtType(capture, ty) else null,
                .delimiter = try self.lowerStringLiteral(step.delimiter),
            };
        }

        return .{ .str_pattern = .{
            .prefix = try self.lowerStringLiteral(str.prefix),
            .steps = try self.addStrPatternStepSpan(steps),
            .end = switch (str.end) {
                .exact => .exact,
                .tail => .tail,
            },
        } };
    }

    fn lowerPatternSpanAtTypes(
        self: *BodyContext,
        checked_patterns: []const checked.CheckedPatternId,
        tys: []const Type.TypeId,
    ) Allocator.Error!DraftSpan(DraftPatId) {
        if (checked_patterns.len != tys.len) Common.invariant("pattern arity differs from concrete checked type");
        const lowered = try self.allocator.alloc(DraftPatId, checked_patterns.len);
        defer self.allocator.free(lowered);
        for (checked_patterns, tys, 0..) |child, child_ty, i| {
            lowered[i] = try self.lowerPatternAtType(child, child_ty);
        }
        return try self.addPatSpan(lowered);
    }

    fn lowerTuplePattern(self: *BodyContext, items: []const checked.CheckedPatternId, ty: Type.TypeId) Allocator.Error!DraftSpan(DraftPatId) {
        return try self.lowerPatternSpanAtTypes(items, self.builder.tupleItemTypes(ty));
    }

    fn lowerListPattern(self: *BodyContext, list: anytype, ty: Type.TypeId) Allocator.Error!BodyPatData {
        const elem_ty = self.constListElemType(ty);
        const lowered = try self.allocator.alloc(DraftPatId, list.patterns.len);
        defer self.allocator.free(lowered);
        for (list.patterns, 0..) |child, i| {
            lowered[i] = try self.lowerPatternAtType(child, elem_ty);
        }
        const rest: ?DraftListRestPattern = if (list.rest) |r| .{
            .index = r.index,
            // A captured rest binds the remaining slice, which has the same
            // list type as the scrutinee.
            .pattern = if (r.pattern) |rest_pattern| try self.lowerPatternAtType(rest_pattern, ty) else null,
        } else null;
        return .{ .list = .{
            .patterns = try self.addPatSpan(lowered),
            .rest = rest,
        } };
    }

    fn lowerTagPattern(self: *BodyContext, tag: anytype, ty: Type.TypeId) Allocator.Error!BodyPatData {
        const name = try self.builder.tagName(self.view, tag.name);
        return .{ .tag = .{
            .name = name,
            .payloads = try self.lowerPatternSpanAtTypes(tag.args, self.builder.tagPayloadTypes(ty, name)),
        } };
    }

    fn lowerRecordPattern(self: *BodyContext, destructs: []const checked.CheckedRecordDestruct, ty: Type.TypeId) Allocator.Error!BodyPatData {
        var lowered = std.ArrayList(DraftRecordDestruct).empty;
        defer lowered.deinit(self.allocator);
        for (destructs) |destruct| {
            const child = switch (destruct.kind) {
                .required => |pattern| pattern,
                .sub_pattern => |pattern| pattern,
                .rest => |pattern| {
                    if (self.patternIsIgnored(pattern)) continue;
                    Common.invariant("record rest pattern must be lowered to explicit rest-record construction before Monotype output");
                },
            };
            const name = try self.builder.recordFieldName(self.view, destruct.label);
            const child_ty = switch (destruct.kind) {
                .required, .sub_pattern => self.builder.recordFieldType(ty, name),
                .rest => unreachable,
            };
            try lowered.append(self.allocator, .{
                .name = name,
                .pattern = try self.lowerPatternAtType(child, child_ty),
            });
        }
        return .{ .record = try self.addRecordDestructSpan(lowered.items) };
    }

    fn patternIsIgnored(self: *BodyContext, pattern_id: checked.CheckedPatternId) bool {
        return switch (self.view.bodies.pattern(pattern_id).data) {
            .underscore => true,
            else => false,
        };
    }

    /// Lower a literal pattern on a non-builtin number type to a fresh bind,
    /// recording an equality condition for the enclosing match branch.
    fn bindLiteralGuardPattern(
        self: *BodyContext,
        conversion: checked.CheckedExprId,
        ty: Type.TypeId,
    ) Allocator.Error!BodyPatData {
        const local = try self.addLocal(self.builder.symbols.fresh(), ty);
        try self.pattern_literal_guards.append(self.allocator, .{
            .local = local,
            .conversion = conversion,
            .ty = ty,
        });
        return .{ .bind = local };
    }

    /// Compare a bound match value against a literal's converted constant,
    /// dispatching to the type's `is_eq` method when it has one and falling
    /// back to structural equality otherwise, mirroring `==`.
    fn lowerPatternLiteralEq(self: *BodyContext, entry: PatternLiteralGuard) Allocator.Error!DraftExprId {
        const scrutinee = try self.localExpr(entry.local, entry.ty);
        const expected = try self.lowerExpr(entry.conversion);
        if (methodOwnerFromType(&self.builder.program.types, entry.ty)) |owner| {
            if (self.builder.lookupMethodTargetByName(owner, "is_eq")) |lookup| {
                var target_ctx = try self.methodTargetContext(lookup);
                defer target_ctx.deinit();
                const target_fn = target_ctx.checkedFunctionType(lookup.target.callable_ty);
                const bool_ty = try self.builder.lowerType(lookup.view, target_fn.ret);
                const arg_tys = [_]Type.TypeId{ entry.ty, entry.ty };
                const callable_mono_ty = try self.methodTargetMonoTypeFromArgs(lookup, &arg_tys, bool_ty);
                const callee = try self.methodTargetCalleeWithMono(lookup, callable_mono_ty);
                return try self.addExpr(.{ .ty = bool_ty, .data = .{ .call_proc = .{
                    .callee = draftProcCalleeFromAst(Ast.procCalleeForSlot(callee)),
                    .args = try self.addExprSpan(&.{ scrutinee, expected }),
                } } });
            }
        }
        return try self.lowerEqualityExpr(entry.ty, scrutinee, expected, "is_eq", try self.builder.primitiveType(.bool));
    }

    /// Take ownership of the literal-equality conditions collected since
    /// `start`, restoring the collection to that length.
    fn drainPatternLiteralGuards(self: *BodyContext, start: usize) Allocator.Error![]PatternLiteralGuard {
        const drained = try self.allocator.dupe(PatternLiteralGuard, self.pattern_literal_guards.items[start..]);
        self.pattern_literal_guards.shrinkRetainingCapacity(start);
        return drained;
    }

    /// Wrap a match-branch body so it only runs when every collected literal
    /// equality holds, jumping to the branch's miss target otherwise.
    fn applyPatternLiteralGuards(
        self: *BodyContext,
        guards: []const PatternLiteralGuard,
        body: DraftExprId,
        fallback: DraftExprId,
        output_ty: Type.TypeId,
    ) Allocator.Error!DraftExprId {
        var result = body;
        var i = guards.len;
        while (i > 0) {
            i -= 1;
            const eq = try self.lowerPatternLiteralEq(guards[i]);
            result = try self.ifExpr(eq, result, fallback, output_ty);
        }
        return result;
    }

    /// Conjoin the branch's collected literal-equality conditions with its
    /// (optional) user guard, literal conditions first.
    fn conjoinPatternLiteralGuards(self: *BodyContext, user_guard: ?DraftExprId) Allocator.Error!?DraftExprId {
        if (self.pattern_literal_guards.items.len == 0) return user_guard;
        const bool_ty = try self.builder.primitiveType(.bool);
        var cond = user_guard;
        var i = self.pattern_literal_guards.items.len;
        while (i > 0) {
            i -= 1;
            const eq = try self.lowerPatternLiteralEq(self.pattern_literal_guards.items[i]);
            cond = if (cond) |inner|
                try self.ifExpr(eq, inner, try self.boolLiteral(false, bool_ty), bool_ty)
            else
                eq;
        }
        self.pattern_literal_guards.clearRetainingCapacity();
        return cond;
    }

    fn lowerNumPattern(self: *BodyContext, value: can.CIR.IntValue, ty: Type.TypeId) BodyPatData {
        return if (self.builder.typeIsDec(ty))
            .{ .dec_lit = intValueToDec(value) }
        else
            .{ .int_lit = value };
    }

    fn lowerIntLiteral(self: *BodyContext, value: can.CIR.IntValue, ty: Type.TypeId) BodyExprData {
        return switch (self.builder.shapeContent(ty)) {
            .primitive => |primitive| switch (primitive) {
                .f32 => .{ .frac_f32_lit = @floatCast(intValueToF64(value)) },
                .f64 => .{ .frac_f64_lit = intValueToF64(value) },
                .dec => .{ .dec_lit = intValueToDec(value) },
                else => .{ .int_lit = value },
            },
            else => .{ .int_lit = value },
        };
    }

    /// Lower a fractional literal to the constant form its instantiated
    /// monotype demands. The checked stage finalizes a fractional literal's
    /// value to one numeric representation, but a generalized literal can be
    /// instantiated at a different fractional primitive than its finalized
    /// default (for example, a literal finalized to `Dec` that this
    /// specialization unifies to `F64`). The constant kind must follow the
    /// instantiated type so backends store bits the destination layout
    /// expects, mirroring `lowerIntLiteral`.
    fn lowerFracLiteral(self: *BodyContext, value: FracLiteralValue, ty: Type.TypeId) BodyExprData {
        return switch (self.builder.shapeContent(ty)) {
            .primitive => |primitive| switch (primitive) {
                .f32 => .{ .frac_f32_lit = value.asF32() },
                .f64 => .{ .frac_f64_lit = value.asF64() },
                .dec => .{ .dec_lit = value.asDec() },
                else => Common.invariant("fractional literal instantiated to a non-fractional Monotype primitive"),
            },
            else => Common.invariant("fractional literal instantiated to a non-primitive Monotype type"),
        };
    }
};

test "monotype sameType keeps failed alias alternatives out of recursion stack" {
    var program = Ast.Program.init(std.testing.allocator);
    defer program.deinit();

    const module_name = try program.names.internModuleName("Test");
    const type_name = try program.names.internTypeName("Alias");
    const checked_ty: checked.CheckedTypeId = @enumFromInt(1);
    const i64_ty = try program.types.add(.{ .primitive = .i64 });
    const str_ty = try program.types.add(.{ .primitive = .str });
    const alias_i64 = try program.types.add(.{ .named = .{
        .named_type = .{ .module = .{}, .ty = checked_ty },
        .def = .{ .module_name = module_name, .type_name = type_name },
        .kind = .alias,
        .args = Type.Span.empty(),
        .backing = .{ .ty = i64_ty, .use = .inspectable },
    } });
    const alias_str = try program.types.add(.{ .named = .{
        .named_type = .{ .module = .{}, .ty = checked_ty },
        .def = .{ .module_name = module_name, .type_name = type_name },
        .kind = .alias,
        .args = Type.Span.empty(),
        .backing = .{ .ty = str_ty, .use = .inspectable },
    } });

    var builder: Builder = undefined;
    builder.program = &program;
    var ctx: BodyContext = undefined;
    ctx.allocator = std.testing.allocator;
    ctx.builder = &builder;

    try std.testing.expect(ctx.sameType(alias_i64, i64_ty));
    try std.testing.expect(ctx.sameType(str_ty, alias_str));
    try std.testing.expect(!ctx.sameType(alias_i64, alias_str));
    try std.testing.expect(!ctx.sameType(alias_str, alias_i64));
}

/// Structural `is_eq` specifics for the generic derivation driver
/// (`BodyContext.lowerDerivation`). Equality threads two operands, builds a
/// component access on each, and conjoins the per-component bools with AND so
/// the first inequality short-circuits to `false`.
const EqDeriver = struct {
    const Operand = struct {
        lhs: DraftExprId,
        rhs: DraftExprId,
    };

    /// Right-to-left so the AND fold nests the later components inside the
    /// earlier `if` bodies, matching source field/element order.
    const forward = false;

    fn expansionStack(self: *BodyContext) *std.AutoHashMap(Type.TypeId, void) {
        return &self.equality_expansion_stack;
    }

    fn defCache(self: *BodyContext) *std.AutoHashMap(GeneratedHelperDefAddress, DraftGeneratedHelperDefEntry) {
        return &self.equality_defs;
    }

    fn defAddress(value_ty: Type.TypeId, result_ty: Type.TypeId) GeneratedHelperDefAddress {
        return .{ .value_ty = @intFromEnum(value_ty), .result_ty = @intFromEnum(result_ty) };
    }

    fn fnType(self: *BodyContext, value_ty: Type.TypeId, result_ty: Type.TypeId) Allocator.Error!DraftTypeCell {
        return try self.twoArgFnTypeCell(value_ty, result_ty);
    }

    fn callArgs(operand: Operand) [2]DraftExprId {
        return .{ operand.lhs, operand.rhs };
    }

    fn helperSecondArgType(value_ty: Type.TypeId, _: Type.TypeId) Type.TypeId {
        return value_ty;
    }

    fn helperOperand(self_expr: DraftExprId, aux_expr: DraftExprId) Operand {
        return .{ .lhs = self_expr, .rhs = aux_expr };
    }

    fn leaf(self: *BodyContext, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .structural_eq = .{
            .lhs = operand.lhs,
            .rhs = operand.rhs,
            .negated = false,
        } } });
    }

    fn combineSeed(self: *BodyContext, _: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.boolLiteral(true, ctx.result_ty);
    }

    fn combine(self: *BodyContext, state: DraftExprId, component: DraftExprId, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.ifExpr(component, state, try self.boolLiteral(false, ctx.result_ty), ctx.result_ty);
    }

    fn componentForField(self: *BodyContext, operand: Operand, _: DraftExprId, field: Type.Field) Allocator.Error!Operand {
        const lhs_field = try self.addExpr(.{ .ty = field.ty, .data = .{ .field_access = .{
            .receiver = operand.lhs,
            .field = field.name,
        } } });
        const rhs_field = try self.addExpr(.{ .ty = field.ty, .data = .{ .field_access = .{
            .receiver = operand.rhs,
            .field = field.name,
        } } });
        return .{ .lhs = lhs_field, .rhs = rhs_field };
    }

    fn componentForTuple(self: *BodyContext, operand: Operand, _: DraftExprId, item_ty: Type.TypeId, index: usize) Allocator.Error!Operand {
        const lhs_item = try self.addExpr(.{ .ty = item_ty, .data = .{ .tuple_access = .{
            .tuple = operand.lhs,
            .elem_index = @intCast(index),
        } } });
        const rhs_item = try self.addExpr(.{ .ty = item_ty, .data = .{ .tuple_access = .{
            .tuple = operand.rhs,
            .elem_index = @intCast(index),
        } } });
        return .{ .lhs = lhs_item, .rhs = rhs_item };
    }

    const owned_missing_owner_msg = "owned equality call requested for a type without a method owner";
    const owned_missing_target_msg = "checked method registry is missing owned equality target";

    fn ownedArgTypes(ty: Type.TypeId, _: Type.TypeId) [2]Type.TypeId {
        return .{ ty, ty };
    }

    fn ownedCall(self: *BodyContext, ty: Type.TypeId, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.derivationOwnedCall(EqDeriver, ty, operand, ctx);
    }

    /// Decomposes structural equality on a nominal type. Record and tuple backings are
    /// decomposed through the nominal operands so field/tuple access sees the nominal
    /// layout; other backings are unwrapped and compared in their shared backing
    /// representation.
    fn named(self: *BodyContext, named_ty: Type.TypeId, backing_ty: Type.TypeId, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        switch (self.builder.program.types.get(backing_ty)) {
            .record => |fields| return try self.derivationRecord(EqDeriver, self.builder.program.types.fieldSpan(fields), operand, ctx),
            .tuple => |items| return try self.derivationTuple(EqDeriver, self.builder.program.types.span(items), operand, ctx),
            else => {},
        }

        const lhs_inner = try self.addLocal(self.builder.symbols.fresh(), backing_ty);
        const rhs_inner = try self.addLocal(self.builder.symbols.fresh(), backing_ty);

        const compare = try self.lowerDerivation(EqDeriver, backing_ty, .{
            .lhs = try self.localExpr(lhs_inner, backing_ty),
            .rhs = try self.localExpr(rhs_inner, backing_ty),
        }, ctx);

        const lhs_pat = try self.addPat(.{ .ty = named_ty, .data = .{ .nominal = try self.bindPat(lhs_inner, backing_ty) } });
        const rhs_pat = try self.addPat(.{ .ty = named_ty, .data = .{ .nominal = try self.bindPat(rhs_inner, backing_ty) } });

        const bind_rhs = try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = rhs_pat,
            .value = operand.rhs,
            .rest = compare,
        } } });
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = lhs_pat,
            .value = operand.lhs,
            .rest = bind_rhs,
        } } });
    }

    /// Decomposes structural equality on a tag union into nested matches so that each
    /// payload is compared. This dispatches owned payload types (e.g. List) to their
    /// `is_eq` methods, matching how record and tuple fields are handled. Leaving tag
    /// unions as a `structural_eq` node would defer the payload comparison to the LIR
    /// structural-equality lowering, which can only compare inline-comparable types and
    /// panics on owned types such as lists.
    fn tagUnion(self: *BodyContext, ty: Type.TypeId, tags_span: Type.Span, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        // Bind both operands to locals so each is evaluated exactly once and the
        // right-hand side can be re-scrutinised inside every left-hand-side branch.
        const lhs_local = try self.addLocal(self.builder.symbols.fresh(), ty);
        const rhs_local = try self.addLocal(self.builder.symbols.fresh(), ty);

        // Copy the tag list because recursive lowerDerivation may reallocate type spans.
        const tags = try self.allocator.dupe(Type.Tag, self.builder.program.types.tagSpan(tags_span));
        defer self.allocator.free(tags);

        const branches = try self.allocator.alloc(DraftBranch, tags.len);
        defer self.allocator.free(branches);
        for (tags, 0..) |tag, branch_index| {
            branches[branch_index] = try tagBranch(self, ty, rhs_local, tag, tags.len == 1, ctx);
        }

        const match_expr = try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .match_ = .{
            .scrutinee = try self.localExpr(lhs_local, ty),
            .branches = try self.addBranchSpan(branches),
        } } });

        const bind_rhs = try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = try self.bindPat(rhs_local, ty),
            .value = operand.rhs,
            .rest = match_expr,
        } } });
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = try self.bindPat(lhs_local, ty),
            .value = operand.lhs,
            .rest = bind_rhs,
        } } });
    }

    /// Builds one branch of the outer match in `tagUnion`: it matches the left operand
    /// against `tag`, binding its payloads, then matches the right operand against the
    /// same tag. When both sides carry `tag`, the payloads are compared pairwise; any
    /// other right-hand variant yields `false`.
    fn tagBranch(self: *BodyContext, ty: Type.TypeId, rhs_local: DraftLocalId, tag: Type.Tag, single_variant: bool, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftBranch {
        // Copy payload types because recursive lowerDerivation may reallocate type spans.
        const payloads = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(tag.payloads));
        defer self.allocator.free(payloads);

        const lhs_pats = try self.allocator.alloc(DraftPatId, payloads.len);
        defer self.allocator.free(lhs_pats);
        const rhs_pats = try self.allocator.alloc(DraftPatId, payloads.len);
        defer self.allocator.free(rhs_pats);
        const lhs_exprs = try self.allocator.alloc(DraftExprId, payloads.len);
        defer self.allocator.free(lhs_exprs);
        const rhs_exprs = try self.allocator.alloc(DraftExprId, payloads.len);
        defer self.allocator.free(rhs_exprs);
        for (payloads, 0..) |payload_ty, i| {
            const lhs_payload_local = try self.addLocal(self.builder.symbols.fresh(), payload_ty);
            const rhs_payload_local = try self.addLocal(self.builder.symbols.fresh(), payload_ty);
            lhs_pats[i] = try self.bindPat(lhs_payload_local, payload_ty);
            rhs_pats[i] = try self.bindPat(rhs_payload_local, payload_ty);
            lhs_exprs[i] = try self.localExpr(lhs_payload_local, payload_ty);
            rhs_exprs[i] = try self.localExpr(rhs_payload_local, payload_ty);
        }

        // Conjunction of the pairwise payload comparisons, defaulting to true (a variant
        // with no payloads is equal once both discriminants match).
        var body = try self.boolLiteral(true, ctx.result_ty);
        var i = payloads.len;
        while (i > 0) {
            i -= 1;
            const payload_eq = try self.lowerDerivation(EqDeriver, payloads[i], .{ .lhs = lhs_exprs[i], .rhs = rhs_exprs[i] }, ctx);
            body = try self.ifExpr(payload_eq, body, try self.boolLiteral(false, ctx.result_ty), ctx.result_ty);
        }

        const rhs_tag_pat = try self.addPat(.{ .ty = ty, .data = .{ .tag = .{
            .name = tag.name,
            .payloads = try self.addPatSpan(rhs_pats),
        } } });
        const rhs_scrutinee = try self.localExpr(rhs_local, ty);
        const inner_match = if (single_variant) blk: {
            const inner_branches = [_]DraftBranch{.{ .pat = rhs_tag_pat, .body = body }};
            break :blk try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .match_ = .{
                .scrutinee = rhs_scrutinee,
                .branches = try self.addBranchSpan(&inner_branches),
            } } });
        } else blk: {
            const wildcard = try self.addPat(.{ .ty = ty, .data = .wildcard });
            const inner_branches = [_]DraftBranch{
                .{ .pat = rhs_tag_pat, .body = body },
                .{ .pat = wildcard, .body = try self.boolLiteral(false, ctx.result_ty) },
            };
            break :blk try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .match_ = .{
                .scrutinee = rhs_scrutinee,
                .branches = try self.addBranchSpan(&inner_branches),
            } } });
        };

        const lhs_tag_pat = try self.addPat(.{ .ty = ty, .data = .{ .tag = .{
            .name = tag.name,
            .payloads = try self.addPatSpan(lhs_pats),
        } } });
        return .{ .pat = lhs_tag_pat, .body = inner_match };
    }
};

/// Structural `to_hash` specifics for the generic derivation driver. Hashing
/// threads a single value plus a running Hasher accumulator: each component
/// feeds the hasher accumulated so far, left to right.
const HashDeriver = struct {
    const Operand = struct {
        value: DraftExprId,
        hasher: DraftExprId,
    };

    /// Left-to-right: each component hashes into the accumulator threaded from
    /// the previous one.
    const forward = true;

    fn expansionStack(self: *BodyContext) *std.AutoHashMap(Type.TypeId, void) {
        return &self.hash_expansion_stack;
    }

    fn defCache(self: *BodyContext) *std.AutoHashMap(GeneratedHelperDefAddress, DraftGeneratedHelperDefEntry) {
        return &self.hash_defs;
    }

    fn defAddress(value_ty: Type.TypeId, result_ty: Type.TypeId) GeneratedHelperDefAddress {
        return .{ .value_ty = @intFromEnum(value_ty), .result_ty = @intFromEnum(result_ty) };
    }

    fn fnType(self: *BodyContext, value_ty: Type.TypeId, result_ty: Type.TypeId) Allocator.Error!DraftTypeCell {
        return try self.hashFnTypeCell(value_ty, result_ty);
    }

    fn callArgs(operand: Operand) [2]DraftExprId {
        return .{ operand.value, operand.hasher };
    }

    fn helperSecondArgType(_: Type.TypeId, result_ty: Type.TypeId) Type.TypeId {
        return result_ty;
    }

    fn helperOperand(self_expr: DraftExprId, aux_expr: DraftExprId) Operand {
        return .{ .value = self_expr, .hasher = aux_expr };
    }

    fn leaf(self: *BodyContext, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .structural_hash = .{
            .value = operand.value,
            .hasher = operand.hasher,
        } } });
    }

    fn combineSeed(_: *BodyContext, operand: Operand, _: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return operand.hasher;
    }

    fn combine(_: *BodyContext, _: DraftExprId, component: DraftExprId, _: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return component;
    }

    fn componentForField(self: *BodyContext, operand: Operand, state: DraftExprId, field: Type.Field) Allocator.Error!Operand {
        const field_value = try self.addExpr(.{ .ty = field.ty, .data = .{ .field_access = .{
            .receiver = operand.value,
            .field = field.name,
        } } });
        return .{ .value = field_value, .hasher = state };
    }

    fn componentForTuple(self: *BodyContext, operand: Operand, state: DraftExprId, item_ty: Type.TypeId, index: usize) Allocator.Error!Operand {
        const item_value = try self.addExpr(.{ .ty = item_ty, .data = .{ .tuple_access = .{
            .tuple = operand.value,
            .elem_index = @intCast(index),
        } } });
        return .{ .value = item_value, .hasher = state };
    }

    const owned_missing_owner_msg = "owned hash call requested for a type without a method owner";
    const owned_missing_target_msg = "checked method registry is missing owned to_hash target";

    fn ownedArgTypes(ty: Type.TypeId, result_ty: Type.TypeId) [2]Type.TypeId {
        return .{ ty, result_ty };
    }

    fn ownedCall(self: *BodyContext, ty: Type.TypeId, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        return try self.derivationOwnedCall(HashDeriver, ty, operand, ctx);
    }

    fn named(self: *BodyContext, named_ty: Type.TypeId, backing_ty: Type.TypeId, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        switch (self.builder.program.types.get(backing_ty)) {
            .record => |fields| return try self.derivationRecord(HashDeriver, self.builder.program.types.fieldSpan(fields), operand, ctx),
            .tuple => |items| return try self.derivationTuple(HashDeriver, self.builder.program.types.span(items), operand, ctx),
            else => {},
        }

        const inner = try self.addLocal(self.builder.symbols.fresh(), backing_ty);
        const hashed = try self.lowerDerivation(HashDeriver, backing_ty, .{
            .value = try self.localExpr(inner, backing_ty),
            .hasher = operand.hasher,
        }, ctx);
        const pat = try self.addPat(.{ .ty = named_ty, .data = .{ .nominal = try self.bindPat(inner, backing_ty) } });
        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = pat,
            .value = operand.value,
            .rest = hashed,
        } } });
    }

    /// Decompose a tag-union hash: write the discriminant index into the hasher,
    /// then match on the value and thread the active variant's payloads through.
    fn tagUnion(self: *BodyContext, value_ty: Type.TypeId, tags_span: Type.Span, operand: Operand, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftExprId {
        // Bind the value to a local so it is matched exactly once.
        const value_local = try self.addLocal(self.builder.symbols.fresh(), value_ty);

        // Copy the tag list because recursive lowerDerivation may reallocate type spans.
        const tags = try self.allocator.dupe(Type.Tag, self.builder.program.types.tagSpan(tags_span));
        defer self.allocator.free(tags);

        const branches = try self.allocator.alloc(DraftBranch, tags.len);
        defer self.allocator.free(branches);
        for (tags, 0..) |tag, index| {
            branches[index] = try tagBranch(self, value_ty, tag, @intCast(index), operand.hasher, ctx);
        }

        const match_expr = try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .match_ = .{
            .scrutinee = try self.localExpr(value_local, value_ty),
            .branches = try self.addBranchSpan(branches),
        } } });

        return try self.addExpr(.{ .ty = ctx.result_ty, .data = .{ .let_ = .{
            .bind = try self.bindPat(value_local, value_ty),
            .value = operand.value,
            .rest = match_expr,
        } } });
    }

    fn tagBranch(self: *BodyContext, value_ty: Type.TypeId, tag: Type.Tag, variant_index: u64, hasher: DraftExprId, ctx: BodyContext.DerivationCtx) Allocator.Error!DraftBranch {
        // Copy payload types because recursive lowerDerivation may reallocate type spans.
        const payloads = try self.allocator.dupe(Type.TypeId, self.builder.program.types.span(tag.payloads));
        defer self.allocator.free(payloads);

        const pats = try self.allocator.alloc(DraftPatId, payloads.len);
        defer self.allocator.free(pats);
        const payload_exprs = try self.allocator.alloc(DraftExprId, payloads.len);
        defer self.allocator.free(payload_exprs);
        for (payloads, 0..) |payload_ty, i| {
            const payload_local = try self.addLocal(self.builder.symbols.fresh(), payload_ty);
            pats[i] = try self.bindPat(payload_local, payload_ty);
            payload_exprs[i] = try self.localExpr(payload_local, payload_ty);
        }

        // First write the discriminant index, then thread each payload's hash.
        var acc = try self.hasherWriteU64(hasher, variant_index, ctx.result_ty);
        for (payloads, 0..) |payload_ty, i| {
            acc = try self.lowerDerivation(HashDeriver, payload_ty, .{ .value = payload_exprs[i], .hasher = acc }, ctx);
        }

        const tag_pat = try self.addPat(.{ .ty = value_ty, .data = .{ .tag = .{
            .name = tag.name,
            .payloads = try self.addPatSpan(pats),
        } } });
        return .{ .pat = tag_pat, .body = acc };
    }
};

/// A fractional literal value in its checked-stage representation, used to
/// re-derive the constant kind the instantiated Monotype primitive requires.
const FracLiteralValue = union(enum) {
    f32: f32,
    f64: f64,
    dec: builtins.dec.RocDec,

    fn asF64(self: FracLiteralValue) f64 {
        return switch (self) {
            .f32 => |v| @floatCast(v),
            .f64 => |v| v,
            .dec => |v| v.toF64(),
        };
    }

    fn asF32(self: FracLiteralValue) f32 {
        return switch (self) {
            .f32 => |v| v,
            .f64 => |v| @floatCast(v),
            .dec => |v| @floatCast(v.toF64()),
        };
    }

    fn asDec(self: FracLiteralValue) builtins.dec.RocDec {
        return switch (self) {
            .f32 => |v| builtins.dec.RocDec.fromF64(@floatCast(v)) orelse
                Common.invariant("f32 fractional literal could not be represented as Dec at its instantiated type"),
            .f64 => |v| builtins.dec.RocDec.fromF64(v) orelse
                Common.invariant("f64 fractional literal could not be represented as Dec at its instantiated type"),
            .dec => |v| v,
        };
    }
};

/// Record a local's source-level name from its pattern binder. An `assign`
/// pattern's region is exactly the identifier token's span, so the name is
/// the source text at that region. Binders from other pattern forms (`as`)
/// stay unnamed.
fn bindLocalName(
    program: *Ast.Program,
    view: ModuleView,
    local: Ast.LocalId,
    binder: checked.PatternBinderId,
) Allocator.Error!void {
    const entry = view.bodies.patternBinder(binder);
    const pattern = view.bodies.pattern(entry.pattern);
    if (pattern.data != .assign) return;
    const source = view.module_env.common.source;
    const start = pattern.source_region.start.offset;
    const end = pattern.source_region.end.offset;
    if (start >= end or end > source.len) return;
    try program.setLocalName(local, source[start..end]);
}

fn moduleView(view: checked.ImportedModuleView) ModuleView {
    return .{
        .key = view.key,
        .module_env = view.module_env,
        .module_identity = view.module_identity,
        .names = checked.importedNames(view),
        .types = view.checked_types,
        .bodies = view.checked_bodies,
        .exhaustiveness_sites = view.exhaustiveness_sites,
        .checked_const_bodies = view.checked_const_bodies,
        .templates = view.checked_procedure_templates,
        .compile_time_roots = view.compile_time_roots,
        .entry_wrappers = view.entry_wrappers,
        .intrinsic_wrappers = view.intrinsic_wrappers,
        .hosted_procs = view.hosted_procs,
        .static_dispatch_plans = view.static_dispatch_plans,
        .method_registry = view.method_registry,
        .resolved_refs = view.resolved_value_refs,
        .nested_proc_sites = view.nested_proc_sites,
        .exported_procedure_bindings = view.exported_procedure_bindings,
        .exported_const_templates = view.exported_const_templates,
        .top_level_procedure_bindings = view.top_level_procedure_bindings,
        .platform_required_bindings = view.platform_required_bindings,
        .callable_eval_templates = view.callable_eval_templates,
        .hoisted_constants = view.hoisted_constants,
        .const_templates = view.const_templates,
        .const_store = view.const_store,
        .interface_capabilities = view.interface_capabilities,
    };
}

fn moduleViewNameMatches(view: ModuleView, module_name: []const u8) bool {
    return Ident.textEql(module_name, view.names.moduleNameText(view.module_identity.module_name)) or
        Ident.textEql(module_name, view.names.moduleNameText(view.module_identity.display_module_name)) or
        Ident.textEql(module_name, view.names.moduleNameText(view.module_identity.qualified_module_name));
}

fn restoreScalar(scalar: checked.ConstScalar) Ast.ExprData {
    return switch (scalar) {
        .i8 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i16 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i32 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i64 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i128 => |value| .{ .int_lit = signedIntLiteral(value) },
        .u8 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u16 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u32 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u64 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u128 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .f32_bits => |bits| .{ .frac_f32_lit = @bitCast(bits) },
        .f64_bits => |bits| .{ .frac_f64_lit = @bitCast(bits) },
        .dec_bits => |bits| .{ .dec_lit = .{ .num = bits } },
    };
}

fn restoreScalarBody(scalar: checked.ConstScalar) BodyExprData {
    return switch (scalar) {
        .i8 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i16 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i32 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i64 => |value| .{ .int_lit = signedIntLiteral(value) },
        .i128 => |value| .{ .int_lit = signedIntLiteral(value) },
        .u8 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u16 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u32 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u64 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .u128 => |value| .{ .int_lit = unsignedIntLiteral(value) },
        .f32_bits => |bits| .{ .frac_f32_lit = @bitCast(bits) },
        .f64_bits => |bits| .{ .frac_f64_lit = @bitCast(bits) },
        .dec_bits => |bits| .{ .dec_lit = .{ .num = bits } },
    };
}

/// Parse a numeral's decimal text into a constant literal of the
/// concrete numeric `primitive`, mirroring the interpreter's `parseNumeralPayload`
/// (`std.fmt.parseInt`/`parseFloat`/`RocDec.fromNonemptySlice`). Returns null
/// when the value does not fit the target representation (out of range, or a
/// fractional text parsed as an integer), so the caller can lower the Err branch.
fn foldNumeralPrimitive(primitive: Type.Primitive, text: []const u8) ?BodyExprData {
    return switch (primitive) {
        .u8 => foldUnsignedNumeral(u8, text),
        .u16 => foldUnsignedNumeral(u16, text),
        .u32 => foldUnsignedNumeral(u32, text),
        .u64 => foldUnsignedNumeral(u64, text),
        .u128 => foldUnsignedNumeral(u128, text),
        .i8 => foldSignedNumeral(i8, text),
        .i16 => foldSignedNumeral(i16, text),
        .i32 => foldSignedNumeral(i32, text),
        .i64 => foldSignedNumeral(i64, text),
        .i128 => foldSignedNumeral(i128, text),
        .f32 => if (std.fmt.parseFloat(f32, text)) |v| .{ .frac_f32_lit = v } else |_| null,
        .f64 => if (std.fmt.parseFloat(f64, text)) |v| .{ .frac_f64_lit = v } else |_| null,
        .dec => if (builtins.dec.RocDec.fromNonemptySlice(text)) |d| .{ .dec_lit = .{ .num = d.num } } else null,
        .bool, .str => Common.invariant("from_numeral target was a non-numeric primitive"),
    };
}

fn foldUnsignedNumeral(comptime T: type, text: []const u8) ?BodyExprData {
    const value = std.fmt.parseInt(T, text, 10) catch return null;
    return .{ .int_lit = unsignedIntLiteral(value) };
}

fn foldSignedNumeral(comptime T: type, text: []const u8) ?BodyExprData {
    const value = std.fmt.parseInt(T, text, 10) catch return null;
    return .{ .int_lit = signedIntLiteral(value) };
}

fn signedIntLiteral(value: anytype) can.CIR.IntValue {
    const widened: i128 = @intCast(value);
    return .{ .bytes = @bitCast(widened), .kind = .i128 };
}

fn unsignedIntLiteral(value: anytype) can.CIR.IntValue {
    const widened: u128 = @intCast(value);
    return .{ .bytes = @bitCast(widened), .kind = .u128 };
}

fn generatedInterpolationStepKey(
    current_fn_key: names.TypeDigest,
    source_expr_id: checked.CheckedExprId,
    index: usize,
) names.TypeDigest {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("roc.generated_interpolation_step");
    hasher.update(&current_fn_key.bytes);
    var source_expr_bytes = std.mem.nativeToLittle(u32, @intFromEnum(source_expr_id));
    hasher.update(std.mem.asBytes(&source_expr_bytes));
    var index_bytes = std.mem.nativeToLittle(u64, @intCast(index));
    hasher.update(std.mem.asBytes(&index_bytes));
    return .{ .bytes = hasher.finalResult() };
}

fn generatedParserRuntimeKey(
    current_fn_key: names.TypeDigest,
    source_expr_id: checked.CheckedExprId,
) names.TypeDigest {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("roc.generated_structural_parser_runtime");
    hasher.update(&current_fn_key.bytes);
    var source_expr_bytes = std.mem.nativeToLittle(u32, @intFromEnum(source_expr_id));
    hasher.update(std.mem.asBytes(&source_expr_bytes));
    return .{ .bytes = hasher.finalResult() };
}

fn generatedEncodeToRuntimeKey(
    current_fn_key: names.TypeDigest,
    source_expr_id: checked.CheckedExprId,
) names.TypeDigest {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("roc.generated_structural_encode_to_runtime");
    hasher.update(&current_fn_key.bytes);
    var source_expr_bytes = std.mem.nativeToLittle(u32, @intFromEnum(source_expr_id));
    hasher.update(std.mem.asBytes(&source_expr_bytes));
    return .{ .bytes = hasher.finalResult() };
}

fn restoredConstFnContextKey(
    module_key: checked.ModuleId,
    fn_id: checked.ConstFnId,
    source_fn_key: names.TypeDigest,
) names.TypeDigest {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("roc.restored_const_fn_context");
    hasher.update(&module_key.bytes);
    hasher.update(&source_fn_key.bytes);
    var fn_id_bytes = std.mem.nativeToLittle(u32, @intFromEnum(fn_id));
    hasher.update(std.mem.asBytes(&fn_id_bytes));
    return .{ .bytes = hasher.finalResult() };
}

fn parserEncodingCaptureId() u32 {
    return 0;
}

fn encodeToValueCaptureId() u32 {
    return 0;
}

fn encodeToEncodingCaptureId() u32 {
    return 1;
}

fn encodeToFirstFieldCaptureId() usize {
    return 2;
}

fn generatedFieldNamesIterStepKey(
    current_fn_key: names.TypeDigest,
    source_expr_id: checked.CheckedExprId,
    index: usize,
    mode: FieldNamesIterMode,
) names.TypeDigest {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("roc.generated_fields_iter_step");
    hasher.update(&current_fn_key.bytes);
    var source_expr_bytes = std.mem.nativeToLittle(u32, @intFromEnum(source_expr_id));
    hasher.update(std.mem.asBytes(&source_expr_bytes));
    var index_bytes = std.mem.nativeToLittle(u64, @intCast(index));
    hasher.update(std.mem.asBytes(&index_bytes));
    const mode_byte: u8 = switch (mode) {
        .all => 0,
        .for_size => 1,
    };
    hasher.update(&[_]u8{mode_byte});
    return .{ .bytes = hasher.finalResult() };
}

fn checkedPayload(view: ModuleView, checked_ty: checked.CheckedTypeId) checked.CheckedTypePayload {
    const raw = @intFromEnum(checked_ty);
    if (raw >= view.types.payloadCount()) Common.invariant("checked type id outside checked type store");
    return view.types.payload(checked_ty);
}

fn schemeRoot(view: ModuleView, source_scheme: anytype, comptime missing_message: []const u8) checked.CheckedTypeId {
    const scheme = view.types.schemeForKey(source_scheme) orelse Common.invariant(missing_message);
    return scheme.root;
}

fn checkedLambdaExprIdForConstFn(view: ModuleView, fn_def: anytype) checked.CheckedExprId {
    return switch (fn_def) {
        .nested => |nested| blk: {
            const site = checkedNestedSite(view, nested);
            const expr_id = site.checked_expr orelse Common.invariant("stored nested function had no checked expression site");
            const expr = view.bodies.expr(expr_id);
            break :blk switch (expr.data) {
                .lambda => expr_id,
                .closure => |closure| closure.lambda,
                else => Common.invariant("stored nested function site did not point at a lambda or closure"),
            };
        },
        else => Common.invariant("capturing stored function must reference a checked nested function"),
    };
}

fn ownerTemplateForConstFnDef(fn_def: anytype) names.ProcTemplate {
    return switch (fn_def) {
        .nested => |nested| nested.owner,
        else => Common.invariant("capturing stored function must have a nested owner template"),
    };
}

fn checkedNestedSite(view: ModuleView, nested: anytype) checked.NestedProcSite {
    for (view.nested_proc_sites.sites) |site| {
        if (site.site != nested.site) continue;
        if (!names.procedureTemplateRefEql(site.owner_template, nested.owner)) continue;
        return site;
    }
    Common.invariant("stored nested function referenced a missing checked nested site");
}

fn checkedBinderType(view: ModuleView, binder: checked.PatternBinderId) checked.CheckedTypeId {
    const raw = @intFromEnum(binder);
    if (raw >= view.bodies.patternBinderCount()) Common.invariant("stored function capture binder is outside checked body store");
    const pattern = view.bodies.patternBinder(@enumFromInt(raw)).pattern;
    const pattern_raw = @intFromEnum(pattern);
    if (pattern_raw >= view.bodies.patternCount()) Common.invariant("stored function capture pattern is outside checked body store");
    return view.bodies.pattern(@enumFromInt(pattern_raw)).ty;
}

fn checkedCaptureBinder(view: ModuleView, pattern: checked.CheckedPatternId) checked.PatternBinderId {
    const raw = @intFromEnum(pattern);
    if (raw >= view.bodies.pattern_binder_by_pattern.len) Common.invariant("checked closure capture pattern was outside the binder index");
    return view.bodies.pattern_binder_by_pattern[raw] orelse
        Common.invariant("checked closure capture pattern had no binder");
}

fn constCaptureBinder(id: check.ConstStore.CaptureId) checked.PatternBinderId {
    return switch (id) {
        .binder => |binder| binder,
        .generated => Common.invariant("generated capture reached source lambda restore"),
    };
}

fn constGeneratedCaptureNode(fn_value: check.ConstStore.ConstFn, capture_id: u32) ?checked.ConstNodeId {
    for (fn_value.captures) |capture| {
        switch (capture.id) {
            .generated => |actual| if (actual == capture_id) return capture.value,
            .binder => {},
        }
    }
    return null;
}

fn constStrNodeByteLen(view: ModuleView, node: checked.ConstNodeId) u32 {
    return switch (view.const_store.get(node)) {
        .str => |str| str.len,
        else => Common.invariant("stored parser renamed field capture was not a Str constant"),
    };
}

fn constStrNodeBytes(view: ModuleView, node: checked.ConstNodeId) []const u8 {
    return switch (view.const_store.get(node)) {
        .str => |str| view.const_store.strBytes(str),
        else => Common.invariant("stored parser renamed field capture was not a Str constant"),
    };
}

fn dispatchPlanForRuntimeExpr(view: ModuleView, expr_id: checked.CheckedExprId) static_dispatch.StaticDispatchCallPlan {
    const expr = view.bodies.expr(expr_id);
    const plan_id = switch (expr.data) {
        .dispatch_call => |maybe| maybe orelse Common.invariant("stored serialization dispatch expression had no dispatch plan"),
        .type_dispatch_call => |maybe| maybe orelse Common.invariant("stored serialization type dispatch expression had no dispatch plan"),
        else => Common.invariant("stored serialization runtime function did not reference a dispatch expression"),
    };
    const plan_raw = @intFromEnum(plan_id);
    if (plan_raw >= view.static_dispatch_plans.plans.len) Common.invariant("stored serialization dispatch plan is outside plan table");
    return view.static_dispatch_plans.plans[plan_raw];
}

fn moduleIdFromDigest(ref: names.CheckedModuleDigest) checked.ModuleId {
    return .{ .bytes = ref.bytes };
}

fn moduleDigestFromId(key: checked.ModuleId) names.CheckedModuleDigest {
    return .{ .bytes = key.bytes };
}

fn hashU32(hasher: *std.crypto.hash.sha2.Sha256, value: u32) void {
    const little = std.mem.nativeToLittle(u32, value);
    hasher.update(std.mem.asBytes(&little));
}

fn hostedTemplate(hosted: anytype) names.ProcTemplate {
    const Hosted = @TypeOf(hosted);
    if (Hosted == names.ProcTemplate) return hosted;
    if (Hosted == Ast.HostedFn) return hosted.template;
    @compileError("unsupported hosted function payload");
}

fn methodOwnerFromType(types: *const Type.Store, ty: Type.TypeId) ?static_dispatch.MethodOwner {
    return switch (types.ownerHead(ty)) {
        .none => null,
        .builtin => |owner| .{ .builtin = owner },
        .named_type => |def| if (def.source_decl) |source_decl|
            .{ .source_decl = .{
                .module_name = def.module_name,
                .statement = source_decl,
            } }
        else
            .{ .nominal = .{
                .module_name = def.module_name,
                .type_name = def.type_name,
            } },
    };
}

fn builtinOwner(builtin: ?checked.CheckedBuiltinNominal) ?static_dispatch.BuiltinOwner {
    return switch (builtin orelse return null) {
        .bool => .bool,
        .str => .str,
        .u8 => .u8,
        .i8 => .i8,
        .u16 => .u16,
        .i16 => .i16,
        .u32 => .u32,
        .i32 => .i32,
        .u64 => .u64,
        .i64 => .i64,
        .u128 => .u128,
        .i128 => .i128,
        .f32 => .f32,
        .f64 => .f64,
        .dec => .dec,
        .list => .list,
        .box => .box,
        .dict => .dict,
        .set => .set,
        .parse_tag_union_spec => .parse_tag_union_spec,
        .fields => .fields,
        .field => .field,
        .crypto_sha256_digest => .crypto_sha256_digest,
        .crypto_sha256_hasher => .crypto_sha256_hasher,
        .crypto_blake3_digest => .crypto_blake3_digest,
        .crypto_blake3_hasher => .crypto_blake3_hasher,
    };
}

fn primitiveInspectLowLevelOp(primitive: Type.Primitive) can.CIR.Expr.LowLevel {
    return switch (primitive) {
        .str => .str_inspect,
        .u8 => .u8_to_str,
        .i8 => .i8_to_str,
        .u16 => .u16_to_str,
        .i16 => .i16_to_str,
        .u32 => .u32_to_str,
        .i32 => .i32_to_str,
        .u64 => .u64_to_str,
        .i64 => .i64_to_str,
        .u128 => .u128_to_str,
        .i128 => .i128_to_str,
        .f32 => .f32_to_str,
        .f64 => .f64_to_str,
        .dec => .dec_to_str,
        .bool => Common.invariant("Bool must lower as an ordinary tag union before Str.inspect"),
    };
}

const ResolvedPayload = struct {
    root: checked.CheckedTypeId,
    payload: checked.CheckedTypePayload,
};

fn resolvedPayload(view: ModuleView, ty: checked.CheckedTypeId) ResolvedPayload {
    var current = ty;
    var remaining = view.types.payloadCount();
    while (remaining > 0) : (remaining -= 1) {
        const payload = checkedPayload(view, current);
        switch (payload) {
            .alias => |alias| current = alias.backing,
            else => return .{ .root = current, .payload = payload },
        }
    }
    Common.invariant("checked type alias chain was cyclic");
}

fn checkedRecordFieldByName(
    view: ModuleView,
    checked_ty: checked.CheckedTypeId,
    field_name: []const u8,
) checked.CheckedRecordField {
    var current = checked_ty;
    var remaining = view.types.payloadCount();
    while (remaining > 0) : (remaining -= 1) {
        switch (checkedPayload(view, current)) {
            .alias => |alias| current = alias.backing,
            .nominal => |nominal| current = nominal.backing,
            .empty_record => break,
            .record_unbound => |fields| {
                for (fields) |field| {
                    if (Ident.textEql(view.names.recordFieldLabelText(field.name), field_name)) return field;
                }
                break;
            },
            .record => |record| {
                for (record.fields) |field| {
                    if (Ident.textEql(view.names.recordFieldLabelText(field.name), field_name)) return field;
                }
                current = record.ext;
            },
            else => Common.invariant("expected checked record field lookup reached a non-record checked type"),
        }
    }
    Common.invariant("expected checked record field was absent");
}

fn intValueToDec(value: can.CIR.IntValue) builtins.dec.RocDec {
    const whole = switch (value.kind) {
        .i128 => @as(i128, @bitCast(value.bytes)),
        .u128 => blk: {
            const unsigned = @as(u128, @bitCast(value.bytes));
            if (unsigned > @as(u128, @intCast(std.math.maxInt(i128)))) {
                Common.invariant("integer pattern solved as Dec exceeded Dec whole-number range");
            }
            break :blk @as(i128, @intCast(unsigned));
        },
    };
    return builtins.dec.RocDec.fromWholeInt(whole) orelse {
        Common.invariant("integer pattern solved as Dec exceeded Dec range");
    };
}

fn intValueToF64(value: can.CIR.IntValue) f64 {
    return switch (value.kind) {
        .i128 => builtins.compiler_rt_128.i128_to_f64(@as(i128, @bitCast(value.bytes))),
        .u128 => builtins.compiler_rt_128.u128_to_f64(@as(u128, @bitCast(value.bytes))),
    };
}

fn branchCount(branches: anytype) usize {
    var count: usize = 0;
    for (branches) |branch| count += branch.pt_len;
    return count;
}

fn moduleBytesEqual(a: [32]u8, b: [32]u8) bool {
    return std.mem.eql(u8, a[0..], b[0..]);
}

fn digestEql(a: names.TypeDigest, b: names.TypeDigest) bool {
    return std.mem.eql(u8, a.bytes[0..], b.bytes[0..]);
}

fn verifyMonotypeTypeStore(program: *const Ast.Program) void {
    if (program.types.verify(&program.names)) |err| switch (err) {
        .type_digest_count_mismatch => Common.invariant("Monotype type digest section length differed from type node count"),
        .type_span_out_of_bounds => Common.invariant("Monotype type span was out of bounds"),
        .field_span_out_of_bounds => Common.invariant("Monotype field span was out of bounds"),
        .tag_span_out_of_bounds => Common.invariant("Monotype tag span was out of bounds"),
        .declared_field_span_out_of_bounds => Common.invariant("Monotype declared field span was out of bounds"),
        .type_ref_out_of_bounds => Common.invariant("Monotype type reference was out of bounds"),
        .record_fields_not_sorted => Common.invariant("Monotype record fields were not normalized"),
        .tag_union_tags_not_sorted => Common.invariant("Monotype tag union variants were not normalized"),
    };
}

fn verifyMonotypeCompletedTypeIds(program: *const Ast.Program) void {
    if (program.view().verifyCompletedTypeIds()) |err| switch (err) {
        .type_store_not_frozen => Common.invariant("completed Monotype program view used a mutable type store"),
        .spec_type_out_of_bounds => Common.invariant("completed Monotype specialization record referenced a missing type"),
        .fn_type_out_of_bounds => Common.invariant("completed Monotype function referenced a missing type"),
        .def_type_out_of_bounds => Common.invariant("completed Monotype definition referenced a missing type"),
        .nested_def_type_out_of_bounds => Common.invariant("completed Monotype nested definition referenced a missing type"),
        .expr_type_out_of_bounds => Common.invariant("completed Monotype expression referenced a missing type"),
        .pat_type_out_of_bounds => Common.invariant("completed Monotype pattern referenced a missing type"),
        .local_type_out_of_bounds => Common.invariant("completed Monotype local referenced a missing type"),
        .typed_local_type_out_of_bounds => Common.invariant("completed Monotype typed local referenced a missing type"),
        .layout_request_type_out_of_bounds => Common.invariant("completed Monotype layout request referenced a missing type"),
        .runtime_schema_request_type_out_of_bounds => Common.invariant("completed Monotype runtime schema request referenced a missing type"),
    };
}

fn verifyMonotypeCallTargets(program: *const Ast.Program) void {
    if (program.view().verifyCallTargets()) |err| switch (err) {
        .local_fn_out_of_bounds => Common.invariant("Monotype direct call referenced a missing local function"),
        .local_fn_type_out_of_bounds => Common.invariant("Monotype direct call referenced a local function with a missing function type"),
        .local_fn_type_not_function => Common.invariant("Monotype direct call referenced a local function with a non-function type"),
        .local_fn_definition_arity_mismatch => Common.invariant("Monotype local function definition arity differed from its function type"),
        .local_call_arity_mismatch => Common.invariant("Monotype direct call arity differed from the callee function type"),
        .imported_fn_out_of_bounds => Common.invariant("Monotype direct call referenced a missing imported function table entry"),
        .imported_local_fn_out_of_bounds => Common.invariant("Monotype imported function table referenced a missing local function"),
        .lifted_fn_before_lifting => Common.invariant("Monotype direct call referenced a lifted function before Monotype lifting"),
    };
}

fn sameTypeDef(left: Type.TypeDef, right: Type.TypeDef) bool {
    return left.module_name == right.module_name and
        left.type_name == right.type_name and
        left.source_decl == right.source_decl;
}

const CheckedTypeAddress = struct {
    module_bytes: [32]u8,
    type_id: u32,
};

fn checkedTypeAddress(view: ModuleView, checked_ty: checked.CheckedTypeId) CheckedTypeAddress {
    return .{
        .module_bytes = view.key.bytes,
        .type_id = @intFromEnum(checked_ty),
    };
}

const TemplateFamily = struct {
    module_bytes: [32]u8,
    proc_base: u32,
    template: u32,
    source_fn_key_bytes: [32]u8,

    fn from(template: names.ProcTemplate, source_fn_key: names.TypeDigest) TemplateFamily {
        return .{
            .module_bytes = names.procTemplateModuleDigest(template).bytes,
            .proc_base = @intFromEnum(template.proc_base),
            .template = @intFromEnum(template.template),
            .source_fn_key_bytes = source_fn_key.bytes,
        };
    }
};

const NestedSiteAddress = struct {
    module_bytes: [32]u8,
    owner_proc_base: u32,
    owner_template: u32,
    expr: u32,

    fn from(
        module_key: checked.ModuleId,
        owner: names.ProcTemplate,
        expr_id: checked.CheckedExprId,
    ) NestedSiteAddress {
        return .{
            .module_bytes = module_key.bytes,
            .owner_proc_base = @intFromEnum(owner.proc_base),
            .owner_template = @intFromEnum(owner.template),
            .expr = @intFromEnum(expr_id),
        };
    }
};

const NestedFnFamily = struct {
    module_bytes: [32]u8,
    owner_proc_base: u32,
    owner_template: u32,
    site: u32,
    context_fn_key_bytes: [32]u8,
    source_fn_key_bytes: [32]u8,

    fn from(nested: Ast.NestedFn, source_fn_key: names.TypeDigest) NestedFnFamily {
        return .{
            .module_bytes = names.procTemplateModuleDigest(nested.owner).bytes,
            .owner_proc_base = @intFromEnum(nested.owner.proc_base),
            .owner_template = @intFromEnum(nested.owner.template),
            .site = @intFromEnum(nested.site),
            .context_fn_key_bytes = nested.context_fn_key.bytes,
            .source_fn_key_bytes = source_fn_key.bytes,
        };
    }
};

test "monotype lower declarations are referenced" {
    std.testing.refAllDecls(@This());
}

test "draft type cell seals graph nodes into closed monotypes" {
    const gpa = std.testing.allocator;

    var type_store = Type.Store.init(gpa);
    defer type_store.deinit();

    var name_store = names.NameStore.init(gpa);
    defer name_store.deinit();

    var unsolved_monos = std.AutoHashMap(Type.TypeId, void).init(gpa);
    defer unsolved_monos.deinit();

    const graph = try InstGraph.create(gpa, &type_store, &name_store, &unsolved_monos);
    defer graph.destroy();

    const node = try graph.newNode(.{ .primitive = .u64 });
    var finals = GraphTypeFinals.init(graph);
    defer finals.deinit();

    const sealed = try DraftTypeCell.fromGraphNode(node).seal(graph, &finals);
    try std.testing.expect(!try graph.typeHasGraphViews(sealed));
    switch (type_store.get(sealed)) {
        .primitive => |primitive| try std.testing.expectEqual(.u64, primitive),
        else => return error.TestExpectedEqual,
    }
}

test "draft sealed type cell validation distinguishes closed snapshots from graph views" {
    const gpa = std.testing.allocator;

    var type_store = Type.Store.init(gpa);
    defer type_store.deinit();

    var name_store = names.NameStore.init(gpa);
    defer name_store.deinit();

    var unsolved_monos = std.AutoHashMap(Type.TypeId, void).init(gpa);
    defer unsolved_monos.deinit();

    const graph = try InstGraph.create(gpa, &type_store, &name_store, &unsolved_monos);
    defer graph.destroy();

    const closed = try type_store.add(.{ .primitive = .u64 });
    const closed_cell = DraftTypeCell.fromSealed(closed);
    try std.testing.expect(!try closed_cell.sealedHasGraphViews(graph));
    switch (try DraftTypeCell.fromActiveType(graph, closed)) {
        .sealed => |sealed| try std.testing.expectEqual(closed, sealed),
        .graph_node => return error.TestExpectedEqual,
    }

    const graph_view = try graph.activeTypeViewForNode(try graph.newNode(.{ .primitive = .u64 }));
    const graph_view_cell: DraftTypeCell = .{ .sealed = graph_view };
    try std.testing.expect(try graph_view_cell.sealedHasGraphViews(graph));
    switch (try DraftTypeCell.fromActiveType(graph, graph_view)) {
        .graph_node => {},
        .sealed => return error.TestExpectedEqual,
    }
    try std.testing.expect(!try DraftTypeCell.fromGraphNode(try graph.newNode(.{ .primitive = .bool })).sealedHasGraphViews(graph));
}

test "body draft store appends draft-local ids spans and type cells" {
    const gpa = std.testing.allocator;

    var program = Ast.Program.init(gpa);
    defer program.deinit();

    var unsolved_monos = std.AutoHashMap(Type.TypeId, void).init(gpa);
    defer unsolved_monos.deinit();

    const graph = try InstGraph.create(gpa, &program.types, &program.names, &unsolved_monos);
    defer graph.destroy();

    var draft = BodyDraftStore.init(gpa);
    defer draft.deinit();

    const ty = DraftTypeCell.fromGraphNode(try graph.newNode(.{ .primitive = .u64 }));
    var symbol_gen = Common.SymbolGen{};
    const local = try draft.addLocal(symbol_gen.fresh(), ty, null);
    const pat = try draft.addPat(.{ .ty = ty, .data = .{ .bind = local } });
    const expr = try draft.addExpr(.{ .ty = ty, .data = .{ .local = local } });
    const expr_span = try draft.addExprSpan(&.{expr});
    const pat_span = try draft.addPatSpan(&.{pat});
    const typed_local_span = try draft.addTypedLocalSpan(&.{.{ .local = local, .ty = ty }});
    const field_name = try program.names.internRecordFieldLabel("field");
    const field_span = try draft.addFieldExprSpan(&.{.{ .name = field_name, .value = expr }});
    const destruct_span = try draft.addRecordDestructSpan(&.{.{ .name = field_name, .pattern = pat }});
    const branch_span = try draft.addBranchSpan(&.{.{ .pat = pat, .body = expr }});
    const if_branch_span = try draft.addIfBranchSpan(&.{.{ .cond = expr, .body = expr }});
    const literal = try draft.addStringLiteral("literal");
    const str_step_span = try draft.addStrPatternStepSpan(&.{.{ .capture = pat, .delimiter = literal }});
    const declared_field_span = try draft.addDeclaredFieldSpan(&.{
        .{ .named = field_name },
        .{ .padding = ty },
    });
    const site = try draft.addComptimeSite(.if_, base.Region.zero(), null, &.{base.Region.zero()});
    const source_file = try draft.addSourceFile("module.roc");
    try draft.setLocalName(local, "value");
    const record_pat = try draft.addPat(.{ .ty = ty, .data = .{ .record = destruct_span } });
    const str_pat = try draft.addPat(.{ .ty = ty, .data = .{ .str_pattern = .{
        .prefix = literal,
        .steps = str_step_span,
        .end = .exact,
    } } });
    const record_expr = try draft.addExpr(.{ .ty = ty, .data = .{ .record = field_span } });
    const match_expr = try draft.addExpr(.{ .ty = ty, .data = .{ .match_ = .{
        .scrutinee = expr,
        .branches = branch_span,
        .comptime_site = site,
    } } });
    const if_expr = try draft.addExpr(.{ .ty = ty, .data = .{ .if_ = .{
        .branches = if_branch_span,
        .final_else = expr,
    } } });
    const stmt = try draft.addStmt(.{ .let_ = .{
        .pat = pat,
        .value = expr,
        .comptime_site = site,
    } });
    const stmt_span = try draft.addStmtSpan(&.{stmt});

    try std.testing.expectEqual(@as(usize, 1), draft.locals.items.len);
    try std.testing.expectEqual(@as(usize, 3), draft.pats.items.len);
    try std.testing.expectEqual(@as(usize, 4), draft.exprs.items.len);
    try std.testing.expectEqual(@as(usize, 1), draft.stmts.items.len);
    try std.testing.expectEqual(@as(u32, 0), expr_span.start);
    try std.testing.expectEqual(@as(u32, 1), expr_span.len);
    try std.testing.expectEqual(@as(u32, 0), pat_span.start);
    try std.testing.expectEqual(@as(u32, 1), pat_span.len);
    try std.testing.expectEqual(@as(u32, 0), typed_local_span.start);
    try std.testing.expectEqual(@as(u32, 1), typed_local_span.len);
    try std.testing.expectEqual(@as(u32, 0), stmt_span.start);
    try std.testing.expectEqual(@as(u32, 1), stmt_span.len);
    try std.testing.expectEqual(@as(u32, 0), field_span.start);
    try std.testing.expectEqual(@as(u32, 1), field_span.len);
    try std.testing.expectEqual(@as(u32, 0), destruct_span.start);
    try std.testing.expectEqual(@as(u32, 1), destruct_span.len);
    try std.testing.expectEqual(@as(u32, 0), branch_span.start);
    try std.testing.expectEqual(@as(u32, 1), branch_span.len);
    try std.testing.expectEqual(@as(u32, 0), if_branch_span.start);
    try std.testing.expectEqual(@as(u32, 1), if_branch_span.len);
    try std.testing.expectEqual(@as(u32, 0), str_step_span.start);
    try std.testing.expectEqual(@as(u32, 1), str_step_span.len);
    try std.testing.expectEqual(@as(u32, 0), declared_field_span.start);
    try std.testing.expectEqual(@as(u32, 2), declared_field_span.len);
    try std.testing.expectEqual(@as(usize, 1), draft.string_literals.items.len);
    try std.testing.expectEqual(@as(usize, 1), draft.comptime_sites.items.len);
    try std.testing.expectEqual(@as(u32, 0), source_file);
    try std.testing.expectEqual(@as(usize, 1), draft.source_files.items.len);
    try std.testing.expectEqual(@as(usize, 1), draft.local_names.items.len);
    try std.testing.expect(draft.local_names.items[@intFromEnum(local)].len != 0);

    var sealer = GraphTypeFinals.init(graph);
    defer sealer.deinit();
    try draft.sealCoreIntoProgram(&program, graph, &sealer);

    const sealed_local: Ast.LocalId = @enumFromInt(@intFromEnum(local));
    const sealed_pat: Ast.PatId = @enumFromInt(@intFromEnum(pat));
    const sealed_expr: Ast.ExprId = @enumFromInt(@intFromEnum(expr));
    const sealed_literal: Ast.StringLiteralId = @enumFromInt(@intFromEnum(literal));
    const sealed_site: Ast.ComptimeSiteId = @enumFromInt(@intFromEnum(site));

    try std.testing.expectEqual(@as(usize, 1), program.locals.items.len);
    try std.testing.expectEqual(@as(usize, 3), program.pats.items.len);
    try std.testing.expectEqual(@as(usize, 4), program.exprs.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.stmts.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.source_files.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.string_literals.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.comptime_sites.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.field_exprs.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.record_destructs.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.str_pattern_steps.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.branches.items.len);
    try std.testing.expectEqual(@as(usize, 1), program.if_branches.items.len);
    try std.testing.expectEqualStrings("literal", program.stringLiteralText(sealed_literal));
    try std.testing.expectEqual(Ast.ComptimeSiteKind.if_, program.comptimeSite(sealed_site).kind);
    try std.testing.expectEqual(@as(usize, 1), program.comptimeSite(sealed_site).branch_regions.len);
    try std.testing.expectEqualStrings("value", program.localName(sealed_local));
    try std.testing.expectEqual(field_name, program.field_exprs.items[0].name);
    try std.testing.expectEqual(sealed_expr, program.field_exprs.items[0].value);
    try std.testing.expectEqual(field_name, program.record_destructs.items[0].name);
    try std.testing.expectEqual(sealed_pat, program.record_destructs.items[0].pattern);
    try std.testing.expectEqual(@as(?Ast.PatId, sealed_pat), program.str_pattern_steps.items[0].capture);
    try std.testing.expectEqual(sealed_literal, program.str_pattern_steps.items[0].delimiter);
    try std.testing.expectEqual(sealed_pat, program.branches.items[0].pat);
    try std.testing.expectEqual(sealed_expr, program.branches.items[0].body);
    try std.testing.expectEqual(sealed_expr, program.if_branches.items[0].cond);
    try std.testing.expectEqual(sealed_expr, program.if_branches.items[0].body);
    switch (program.pats.items[0].data) {
        .bind => |bind_local| try std.testing.expectEqual(sealed_local, bind_local),
        else => return error.TestExpectedEqual,
    }
    switch (program.pats.items[@intFromEnum(record_pat)].data) {
        .record => |span| {
            try std.testing.expectEqual(@as(u32, 0), span.start);
            try std.testing.expectEqual(@as(u32, 1), span.len);
        },
        else => return error.TestExpectedEqual,
    }
    switch (program.pats.items[@intFromEnum(str_pat)].data) {
        .str_pattern => |pattern| {
            try std.testing.expectEqual(sealed_literal, pattern.prefix);
            try std.testing.expectEqual(@as(u32, 0), pattern.steps.start);
            try std.testing.expectEqual(@as(u32, 1), pattern.steps.len);
            try std.testing.expectEqual(Ast.StrPatternEnd.exact, pattern.end);
        },
        else => return error.TestExpectedEqual,
    }
    switch (program.exprs.items[0].data) {
        .local => |expr_local| try std.testing.expectEqual(sealed_local, expr_local),
        else => return error.TestExpectedEqual,
    }
    switch (program.exprs.items[@intFromEnum(record_expr)].data) {
        .record => |span| {
            try std.testing.expectEqual(@as(u32, 0), span.start);
            try std.testing.expectEqual(@as(u32, 1), span.len);
        },
        else => return error.TestExpectedEqual,
    }
    switch (program.exprs.items[@intFromEnum(match_expr)].data) {
        .match_ => |match_| {
            try std.testing.expectEqual(sealed_expr, match_.scrutinee);
            try std.testing.expectEqual(@as(u32, 0), match_.branches.start);
            try std.testing.expectEqual(@as(u32, 1), match_.branches.len);
            try std.testing.expectEqual(@as(?Ast.ComptimeSiteId, sealed_site), match_.comptime_site);
        },
        else => return error.TestExpectedEqual,
    }
    switch (program.exprs.items[@intFromEnum(if_expr)].data) {
        .if_ => |if_| {
            try std.testing.expectEqual(@as(u32, 0), if_.branches.start);
            try std.testing.expectEqual(@as(u32, 1), if_.branches.len);
            try std.testing.expectEqual(sealed_expr, if_.final_else);
        },
        else => return error.TestExpectedEqual,
    }
    switch (program.stmts.items[0]) {
        .let_ => |let_| {
            try std.testing.expectEqual(sealed_pat, let_.pat);
            try std.testing.expectEqual(sealed_expr, let_.value);
            try std.testing.expectEqual(@as(?Ast.ComptimeSiteId, sealed_site), let_.comptime_site);
        },
        else => return error.TestExpectedEqual,
    }
}

test "body draft sealed output maps back from specialization cache without body fixups" {
    const gpa = std.testing.allocator;

    var program = Ast.Program.init(gpa);
    defer program.deinit();

    var unsolved_monos = std.AutoHashMap(Type.TypeId, void).init(gpa);
    defer unsolved_monos.deinit();

    const graph = try InstGraph.create(gpa, &program.types, &program.names, &unsolved_monos);
    defer graph.destroy();

    var draft = BodyDraftStore.init(gpa);
    defer draft.deinit();

    const unit_node = try graph.newNode(.zst);
    const list_node = try graph.newNode(.{ .list = unit_node });
    const unit_cell = DraftTypeCell.fromGraphNode(unit_node);
    const list_cell = DraftTypeCell.fromGraphNode(list_node);

    var symbol_gen = Common.SymbolGen{};
    const local = try draft.addLocal(symbol_gen.fresh(), list_cell, null);
    const pat = try draft.addPat(.{ .ty = list_cell, .data = .{ .bind = local } });
    const expr = try draft.addExpr(.{ .ty = list_cell, .data = .{ .local = local } });
    const stmt = try draft.addStmt(.{ .let_ = .{
        .pat = pat,
        .value = expr,
        .comptime_site = null,
    } });
    _ = try draft.addTypedLocalSpan(&.{.{ .local = local, .ty = list_cell }});
    _ = try draft.addStmtSpan(&.{stmt});
    _ = try draft.addExpr(.{ .ty = unit_cell, .data = .unit });

    var sealer = GraphTypeFinals.init(graph);
    defer sealer.deinit();
    try draft.sealCoreIntoProgram(&program, graph, &sealer);
    program.freeze();

    const fresh = program.view();
    try std.testing.expectEqual(@as(?Ast.CompletedTypeIdVerifyError, null), fresh.verifyCompletedTypeIds());
    try std.testing.expectEqual(@as(?Type.Store.VerifyError, null), fresh.types.verify(fresh.names));

    const type_digests = try gpa.alloc(names.TypeDigest, fresh.types.types.len);
    defer gpa.free(type_digests);
    for (type_digests, 0..) |*digest, index| {
        digest.* = program.types.typeDigest(&program.names, @enumFromInt(@as(u32, @intCast(index))));
    }

    const zero_hash = [_]u8{0} ** 32;
    const image = try serialize.buildImage(gpa, zero_hash, zero_hash, &.{
        .{ .id = .type_nodes, .bytes = std.mem.sliceAsBytes(fresh.types.types) },
        .{ .id = .type_args, .bytes = std.mem.sliceAsBytes(fresh.types.spans) },
        .{ .id = .fields, .bytes = std.mem.sliceAsBytes(fresh.types.fields) },
        .{ .id = .tags, .bytes = std.mem.sliceAsBytes(fresh.types.tags) },
        .{ .id = .declared_fields, .bytes = std.mem.sliceAsBytes(fresh.types.declared_fields) },
        .{ .id = .type_digests, .bytes = std.mem.sliceAsBytes(type_digests) },
        .{ .id = .exprs, .bytes = std.mem.sliceAsBytes(fresh.exprs) },
        .{ .id = .pats, .bytes = std.mem.sliceAsBytes(fresh.pats) },
        .{ .id = .stmts, .bytes = std.mem.sliceAsBytes(fresh.stmts) },
        .{ .id = .locals, .bytes = std.mem.sliceAsBytes(fresh.locals) },
        .{ .id = .typed_locals, .bytes = std.mem.sliceAsBytes(fresh.typed_locals) },
        .{ .id = .stmt_ids, .bytes = std.mem.sliceAsBytes(fresh.stmt_ids) },
        .{ .id = .expr_locs, .bytes = std.mem.sliceAsBytes(fresh.expr_locs) },
        .{ .id = .expr_regions, .bytes = std.mem.sliceAsBytes(fresh.expr_regions) },
        .{ .id = .stmt_locs, .bytes = std.mem.sliceAsBytes(fresh.stmt_locs) },
        .{ .id = .stmt_regions, .bytes = std.mem.sliceAsBytes(fresh.stmt_regions) },
    });
    defer gpa.free(image);

    var header: serialize.SpecializationCacheHeader = undefined;
    @memcpy(std.mem.asBytes(&header), image[0..@sizeOf(serialize.SpecializationCacheHeader)]);
    const mapped = try serialize.viewMappedFile(&header, image.ptr, image.len, zero_hash, zero_hash, 0);
    const mapped_program = try serialize.mappedProgramView(mapped);

    try std.testing.expectEqual(@as(?Type.Store.VerifyError, null), mapped_program.types.verify(&program.names));
    try std.testing.expectEqualSlices(Type.Content, fresh.types.types, mapped_program.types.types);
    try std.testing.expectEqualSlices(Type.TypeId, fresh.types.spans, mapped_program.types.spans);
    try std.testing.expectEqualSlices(Ast.Expr, fresh.exprs, mapped_program.exprs);
    try std.testing.expectEqualSlices(Ast.Pat, fresh.pats, mapped_program.pats);
    try std.testing.expectEqualSlices(Ast.Stmt, fresh.stmts, mapped_program.stmts);
    try std.testing.expectEqualSlices(Ast.Local, fresh.locals, mapped_program.locals);
    try std.testing.expectEqualSlices(Ast.TypedLocal, fresh.typed_locals, mapped_program.typed_locals);
    try std.testing.expectEqualSlices(Ast.StmtId, fresh.stmt_ids, mapped_program.stmt_ids);
}

test "record parser presence words cover fields wider than one u64" {
    try std.testing.expectEqual(@as(usize, 0), BodyContext.recordPresenceWordCount(0));
    try std.testing.expectEqual(@as(usize, 1), BodyContext.recordPresenceWordCount(1));
    try std.testing.expectEqual(@as(usize, 1), BodyContext.recordPresenceWordCount(64));
    try std.testing.expectEqual(@as(usize, 2), BodyContext.recordPresenceWordCount(65));
    try std.testing.expectEqual(@as(usize, 2), BodyContext.recordPresenceWordCount(128));
    try std.testing.expectEqual(@as(usize, 3), BodyContext.recordPresenceWordCount(129));

    try std.testing.expectEqual(@as(usize, 0), BodyContext.recordPresenceWordIndex(0));
    try std.testing.expectEqual(@as(usize, 0), BodyContext.recordPresenceWordIndex(63));
    try std.testing.expectEqual(@as(usize, 1), BodyContext.recordPresenceWordIndex(64));
    try std.testing.expectEqual(@as(usize, 1), BodyContext.recordPresenceWordIndex(127));
    try std.testing.expectEqual(@as(usize, 2), BodyContext.recordPresenceWordIndex(128));

    try std.testing.expectEqual(@as(u64, 1), BodyContext.recordPresenceMask(0));
    try std.testing.expectEqual(@as(u64, 1) << 63, BodyContext.recordPresenceMask(63));
    try std.testing.expectEqual(@as(u64, 1), BodyContext.recordPresenceMask(64));
    try std.testing.expectEqual(@as(u64, 2), BodyContext.recordPresenceMask(65));
    try std.testing.expectEqual(@as(u64, 1) << 63, BodyContext.recordPresenceMask(127));
    try std.testing.expectEqual(@as(u64, 1), BodyContext.recordPresenceMask(128));
}
